fn splash_gradient(t: f64) -> CtColor {
    fn lerp_u8(a: u8, b: u8, t: f64) -> u8 {
        let t = t.clamp(0.0, 1.0);
        (a as f64 + (b as f64 - a as f64) * t)
            .round()
            .clamp(0.0, 255.0) as u8
    }

    // sky-400 -> violet-400
    let (r0, g0, b0) = (56u8, 189u8, 248u8);
    let (r1, g1, b1) = (167u8, 139u8, 250u8);
    CtColor::Rgb {
        r: lerp_u8(r0, r1, t),
        g: lerp_u8(g0, g1, t),
        b: lerp_u8(b0, b1, t),
    }
}

async fn show_startup_splash() {
    if !io::stdout().is_terminal() {
        return;
    }

    let mut stdout = io::stdout();
    let (cols, rows) = crossterm::terminal::size().unwrap_or((100, 30));

    let art_h = MAMBA_ASCII.len() as u16;
    let total_h = art_h.saturating_add(5); // tagline + spacing + progress line
    let start_y = rows.saturating_sub(total_h) / 2;

    let centered_x = |line: &str| -> u16 {
        let w = line.chars().count().min(u16::MAX as usize) as u16;
        cols.saturating_sub(w) / 2
    };

    let _ = execute!(stdout, CtClear(ClearType::All), MoveTo(0, 0), Hide);

    for (i, line) in MAMBA_ASCII.iter().enumerate() {
        let t = if MAMBA_ASCII.len() <= 1 {
            0.0
        } else {
            i as f64 / (MAMBA_ASCII.len() - 1) as f64
        };
        let color = splash_gradient(t);
        let _ = execute!(
            stdout,
            MoveTo(centered_x(line), start_y.saturating_add(i as u16)),
            SetForegroundColor(color),
            SetAttribute(Attribute::Bold),
            Print(*line),
            SetAttribute(Attribute::Reset),
            ResetColor
        );
    }

    let tagline1 = format!("Mamba • Solana market kit • v{}", env!("CARGO_PKG_VERSION"));
    let tagline2 = "10 markets • One API • MEV Supported";
    let dim = CtColor::Rgb {
        r: 148,
        g: 163,
        b: 184,
    };

    let tag1_y = start_y.saturating_add(art_h).saturating_add(1);
    let tag2_y = tag1_y.saturating_add(1);
    let _ = execute!(
        stdout,
        MoveTo(centered_x(&tagline1), tag1_y),
        SetForegroundColor(dim),
        Print(&tagline1),
        ResetColor
    );
    let _ = execute!(
        stdout,
        MoveTo(centered_x(tagline2), tag2_y),
        SetForegroundColor(dim),
        Print(tagline2),
        ResetColor
    );

    let progress_y = tag2_y.saturating_add(2);
    let total = Duration::from_secs(3);
    let start = Instant::now();
    let spinner = ['|', '/', '-', '\\'];
    let bar_w: usize = 28;
    let accent = CtColor::Rgb {
        r: 94,
        g: 234,
        b: 212,
    }; // teal-200
    let mut frame: usize = 0;

    while start.elapsed() < total {
        let progress = (start.elapsed().as_secs_f64() / total.as_secs_f64()).clamp(0.0, 1.0);
        let filled = (progress * bar_w as f64).round() as usize;
        let bar = format!("[{}{}]", "█".repeat(filled), " ".repeat(bar_w - filled));
        let line = format!("{}  initializing  {}", spinner[frame % spinner.len()], bar);
        let _ = execute!(
            stdout,
            MoveTo(centered_x(&line), progress_y),
            CtClear(ClearType::CurrentLine),
            SetForegroundColor(accent),
            Print(&line),
            ResetColor
        );
        let _ = stdout.flush();
        frame = frame.wrapping_add(1);
        tokio::time::sleep(Duration::from_millis(90)).await;
    }

    let _ = execute!(
        stdout,
        ResetColor,
        Show,
        CtClear(ClearType::All),
        MoveTo(0, 0)
    );
    let _ = stdout.flush();
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CreateNetwork {
    Devnet,
    Mainnet,
}

impl CreateNetwork {
    fn cycle(self, delta: i32) -> Self {
        match (self, delta.signum()) {
            (Self::Devnet, 1) => Self::Mainnet,
            (Self::Mainnet, 1) => Self::Devnet,
            (Self::Devnet, -1) => Self::Mainnet,
            (Self::Mainnet, -1) => Self::Devnet,
            _ => self,
        }
    }

    fn label(self) -> &'static str {
        match self {
            Self::Devnet => "devnet",
            Self::Mainnet => "mainnet",
        }
    }

    fn default_http_url(self) -> &'static str {
        match self {
            Self::Devnet => mamba::core::cluster::DEFAULT_DEVNET_HTTP_URL,
            Self::Mainnet => mamba::core::cluster::DEFAULT_MAINNET_HTTP_URL,
        }
    }

    fn default_ws_url(self) -> &'static str {
        match self {
            Self::Devnet => mamba::core::cluster::DEFAULT_DEVNET_WS_URL,
            Self::Mainnet => mamba::core::cluster::DEFAULT_MAINNET_WS_URL,
        }
    }
}

fn infer_create_network_from_url(url: &str) -> Option<CreateNetwork> {
    let url = url.trim().to_ascii_lowercase();
    if url.contains("devnet") {
        Some(CreateNetwork::Devnet)
    } else if url.contains("mainnet") {
        Some(CreateNetwork::Mainnet)
    } else {
        None
    }
}

fn create_network_for_cluster(
    cluster: Option<mamba::core::cluster::SolanaCluster>,
) -> Option<CreateNetwork> {
    match cluster {
        Some(mamba::core::cluster::SolanaCluster::Devnet) => Some(CreateNetwork::Devnet),
        Some(mamba::core::cluster::SolanaCluster::MainnetBeta) => Some(CreateNetwork::Mainnet),
        _ => None,
    }
}

fn cluster_for_network(network: Option<CreateNetwork>) -> mamba::core::cluster::SolanaCluster {
    match network {
        Some(CreateNetwork::Devnet) => mamba::core::cluster::SolanaCluster::Devnet,
        Some(CreateNetwork::Mainnet) => mamba::core::cluster::SolanaCluster::MainnetBeta,
        None => mamba::core::cluster::SolanaCluster::Unknown,
    }
}

fn apply_selected_network(ui: &mut UiState, app: &mut AppState, network: CreateNetwork) {
    app.connected_network = Some(network);
    ui.create.network = network;
    ui.create_pool.network = network;
    ui.pool_manage.network = network;
    ui.wallet_manage.network = network;
    ui.quick_trade.network = network;
}

fn market_priority_with_selected_first(selected_market: Option<Market>) -> Option<Vec<Market>> {
    let selected_market = selected_market?;
    let mut markets = vec![selected_market];
    for market in Swaps::default_market_priority().iter().copied() {
        if market != selected_market {
            markets.push(market);
        }
    }
    Some(markets)
}

fn effective_create_rpc_http_url(
    selected_network: CreateNetwork,
    global_http_url: Option<&str>,
    connected_network: Option<CreateNetwork>,
) -> String {
    let global_http_url = global_http_url.map(str::trim).filter(|v| !v.is_empty());
    let global_network =
        connected_network.or_else(|| global_http_url.and_then(infer_create_network_from_url));

    if global_network == Some(selected_network)
        && let Some(url) = global_http_url
    {
        url.to_string()
    } else {
        selected_network.default_http_url().to_string()
    }
}

fn rpc_url_override_for_network(
    selected_network: CreateNetwork,
    connected_network: Option<CreateNetwork>,
    global_http_url: Option<&str>,
) -> Option<String> {
    if connected_network == Some(selected_network) {
        return None;
    }

    Some(effective_create_rpc_http_url(
        selected_network,
        global_http_url,
        connected_network,
    ))
}

fn effective_quick_trade_rpc_http_url(
    ui: &UiState,
    app: &AppState,
    http_url: Option<&str>,
) -> String {
    effective_create_rpc_http_url(ui.quick_trade.network, http_url, app.connected_network)
}

fn quick_trade_rpc_url_override(
    ui: &UiState,
    app: &AppState,
    http_url: Option<&str>,
) -> Option<String> {
    rpc_url_override_for_network(ui.quick_trade.network, app.connected_network, http_url)
}

