enum CreateCommand {
    ListMethods,
    RaydiumListGlobalConfigs,
    RaydiumListPlatformConfigs,
    Build(CreateBuildCommand),
}

#[derive(Debug, Clone)]
struct WalletExportCommand {
    selectors: Vec<String>,
    format: ManagedWalletExportFormat,
    out: PathBuf,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CreateMethod {
    PumpFun,
    RaydiumLaunchpad,
    SplToken,
    SplToken2022,
}

impl CreateMethod {
    fn as_api_str(self) -> &'static str {
        match self {
            Self::PumpFun => "pump_fun",
            Self::RaydiumLaunchpad => "raydium_launchpad",
            Self::SplToken => "spl_token",
            Self::SplToken2022 => "spl_token_2022",
        }
    }
}

fn parse_create_method(raw: &str) -> anyhow::Result<CreateMethod> {
    match raw.trim().to_ascii_lowercase().as_str() {
        "pump_fun" | "pumpfun" | "pump" => Ok(CreateMethod::PumpFun),
        "raydium_launchpad" | "raydium" | "launchpad" | "launchlab" => {
            Ok(CreateMethod::RaydiumLaunchpad)
        }
        "spl_token" | "token" | "tokenkeg" => Ok(CreateMethod::SplToken),
        "spl_token_2022" | "token_2022" | "token2022" => Ok(CreateMethod::SplToken2022),
        other => bail!("invalid --create-method value: {other}"),
    }
}

#[derive(Debug, Clone)]
enum RaydiumCurveKind {
    Constant,
    Fixed,
    Linear,
}

fn parse_raydium_curve_kind(raw: &str) -> anyhow::Result<RaydiumCurveKind> {
    match raw.trim().to_ascii_lowercase().as_str() {
        "constant" => Ok(RaydiumCurveKind::Constant),
        "fixed" => Ok(RaydiumCurveKind::Fixed),
        "linear" => Ok(RaydiumCurveKind::Linear),
        other => bail!("invalid --raydium-curve-kind value: {other}"),
    }
}

#[derive(Debug, Clone, Copy)]
enum RaydiumAmmFeeOn {
    QuoteToken,
    BothToken,
}

fn parse_raydium_amm_fee_on(raw: &str) -> anyhow::Result<RaydiumAmmFeeOn> {
    match raw.trim().to_ascii_lowercase().as_str() {
        "quote_token" | "quote" => Ok(RaydiumAmmFeeOn::QuoteToken),
        "both_token" | "both" => Ok(RaydiumAmmFeeOn::BothToken),
        other => bail!("invalid --raydium-amm-fee-on value: {other}"),
    }
}

#[derive(Debug, Clone, Copy)]
enum RaydiumBaseTokenProgram {
    SplToken,
    SplToken2022,
}

fn parse_raydium_base_token_program(raw: &str) -> anyhow::Result<RaydiumBaseTokenProgram> {
    match raw.trim().to_ascii_lowercase().as_str() {
        "spl_token" | "token" | "tokenkeg" | "token_program" => {
            Ok(RaydiumBaseTokenProgram::SplToken)
        }
        "spl_token_2022" | "token_2022" | "token2022" | "token_2022_program" => {
            Ok(RaydiumBaseTokenProgram::SplToken2022)
        }
        other => bail!("invalid --raydium-base-token-program value: {other}"),
    }
}

fn parse_wallet_export_format(raw: &str) -> anyhow::Result<ManagedWalletExportFormat> {
    match raw.trim().to_ascii_lowercase().as_str() {
        "json" => Ok(ManagedWalletExportFormat::Json),
        "txt" | "text" => Ok(ManagedWalletExportFormat::Text),
        other => bail!("invalid --wallet-export-format value: {other}"),
    }
}

fn infer_wallet_export_format(path: &Path) -> Option<ManagedWalletExportFormat> {
    match path
        .extension()?
        .to_str()?
        .trim()
        .to_ascii_lowercase()
        .as_str()
    {
        "json" => Some(ManagedWalletExportFormat::Json),
        "txt" | "text" => Some(ManagedWalletExportFormat::Text),
        _ => None,
    }
}

