fn pump_fun_response_uses_token_2022(response: &CreateBuildResponse) -> bool {
    response.derived_addresses.contains_key("mayhem_program_id")
        || response.derived_addresses.contains_key("mayhem_state")
        || response
            .derived_addresses
            .contains_key("mayhem_token_vault")
}

fn expected_mint_token_program_for_create(
    method: CreateMethod,
    raydium_base_token_program: Option<RaydiumBaseTokenProgram>,
    response: &CreateBuildResponse,
) -> anyhow::Result<Pubkey> {
    if let Some(raw) = response
        .mint_token_program
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        return Pubkey::from_str(raw)
            .with_context(|| format!("invalid response.mint_token_program pubkey: {raw}"));
    }

    Ok(match method {
        CreateMethod::PumpFun => {
            if pump_fun_response_uses_token_2022(response) {
                TOKEN_2022_PROGRAM_ID
            } else {
                TOKEN_PROGRAM_ID
            }
        }
        CreateMethod::SplToken => TOKEN_PROGRAM_ID,
        CreateMethod::SplToken2022 => TOKEN_2022_PROGRAM_ID,
        CreateMethod::RaydiumLaunchpad => {
            match raydium_base_token_program.unwrap_or(RaydiumBaseTokenProgram::SplToken) {
                RaydiumBaseTokenProgram::SplToken => TOKEN_PROGRAM_ID,
                RaydiumBaseTokenProgram::SplToken2022 => TOKEN_2022_PROGRAM_ID,
            }
        }
    })
}

