struct ManagedPoolPositionRow {
    market: String,
    pool: String,
    base_mint: String,
    quote_mint: String,
    lp_mint: Option<String>,
    owner_pubkey: Option<String>,
    owner_label: Option<String>,
    owner_role: String,
    owner_lp_balance_raw: Option<String>,
    owner_lp_balance_ui: Option<f64>,
    lp_decimals: Option<u8>,
    estimated_base_out_ui: Option<f64>,
    estimated_quote_out_ui: Option<f64>,
    withdraw_supported: bool,
    close_supported: bool,
    note: Option<String>,
}

impl ManagedPoolPositionRow {
    fn market_enum(&self) -> Option<Market> {
        Market::from_token(&self.market)
    }

    fn pool_pubkey(&self) -> Option<Pubkey> {
        Pubkey::from_str(self.pool.trim()).ok()
    }

    fn base_mint_pubkey(&self) -> Option<Pubkey> {
        Pubkey::from_str(self.base_mint.trim()).ok()
    }

    fn quote_mint_pubkey(&self) -> Option<Pubkey> {
        Pubkey::from_str(self.quote_mint.trim()).ok()
    }

    fn lp_mint_pubkey(&self) -> Option<Pubkey> {
        self.lp_mint
            .as_deref()
            .and_then(|raw| Pubkey::from_str(raw.trim()).ok())
    }

    fn title_line(&self, width: usize) -> String {
        let market = self
            .market_enum()
            .map(monitor_market_label)
            .map(str::to_string)
            .unwrap_or_else(|| self.market.clone());
        let owner = self
            .owner_label
            .as_deref()
            .filter(|value| !value.trim().is_empty())
            .map(str::to_string)
            .or_else(|| {
                self.owner_pubkey
                    .as_deref()
                    .filter(|value| !value.trim().is_empty())
                    .map(short_pubkey_str)
            })
            .unwrap_or_else(|| "-".to_string());
        let prefix = if self.withdraw_supported {
            "●"
        } else {
            "○"
        };
        let lp = format_optional_compact_amount(self.owner_lp_balance_ui);
        let est_base = format_optional_compact_amount(self.estimated_base_out_ui);
        let est_quote = format_optional_compact_amount(self.estimated_quote_out_ui);
        truncate(
            &format!(
                "{prefix} {:<14} owner={} {} lp={} out≈{}/{}",
                market,
                owner,
                short_pubkey_str(&self.pool),
                lp,
                est_base,
                est_quote
            ),
            width,
        )
    }
}

