fn default_mamba_api_base_url() -> String {
    let bind = std::env::var("MAMBA_API_BIND_ADDR")
        .ok()
        .map(|v| v.trim().to_string())
        .filter(|v| !v.is_empty())
        .unwrap_or_else(|| "127.0.0.1:8787".to_string());
    let route_base = std::env::var("MAMBA_API_ROUTE_BASE")
        .ok()
        .map(|v| v.trim().to_string())
        .filter(|v| !v.is_empty())
        .unwrap_or_else(|| "/mamba-api".to_string());
    let route_base = if route_base.starts_with('/') {
        route_base
    } else {
        format!("/{route_base}")
    };
    let route_base = route_base.trim_end_matches('/');
    format!("http://{bind}{route_base}/v1")
}

fn require_api_base_url(raw: Option<String>) -> anyhow::Result<String> {
    let base = raw
        .or_else(|| std::env::var("MAMBA_API_BASE_URL").ok())
        .map(|v| v.trim().trim_end_matches('/').to_string())
        .filter(|v| !v.is_empty())
        .unwrap_or_else(default_mamba_api_base_url);
    anyhow::ensure!(
        base.ends_with("/v1"),
        "invalid api base url (must end with /v1): {base}"
    );
    Ok(base)
}

fn require_api_key(raw: Option<String>) -> anyhow::Result<String> {
    raw.or_else(|| std::env::var("MAMBA_API_KEY").ok())
        .map(|v| v.trim().to_string())
        .filter(|v| !v.is_empty())
        .context("missing api key (pass --create-api-key or set MAMBA_API_KEY)")
}

fn load_keypair_from_file(path: &std::path::Path) -> anyhow::Result<Keypair> {
    let raw =
        fs::read_to_string(path).with_context(|| format!("read keypair {}", path.display()))?;
    let bytes: Vec<u8> = serde_json::from_str(raw.trim())
        .with_context(|| format!("parse keypair json {}", path.display()))?;
    Keypair::try_from(bytes.as_slice())
        .with_context(|| format!("{} must encode 64 keypair bytes", path.display()))
}

fn write_private_text(path: &std::path::Path, text: &str) -> anyhow::Result<()> {
    fs::write(path, text).with_context(|| format!("write {}", path.display()))?;
    set_private_permissions(path, 0o600)
        .with_context(|| format!("chmod 600 {}", path.display()))?;
    Ok(())
}

#[cfg(unix)]
fn set_private_permissions(path: &Path, mode: u32) -> anyhow::Result<()> {
    fs::set_permissions(path, fs::Permissions::from_mode(mode))
        .with_context(|| format!("set permissions {mode:o} on {}", path.display()))?;
    Ok(())
}

#[cfg(not(unix))]
fn set_private_permissions(_path: &Path, _mode: u32) -> anyhow::Result<()> {
    Ok(())
}

