fn parse_ui_token_account_balance(account: &UiAccount) -> Option<(Pubkey, f64)> {
    let UiAccountData::Json(parsed) = &account.data else {
        return None;
    };
    let info = parsed.parsed.get("info")?;
    let mint = Pubkey::from_str(info.get("mint")?.as_str()?.trim()).ok()?;
    let token_amount = info.get("tokenAmount")?;
    let amount = token_amount
        .get("uiAmount")
        .and_then(Value::as_f64)
        .or_else(|| {
            token_amount
                .get("uiAmountString")
                .and_then(Value::as_str)
                .and_then(|raw| raw.parse::<f64>().ok())
        })?;
    if amount.is_finite() {
        Some((mint, amount))
    } else {
        None
    }
}

fn collect_position_balances_from_accounts(
    accounts: &[RpcKeyedAccount],
    candidate_mints: &HashSet<Pubkey>,
) -> HashMap<Pubkey, f64> {
    let mut balances = HashMap::new();
    for account in accounts {
        let Some((mint, amount)) = parse_ui_token_account_balance(&account.account) else {
            continue;
        };
        if !candidate_mints.contains(&mint) || !amount.is_finite() || amount <= 0.0 {
            continue;
        }
        *balances.entry(mint).or_insert(0.0) += amount;
    }
    balances
}

async fn fetch_wallet_position_balances(
    owner: &Pubkey,
    candidate_mints: &HashSet<Pubkey>,
    sol: Arc<SolHook>,
) -> anyhow::Result<HashMap<Pubkey, f64>> {
    let fetch = async {
        sol.run_rpc_attempts("getTokenAccountsByOwner", |rpc| async move {
            let spl_accounts = rpc.get_token_accounts_by_owner_with_commitment(
                owner,
                TokenAccountsFilter::ProgramId(TOKEN_PROGRAM_ID),
                CommitmentConfig::confirmed(),
            );
            let token_2022_accounts = rpc.get_token_accounts_by_owner_with_commitment(
                owner,
                TokenAccountsFilter::ProgramId(TOKEN_2022_PROGRAM_ID),
                CommitmentConfig::confirmed(),
            );
            let (spl_accounts, token_2022_accounts) =
                tokio::join!(spl_accounts, token_2022_accounts);

            let mut balances = collect_position_balances_from_accounts(
                &spl_accounts
                    .context("getTokenAccountsByOwner(spl-token) failed")?
                    .value,
                candidate_mints,
            );
            for (mint, amount) in collect_position_balances_from_accounts(
                &token_2022_accounts
                    .context("getTokenAccountsByOwner(token-2022) failed")?
                    .value,
                candidate_mints,
            ) {
                *balances.entry(mint).or_insert(0.0) += amount;
            }
            Ok::<_, anyhow::Error>(balances)
        })
        .await
    };

    tokio::time::timeout(
        Duration::from_secs(WALLET_POSITIONS_RPC_TIMEOUT_SECS),
        fetch,
    )
    .await
    .with_context(|| {
        format!(
            "wallet positions lookup timed out after {}s for {}",
            WALLET_POSITIONS_RPC_TIMEOUT_SECS, owner
        )
    })?
}

fn parse_token_account_owner_and_amount(
    account: &solana_account::Account,
) -> Option<(Pubkey, Pubkey, u64)> {
    if account.owner == TOKEN_PROGRAM_ID {
        use solana_program::program_pack::Pack;
        let parsed = spl_token::state::Account::unpack_from_slice(&account.data).ok()?;
        return Some((parsed.mint, parsed.owner, parsed.amount));
    }

    if account.owner == TOKEN_2022_PROGRAM_ID {
        use spl_token_2022::extension::StateWithExtensions;
        let parsed =
            StateWithExtensions::<spl_token_2022::state::Account>::unpack(&account.data).ok()?;
        return Some((parsed.base.mint, parsed.base.owner, parsed.base.amount));
    }

    None
}

async fn fetch_holders_snapshot(
    sol: &SolHook,
    mint: &Pubkey,
    holders_limit: usize,
) -> anyhow::Result<HoldersSnapshot> {
    let supply = sol
        .run_rpc_attempts("getTokenSupply", |rpc| async move {
            Ok(rpc.get_token_supply(mint).await?)
        })
        .await
        .ok();
    let supply_ui = supply.as_ref().and_then(ui_token_amount_to_f64);

    let largest_accounts = sol
        .run_rpc_attempts("getTokenLargestAccounts", |rpc| async move {
            Ok(rpc.get_token_largest_accounts(mint).await?)
        })
        .await
        .context("get_token_largest_accounts failed")?;

    let token_accounts = largest_accounts
        .iter()
        .filter_map(|row| Pubkey::from_str(row.address.trim()).ok())
        .collect::<Vec<_>>();

    let mut rows_by_owner: HashMap<Pubkey, (f64, usize)> = HashMap::new();
    if !token_accounts.is_empty() {
        let accounts = sol
            .get_multiple_accounts_resilient(&token_accounts)
            .await
            .context("get_multiple_accounts failed")?;

        let decimals = supply.as_ref().map(|s| s.decimals).unwrap_or(0);
        let divisor = 10_f64.powi(i32::from(decimals));

        for account in accounts.into_iter().flatten() {
            let Some((account_mint, owner, amount_raw)) =
                parse_token_account_owner_and_amount(&account)
            else {
                continue;
            };
            if &account_mint != mint {
                continue;
            }

            let amount_ui = (amount_raw as f64) / divisor;
            if !amount_ui.is_finite() || amount_ui <= 0.0 {
                continue;
            }
            let entry = rows_by_owner.entry(owner).or_insert((0.0, 0));
            entry.0 += amount_ui;
            entry.1 += 1;
        }
    }

    let mut rows = rows_by_owner
        .into_iter()
        .map(|(owner, (amount, token_accounts))| HolderRow {
            owner,
            amount,
            pct_supply: supply_ui
                .filter(|supply| *supply > 0.0)
                .map(|supply| (amount / supply) * 100.0),
            token_accounts,
        })
        .collect::<Vec<_>>();
    rows.sort_by(|left, right| right.amount.total_cmp(&left.amount));
    rows.truncate(holders_limit.max(1));

    let covered_supply_pct = supply_ui.filter(|supply| *supply > 0.0).and_then(|supply| {
        let covered: f64 = rows.iter().map(|row| row.amount).sum();
        let pct = (covered / supply) * 100.0;
        if pct.is_finite() { Some(pct) } else { None }
    });

    Ok(HoldersSnapshot {
        mint: *mint,
        fetched_unix_ms: now_unix_ms(),
        supply,
        rows,
        covered_supply_pct,
    })
}

fn spawn_holders_fetch(
    mint: Pubkey,
    holders_limit: usize,
    sol: Arc<SolHook>,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        match fetch_holders_snapshot(sol.as_ref(), &mint, holders_limit).await {
            Ok(snapshot) => {
                let _ = tx.send(AppMsg::Holders(snapshot)).await;
            }
            Err(error) => {
                let _ = tx
                    .send(AppMsg::HoldersError {
                        mint,
                        error: format!("{error:#}"),
                    })
                    .await;
            }
        }
    });
}

fn spawn_route_lookup(
    mint: Pubkey,
    market_priority: Option<Vec<Market>>,
    rpc: Arc<RpcClient>,
    cluster: mamba::core::cluster::SolanaCluster,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let sol_hook = SolHook::from_rpc_client_with_cluster(rpc, cluster);
        let sol = Arc::new(sol_hook.clone());
        let keypair = Arc::new(Keypair::new());
        let pump_fun = PumpFun::new(keypair.clone(), sol.clone());
        let pump_swap = PumpSwap::new(keypair.clone(), sol.clone());
        let swaps = Swaps::new(sol_hook, pump_swap, pump_fun);

        let mint_text = mint.to_string();
        let quote_text = WSOL_MINT.to_string();
        let route_timeout = Swaps::route_lookup_timeout_duration(market_priority.as_deref());
        let route = match tokio::time::timeout(
            route_timeout,
            swaps.find_pool_for_mint_with_market_priority(
                &mint_text,
                Some(&quote_text),
                0,
                market_priority.as_deref(),
            ),
        )
        .await
        {
            Ok(Ok(Some(route))) => route,
            Ok(Ok(None)) => {
                let _ = tx
                    .send(AppMsg::Route(RouteSnapshot {
                        mint,
                        fetched_unix_ms: now_unix_ms(),
                        route: None,
                        price_sol: None,
                    }))
                    .await;
                return;
            }
            Ok(Err(error)) => {
                let _ = tx
                    .send(AppMsg::RouteError {
                        mint,
                        error: format!("{error:#}"),
                    })
                    .await;
                return;
            }
            Err(_) => {
                let _ = tx
                    .send(AppMsg::RouteError {
                        mint,
                        error: format!("route lookup timed out after {}s", route_timeout.as_secs()),
                    })
                    .await;
                return;
            }
        };

        let price_timeout = Swaps::price_lookup_timeout_duration();
        match tokio::time::timeout(
            price_timeout,
            swaps.fetch_price_for_market_pool(route.market, &route.pool),
        )
        .await
        {
            Ok(Ok(price_sol)) => {
                let _ = tx
                    .send(AppMsg::Route(RouteSnapshot {
                        mint,
                        fetched_unix_ms: now_unix_ms(),
                        route: Some(route),
                        price_sol: Some(price_sol),
                    }))
                    .await;
            }
            Ok(Err(error)) => {
                let _ = tx
                    .send(AppMsg::RouteError {
                        mint,
                        error: format!("{error:#}"),
                    })
                    .await;
            }
            Err(_) => {
                let _ = tx
                    .send(AppMsg::RouteError {
                        mint,
                        error: format!(
                            "price lookup timed out after {}s for market {} pool {}",
                            price_timeout.as_secs(),
                            route.market.as_str(),
                            route.pool
                        ),
                    })
                    .await;
            }
        }
    });
}

