fn spawn_wallet_positions_lookup(
    wallets: Vec<(Pubkey, Option<String>)>,
    candidates: Vec<WalletPositionRow>,
    sol: Arc<SolHook>,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        if wallets.is_empty() || candidates.is_empty() {
            let _ = tx
                .send(AppMsg::WalletPositions(WalletPositionsSnapshot {
                    fetched_unix_ms: now_unix_ms(),
                    positions: Vec::new(),
                }))
                .await;
            return;
        }

        let candidate_by_mint = candidates
            .into_iter()
            .map(|candidate| (candidate.mint, candidate))
            .collect::<HashMap<_, _>>();
        let candidate_mints = candidate_by_mint.keys().copied().collect::<HashSet<_>>();
        let mut positions = Vec::new();
        let mut errors = Vec::new();
        for (owner_pubkey, owner_label) in wallets {
            let balances =
                match fetch_wallet_position_balances(&owner_pubkey, &candidate_mints, sol.clone())
                    .await
                {
                    Ok(balances) => balances,
                    Err(err) => {
                        let owner = owner_label
                            .as_deref()
                            .map(str::to_string)
                            .unwrap_or_else(|| short_pubkey(&owner_pubkey));
                        errors.push(format!("{owner}: {}", truncate(&format!("{err:#}"), 120)));
                        continue;
                    }
                };
            for (mint, token_amount) in balances {
                if !token_amount.is_finite() || token_amount <= 0.0 {
                    continue;
                }
                let Some(candidate) = candidate_by_mint.get(&mint) else {
                    continue;
                };
                positions.push(WalletPositionRow {
                    owner_pubkey,
                    owner_label: owner_label.clone(),
                    token_amount,
                    value_sol: candidate.price_sol.map(|price| price * token_amount),
                    ..candidate.clone()
                });
            }
        }

        positions.sort_by(|left, right| {
            right
                .value_sol
                .unwrap_or(0.0)
                .total_cmp(&left.value_sol.unwrap_or(0.0))
                .then(right.last_seen_unix_ms.cmp(&left.last_seen_unix_ms))
        });

        if positions.is_empty() && !errors.is_empty() {
            let _ = tx
                .send(AppMsg::WalletPositionsError {
                    error: truncate(&errors.join(" | "), 220),
                })
                .await;
            return;
        }

        let _ = tx
            .send(AppMsg::WalletPositions(WalletPositionsSnapshot {
                fetched_unix_ms: now_unix_ms(),
                positions,
            }))
            .await;
    });
}

fn spawn_trade_token_balance_lookup(
    market: Market,
    mint: Pubkey,
    wallets: Vec<Pubkey>,
    sol: Arc<SolHook>,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let mut token_balance = 0.0;
        for owner_pubkey in wallets {
            let balance = sol
                .get_token_balance(&owner_pubkey, &mint)
                .await
                .unwrap_or(0.0);
            if balance.is_finite() && balance > 0.0 {
                token_balance += balance;
            }
        }

        let _ = tx
            .send(AppMsg::TradeTokenBalance(TradeTokenBalanceSnapshot {
                market,
                mint,
                fetched_unix_ms: now_unix_ms(),
                token_balance,
            }))
            .await;
    });
}

fn spawn_pool_positions_fetch(
    network: CreateNetwork,
    wallets: Vec<(Pubkey, Option<String>)>,
    base: String,
    api_key: String,
    rpc_url_override: Option<String>,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let res = async {
            let client = reqwest::Client::builder()
                .timeout(Duration::from_secs(30))
                .build()
                .context("build http client")?;
            let mut out = Vec::new();
            for (pubkey, owner_label) in wallets {
                let mut url = build_mamba_api_url(&base, "pool/positions")?;
                url.query_pairs_mut()
                    .append_pair("owner", &pubkey.to_string())
                    .append_pair("include_unsupported", "false");
                if let Some(rpc_url) = rpc_url_override.as_deref() {
                    url.query_pairs_mut().append_pair("rpc_url", rpc_url);
                }
                let mut positions: Vec<ManagedPoolPositionRow> =
                    http_json(client.get(url).header("x-api-key", &api_key)).await?;
                for row in positions.iter_mut() {
                    row.owner_pubkey = Some(pubkey.to_string());
                    row.owner_label = owner_label.clone();
                }
                out.extend(positions);
            }
            Ok::<_, anyhow::Error>(out)
        }
        .await;

        match res {
            Ok(positions) => {
                let _ = tx
                    .send(AppMsg::PoolPositions(PoolPositionsSnapshot {
                        network,
                        fetched_unix_ms: now_unix_ms(),
                        positions,
                    }))
                    .await;
            }
            Err(error) => {
                let _ = tx
                    .send(AppMsg::PoolPositionsError {
                        network,
                        error: format!("{error:#}"),
                    })
                    .await;
            }
        }
    });
}

async fn build_pool_manage_via_api_and_sign(
    position: ManagedPoolPositionRow,
    network: CreateNetwork,
    withdraw_pct: f64,
    slippage_pct: f64,
    base: &str,
    api_key: &str,
    payer: Arc<Keypair>,
    http_url: Option<&str>,
    send: bool,
    confirm: bool,
) -> anyhow::Result<PoolManageFinished> {
    let market = position
        .market_enum()
        .with_context(|| format!("unsupported pool market {}", position.market))?;
    let pool = position.pool_pubkey().context("invalid pool pubkey")?;
    let base_mint = position
        .base_mint_pubkey()
        .context("invalid base mint pubkey")?;
    let quote_mint = position
        .quote_mint_pubkey()
        .context("invalid quote mint pubkey")?;
    let lp_mint = position.lp_mint_pubkey();
    let owner = payer.pubkey();
    let rpc_url = http_url
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| network.default_http_url());

    let timestamp = chrono::Utc::now().format("%Y%m%dT%H%M%SZ").to_string();
    let out_dir = PathBuf::from("artifacts/pool-manage");
    fs::create_dir_all(&out_dir)
        .with_context(|| format!("create pool-manage out dir {}", out_dir.display()))?;
    let bundle_path = create_pool_manage_bundle_path(&out_dir, &timestamp, market.as_str(), &pool);

    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(60))
        .build()
        .context("build http client")?;

    let body = json!({
        "market": market.as_str(),
        "owner": owner.to_string(),
        "pool": pool.to_string(),
        "withdraw_pct": withdraw_pct,
        "slippage_pct": slippage_pct,
        "simulate": true,
        "rpc_url": rpc_url,
    });
    let url = format!("{base}/pool/manage/build");
    let response: PoolBuildResponse =
        http_json(client.post(url).header("x-api-key", api_key).json(&body)).await?;

    let unsigned_wire = B64
        .decode(response.transaction.trim())
        .context("decode unsigned tx base64")?;
    let unsigned_tx: VersionedTransaction =
        bincode::deserialize(&unsigned_wire).context("deserialize unsigned tx")?;

    let required_signers: Vec<Pubkey> = response
        .required_signers
        .iter()
        .map(|raw| Pubkey::from_str(raw.trim()))
        .collect::<Result<Vec<_>, _>>()
        .context("parse required_signers")?;
    anyhow::ensure!(
        required_signers == vec![owner],
        "pool management builder returned unexpected required signers: {required_signers:?}"
    );

    let signed_tx = VersionedTransaction::try_new(unsigned_tx.message.clone(), &[payer.as_ref()])
        .context("sign transaction")?;
    let signed_wire = bincode::serialize(&signed_tx).context("serialize signed tx")?;
    let signed_b64 = B64.encode(signed_wire);

    let sol = SolHook::new(rpc_url.to_string());
    let cluster = detect_cluster_via_sol(&sol).await;
    let signed_sim_ok = simulate_signed_transaction_ok(&sol, &signed_tx).await;
    let server_sim_ok = response.simulation.as_ref().map(|sim| sim.ok);

    let mut send_sig: Option<String> = None;
    let mut confirm_ok: Option<bool> = None;
    let mut send_error: Option<String> = None;

    if send {
        if server_sim_ok.is_some_and(|ok| !ok) {
            send_error = Some("refusing to send: server simulation failed".to_string());
        } else if signed_sim_ok.is_some_and(|ok| !ok) {
            send_error = Some("refusing to send: signed simulation failed".to_string());
        } else {
            let allow_mainnet_send = std::env::var("MAMBA_CLIENT_ALLOW_MAINNET_SEND")
                .ok()
                .is_some_and(|value| {
                    matches!(
                        value.trim().to_ascii_lowercase().as_str(),
                        "1" | "true" | "yes"
                    )
                });
            match network {
                CreateNetwork::Devnet => {
                    if cluster != Some(mamba::core::cluster::SolanaCluster::Devnet) {
                        send_error = Some(format!(
                            "refusing to send: rpc cluster mismatch (expected devnet got {:?})",
                            cluster
                        ));
                    }
                }
                CreateNetwork::Mainnet => {
                    if !allow_mainnet_send {
                        send_error = Some(
                            "send locked: mainnet (set MAMBA_CLIENT_ALLOW_MAINNET_SEND=true)"
                                .to_string(),
                        );
                    } else if cluster != Some(mamba::core::cluster::SolanaCluster::MainnetBeta) {
                        send_error = Some(format!(
                            "refusing to send: rpc cluster mismatch (expected mainnet got {:?})",
                            cluster
                        ));
                    }
                }
            }
        }

        if send_error.is_none() {
            match send_signed_transaction_via_sol(&sol, &signed_tx).await {
                Ok(sig) => {
                    send_sig = Some(sig.to_string());
                    if confirm {
                        match wait_for_confirmed_signature_via_sol(&sol, &sig, "pool management tx")
                            .await
                        {
                            Ok(()) => confirm_ok = Some(true),
                            Err(err) => {
                                confirm_ok = Some(false);
                                send_error = Some(format!("{err:#}"));
                            }
                        }
                    }
                }
                Err(err) => {
                    send_error = Some(format!("sendTransaction failed: {err:#}"));
                }
            }
        }
    }

    let bundle = PoolManageArtifactBundle {
        timestamp_utc: timestamp.clone(),
        flow: "tui".to_string(),
        market: market.as_str().to_string(),
        owner: owner.to_string(),
        pool: pool.to_string(),
        base_mint: base_mint.to_string(),
        quote_mint: quote_mint.to_string(),
        lp_mint: lp_mint.map(|value| value.to_string()),
        withdraw_pct,
        slippage_pct,
        api_base_url: Some(base.to_string()),
        rpc_url: Some(redact_url_for_artifact(rpc_url)),
        request: Some(body),
        response: Some(response),
        signed_tx_b64: Some(signed_b64),
        signed_sim_ok,
        cluster: cluster.map(|value| format!("{value:?}")),
        send_requested: send,
        send_signature: send_sig.clone(),
        confirm_ok,
        error: send_error.clone(),
    };
    write_pool_manage_bundle(&bundle_path, &bundle)?;

    Ok(PoolManageFinished {
        out_dir: bundle_path,
        market,
        pool,
        base_mint,
        quote_mint,
        lp_mint,
        cluster,
        server_sim_ok,
        signed_sim_ok,
        send_requested: send,
        send_sig,
        confirm_ok,
        send_error,
    })
}

fn spawn_pool_manage_build(
    position: ManagedPoolPositionRow,
    network: CreateNetwork,
    withdraw_pct: f64,
    slippage_pct: f64,
    base: String,
    api_key: String,
    payer: Arc<Keypair>,
    http_url: Option<String>,
    send: bool,
    confirm: bool,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        match build_pool_manage_via_api_and_sign(
            position,
            network,
            withdraw_pct,
            slippage_pct,
            &base,
            &api_key,
            payer,
            http_url.as_deref(),
            send,
            confirm,
        )
        .await
        {
            Ok(finished) => {
                let _ = tx.send(AppMsg::PoolManageFinished(finished)).await;
            }
            Err(error) => {
                let _ = tx
                    .send(AppMsg::PoolManageFailed {
                        error: format!("{error:#}"),
                    })
                    .await;
            }
        }
    });
}

fn spawn_wallet_create(
    base: String,
    api_key: String,
    label: Option<String>,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let res = async {
            let client = reqwest::Client::builder()
                .timeout(Duration::from_secs(20))
                .build()
                .context("build http client")?;
            let body = json!({
                "label": label,
            });
            let url = format!("{base}/wallets");
            let wallet: ManagedWalletSummary =
                http_json(client.post(url).header("x-api-key", api_key).json(&body)).await?;
            Ok::<_, anyhow::Error>(wallet)
        }
        .await;

        match res {
            Ok(wallet) => {
                let _ = tx.send(AppMsg::WalletCreateFinished(wallet)).await;
            }
            Err(error) => {
                let _ = tx
                    .send(AppMsg::WalletCreateFailed {
                        error: format!("{error:#}"),
                    })
                    .await;
            }
        }
    });
}

async fn build_wallet_transfer_via_api_and_sign(
    network: CreateNetwork,
    from: Pubkey,
    to: Pubkey,
    asset: WalletTransferAsset,
    mint: Option<Pubkey>,
    amount_input: String,
    base: &str,
    api_key: &str,
    payer: Arc<Keypair>,
    http_url: Option<&str>,
    send: bool,
    confirm: bool,
) -> anyhow::Result<WalletTransferFinished> {
    anyhow::ensure!(
        payer.pubkey() == from,
        "transfer signer mismatch: expected {from} got {}",
        payer.pubkey()
    );

    let rpc_url = http_url
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| network.default_http_url());

    let timestamp = chrono::Utc::now().format("%Y%m%dT%H%M%SZ").to_string();
    let out_dir = PathBuf::from("artifacts/wallet-transfer");
    fs::create_dir_all(&out_dir)
        .with_context(|| format!("create wallet-transfer out dir {}", out_dir.display()))?;
    let bundle_path = create_wallet_transfer_bundle_path(&out_dir, &timestamp, &from, &to);

    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(60))
        .build()
        .context("build http client")?;

    let body = json!({
        "from_wallet": from.to_string(),
        "to_wallet": to.to_string(),
        "amount": amount_input,
        "asset_kind": asset.label(),
        "mint": mint.map(|value| value.to_string()),
        "rpc_url": rpc_url,
    });
    let url = format!("{base}/wallets/transfer/build");
    let response: WalletTransferBuildResponse =
        http_json(client.post(url).header("x-api-key", api_key).json(&body)).await?;

    let unsigned_wire = B64
        .decode(response.transaction.trim())
        .context("decode unsigned tx base64")?;
    let unsigned_tx: VersionedTransaction =
        bincode::deserialize(&unsigned_wire).context("deserialize unsigned tx")?;

    let required_signers: Vec<Pubkey> = response
        .required_signers
        .iter()
        .map(|raw| Pubkey::from_str(raw.trim()))
        .collect::<Result<Vec<_>, _>>()
        .context("parse required_signers")?;
    anyhow::ensure!(
        required_signers == vec![from],
        "wallet transfer builder returned unexpected required signers: {required_signers:?}"
    );

    let signed_tx = VersionedTransaction::try_new(unsigned_tx.message.clone(), &[payer.as_ref()])
        .context("sign wallet transfer transaction")?;
    let signed_wire = bincode::serialize(&signed_tx).context("serialize signed tx")?;
    let signed_b64 = B64.encode(signed_wire);

    let sol = SolHook::new(rpc_url.to_string());
    let cluster = detect_cluster_via_sol(&sol).await;

    let mut send_sig: Option<String> = None;
    let mut confirm_ok: Option<bool> = None;
    let mut send_error: Option<String> = None;

    if send {
        let allow_mainnet_send = allow_mainnet_send_from_env();
        match network {
            CreateNetwork::Devnet => {
                if cluster != Some(mamba::core::cluster::SolanaCluster::Devnet) {
                    send_error = Some(format!(
                        "refusing to send: rpc cluster mismatch (expected devnet got {:?})",
                        cluster
                    ));
                }
            }
            CreateNetwork::Mainnet => {
                if !allow_mainnet_send {
                    send_error = Some(
                        "send locked: mainnet (set MAMBA_CLIENT_ALLOW_MAINNET_SEND=true)"
                            .to_string(),
                    );
                } else if cluster != Some(mamba::core::cluster::SolanaCluster::MainnetBeta) {
                    send_error = Some(format!(
                        "refusing to send: rpc cluster mismatch (expected mainnet got {:?})",
                        cluster
                    ));
                }
            }
        }

        if send_error.is_none() {
            match send_signed_transaction_via_sol(&sol, &signed_tx).await {
                Ok(sig) => {
                    send_sig = Some(sig.to_string());
                    if confirm {
                        match wait_for_confirmed_signature_via_sol(&sol, &sig, "wallet transfer")
                            .await
                        {
                            Ok(()) => confirm_ok = Some(true),
                            Err(err) => {
                                confirm_ok = Some(false);
                                send_error = Some(format!("{err:#}"));
                            }
                        }
                    }
                }
                Err(err) => {
                    send_error = Some(format!("sendTransaction failed: {err:#}"));
                }
            }
        }
    }

    let bundle = WalletTransferArtifactBundle {
        timestamp_utc: timestamp.clone(),
        flow: "tui".to_string(),
        from: from.to_string(),
        to: to.to_string(),
        mint: mint.map(|value| value.to_string()),
        kind: response.kind.clone(),
        amount_input: response.amount_input.clone(),
        amount_raw: response.amount_raw.clone(),
        api_base_url: Some(base.to_string()),
        rpc_url: Some(redact_url_for_artifact(rpc_url)),
        request: Some(body),
        response: Some(response.clone()),
        signed_tx_b64: Some(signed_b64),
        cluster: cluster.map(|value| format!("{value:?}")),
        send_requested: send,
        send_signature: send_sig.clone(),
        confirm_ok,
        error: send_error.clone(),
    };
    write_wallet_transfer_bundle(&bundle_path, &bundle)?;

    Ok(WalletTransferFinished {
        out_dir: bundle_path,
        from,
        to,
        mint,
        kind: response.kind,
        amount_input: response.amount_input,
        amount_raw: response.amount_raw,
        cluster,
        send_requested: send,
        send_sig,
        confirm_ok,
        send_error,
    })
}

async fn build_wallet_clean_via_api_and_sign(
    network: CreateNetwork,
    owner: Pubkey,
    burn_nonzero: bool,
    close_empty: bool,
    close_wsol: bool,
    base: &str,
    api_key: &str,
    payer: Arc<Keypair>,
    http_url: Option<&str>,
    send: bool,
    confirm: bool,
) -> anyhow::Result<WalletCleanFinished> {
    anyhow::ensure!(
        payer.pubkey() == owner,
        "wallet cleaner signer mismatch: expected {owner} got {}",
        payer.pubkey()
    );

    let rpc_url = http_url
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or_else(|| network.default_http_url());

    let timestamp = chrono::Utc::now().format("%Y%m%dT%H%M%SZ").to_string();
    let out_dir = PathBuf::from("artifacts/wallet-clean");
    fs::create_dir_all(&out_dir)
        .with_context(|| format!("create wallet-clean out dir {}", out_dir.display()))?;
    let bundle_path = create_wallet_clean_bundle_path(&out_dir, &timestamp, &owner);

    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(60))
        .build()
        .context("build http client")?;

    let body = json!({
        "owner": owner.to_string(),
        "burn_nonzero": burn_nonzero,
        "close_empty": close_empty,
        "close_wsol": close_wsol,
        "simulate": true,
        "rpc_url": rpc_url,
    });
    let response = wallet_clean_build_via_api_or_local(
        &client,
        base,
        api_key,
        rpc_url,
        owner,
        burn_nonzero,
        close_empty,
        close_wsol,
    )
    .await?;

    let sol = SolHook::new(rpc_url.to_string());
    let cluster = detect_cluster_via_sol(&sol).await;

    let mut send_sigs = Vec::new();
    let mut send_error: Option<String> = None;
    let mut batch_artifacts = Vec::new();

    if send {
        let allow_mainnet_send = allow_mainnet_send_from_env();
        match network {
            CreateNetwork::Devnet => {
                if cluster != Some(mamba::core::cluster::SolanaCluster::Devnet) {
                    send_error = Some(format!(
                        "refusing to send: rpc cluster mismatch (expected devnet got {:?})",
                        cluster
                    ));
                }
            }
            CreateNetwork::Mainnet => {
                if !allow_mainnet_send {
                    send_error = Some(
                        "send locked: mainnet (set MAMBA_CLIENT_ALLOW_MAINNET_SEND=true)"
                            .to_string(),
                    );
                } else if cluster != Some(mamba::core::cluster::SolanaCluster::MainnetBeta) {
                    send_error = Some(format!(
                        "refusing to send: rpc cluster mismatch (expected mainnet got {:?})",
                        cluster
                    ));
                }
            }
        }
    }

    for batch in response.batches.iter() {
        let unsigned_wire = B64
            .decode(batch.transaction.trim())
            .context("decode wallet clean unsigned tx base64")?;
        let unsigned_tx: VersionedTransaction =
            bincode::deserialize(&unsigned_wire).context("deserialize wallet clean unsigned tx")?;

        let required_signers: Vec<Pubkey> = batch
            .required_signers
            .iter()
            .map(|raw| Pubkey::from_str(raw.trim()))
            .collect::<Result<Vec<_>, _>>()
            .context("parse wallet clean required_signers")?;
        anyhow::ensure!(
            required_signers == vec![owner],
            "wallet cleaner builder returned unexpected required signers: {required_signers:?}"
        );

        let signed_tx =
            VersionedTransaction::try_new(unsigned_tx.message.clone(), &[payer.as_ref()])
                .context("sign wallet cleaner transaction")?;
        let signed_wire = bincode::serialize(&signed_tx).context("serialize signed tx")?;
        let signed_b64 = B64.encode(signed_wire);
        let signed_sim_ok = simulate_signed_transaction_ok(&sol, &signed_tx).await;

        let mut send_signature: Option<String> = None;
        let mut batch_confirm_ok: Option<bool> = None;
        let mut batch_error: Option<String> = None;

        if send && send_error.is_none() {
            if signed_sim_ok.is_some_and(|ok| !ok) {
                batch_error = Some(format!(
                    "refusing to send cleaner batch {}: signed simulation failed",
                    batch.batch_index + 1
                ));
            } else {
                match send_signed_transaction_via_sol(&sol, &signed_tx).await {
                    Ok(sig) => {
                        let sig_text = sig.to_string();
                        send_sigs.push(sig_text.clone());
                        send_signature = Some(sig_text);
                        if confirm {
                            let label = format!("wallet cleaner batch {}", batch.batch_index + 1);
                            match wait_for_confirmed_signature_via_sol(&sol, &sig, &label).await {
                                Ok(()) => batch_confirm_ok = Some(true),
                                Err(err) => {
                                    batch_confirm_ok = Some(false);
                                    batch_error = Some(format!("{err:#}"));
                                }
                            }
                        }
                    }
                    Err(err) => {
                        batch_error = Some(format!("sendTransaction failed: {err:#}"));
                    }
                }
            }
        }

        if batch_error.is_some() && send_error.is_none() {
            send_error = batch_error.clone();
        }
        batch_artifacts.push(WalletCleanBatchArtifact {
            batch_index: batch.batch_index,
            signed_tx_b64: Some(signed_b64),
            signed_sim_ok,
            send_signature,
            confirm_ok: batch_confirm_ok,
            error: batch_error,
        });
    }

    let bundle = WalletCleanArtifactBundle {
        timestamp_utc: timestamp.clone(),
        flow: "tui".to_string(),
        owner: owner.to_string(),
        burn_nonzero,
        close_empty,
        close_wsol,
        api_base_url: Some(base.to_string()),
        rpc_url: Some(redact_url_for_artifact(rpc_url)),
        request: Some(body),
        response: Some(response.clone()),
        cluster: cluster.map(|value| format!("{value:?}")),
        send_requested: send,
        batches: batch_artifacts,
        error: send_error.clone(),
    };
    write_wallet_clean_bundle(&bundle_path, &bundle)?;

    Ok(WalletCleanFinished {
        out_dir: bundle_path,
        selected_account_count: response.selected_account_count,
        selected_reclaim_lamports: response.selected_reclaim_lamports,
        send_requested: send,
        send_sigs,
        send_error,
    })
}

fn spawn_wallet_clean_batch(
    wallets: Vec<WalletActionTarget>,
    network: CreateNetwork,
    burn_nonzero: bool,
    close_empty: bool,
    close_wsol: bool,
    base: String,
    api_key: String,
    http_url: Option<String>,
    send: bool,
    confirm: bool,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let mut outcomes = Vec::with_capacity(wallets.len());
        for wallet in wallets {
            let result = build_wallet_clean_via_api_and_sign(
                network,
                wallet.pubkey,
                burn_nonzero,
                close_empty,
                close_wsol,
                &base,
                &api_key,
                wallet.signer.clone(),
                http_url.as_deref(),
                send,
                confirm,
            )
            .await;
            match result {
                Ok(finished) => outcomes.push(WalletActionOutcome {
                    wallet_pubkey: wallet.pubkey,
                    wallet_label: wallet.label,
                    finished: Some(finished),
                    error: None,
                }),
                Err(error) => outcomes.push(WalletActionOutcome {
                    wallet_pubkey: wallet.pubkey,
                    wallet_label: wallet.label,
                    finished: None,
                    error: Some(format!("{error:#}")),
                }),
            }
        }
        let _ = tx.send(AppMsg::WalletCleanBatchFinished(outcomes)).await;
    });
}

