#[derive(Debug, Clone, Copy)]
struct CreateAutoBuyParams {
    buy_sol: f64,
    slippage_pct: f64,
}

async fn build_create_via_api_and_sign(
    method: CreateMethod,
    name: String,
    symbol: String,
    uri: String,
    raydium_launchpad: Option<serde_json::Value>,
    raydium_base_token_program: Option<RaydiumBaseTokenProgram>,
    auto_buy: Option<CreateAutoBuyParams>,
    description: Option<String>,
    image_path: Option<PathBuf>,
    twitter: Option<String>,
    telegram: Option<String>,
    website: Option<String>,
    show_name: bool,
    ipfs_upload_url: Option<String>,
    decimals: Option<u8>,
    swqos_settings: Option<SWQoSettings>,
    base: &str,
    api_key: &str,
    payer: Arc<Keypair>,
    http_url: Option<&str>,
    send: bool,
    confirm: bool,
    verify: bool,
) -> anyhow::Result<CreateFinished> {
    let inferred_network = http_url
        .map(str::trim)
        .filter(|v| !v.is_empty())
        .and_then(infer_create_network_from_url);
    let (mut swqos_settings, initial_swqos_note) = match inferred_network {
        Some(network) => swqos_settings_for_network(swqos_settings, network),
        None => (swqos_settings, None),
    };
    let payer_pubkey = payer.pubkey();
    let mint_keypair = Keypair::new();
    let mint_pubkey = mint_keypair.pubkey();

    let expected_name = name.clone();
    let expected_symbol = symbol.clone();
    let mut uri = uri;

    let has_metadata_fields = description.as_deref().is_some_and(|v| !v.trim().is_empty())
        || twitter.as_deref().is_some_and(|v| !v.trim().is_empty())
        || telegram.as_deref().is_some_and(|v| !v.trim().is_empty())
        || website.as_deref().is_some_and(|v| !v.trim().is_empty());

    if has_metadata_fields && image_path.is_none() {
        bail!("image path is required when providing token description/socials");
    }

    let timestamp = chrono::Utc::now().format("%Y%m%dT%H%M%SZ").to_string();
    let out_dir = PathBuf::from("artifacts/create");
    fs::create_dir_all(&out_dir)
        .with_context(|| format!("create out dir {}", out_dir.display()))?;
    let bundle_path = create_bundle_path(&out_dir, &timestamp, method.as_api_str(), &mint_pubkey);
    let mut notes = Vec::new();
    if let Some(note) = initial_swqos_note {
        notes.push(note.to_string());
    }

    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(60))
        .build()
        .context("build http client")?;

    let mut metadata_upload: Option<serde_json::Value> = None;
    if let Some(image_path) = image_path.as_deref() {
        let upload_url = ipfs_upload_url
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
            .map(|v| v.to_string())
            .or_else(|| {
                std::env::var("MAMBA_IPFS_UPLOAD_URL")
                    .ok()
                    .map(|v| v.trim().to_string())
                    .filter(|v| !v.is_empty())
            })
            .unwrap_or_else(|| DEFAULT_PUMP_FUN_IPFS_UPLOAD_URL.to_string());

        let file_bytes = fs::read(image_path)
            .with_context(|| format!("read image file {}", image_path.display()))?;
        let file_name = image_path
            .file_name()
            .and_then(|v| v.to_str())
            .unwrap_or("image");
        let file_content_type = guess_image_content_type(image_path);
        let description = description.as_deref().unwrap_or_default();

        let upload = upload_token_metadata_to_ipfs_via_pump_fun(
            &client,
            &upload_url,
            PumpFunIpfsUploadRequest {
                name: &expected_name,
                symbol: &expected_symbol,
                description,
                twitter: twitter.as_deref(),
                telegram: telegram.as_deref(),
                website: website.as_deref(),
                show_name,
                file_name,
                file_bytes: &file_bytes,
                file_content_type,
            },
        )
        .await
        .context("ipfs upload failed")?;

        metadata_upload = Some(serde_json::to_value(&upload).context("serialize metadata upload")?);
        uri = upload.metadata_uri;
    }

    let expected_uri = uri.clone();

    let mut body = json!({
        "method": method.as_api_str(),
        "payer": payer_pubkey.to_string(),
        "mint": mint_pubkey.to_string(),
        "name": name,
        "symbol": symbol,
        "uri": uri,
        "simulate": true,
    });
    if let Some(rpc_url) = http_url.map(str::trim).filter(|v| !v.is_empty()) {
        body["rpc_url"] = json!(rpc_url);
    }
    if let Some(decimals) = decimals {
        body["decimals"] = json!(decimals);
    }
    if let Some(auto_buy) = auto_buy {
        anyhow::ensure!(
            matches!(
                method,
                CreateMethod::PumpFun | CreateMethod::RaydiumLaunchpad
            ),
            "auto-buy is only supported for pump_fun or raydium_launchpad"
        );
        body["auto_buy"] = json!({
            "buy_sol": auto_buy.buy_sol,
            "slippage_pct": auto_buy.slippage_pct,
        });
    }
    apply_swqos_settings_to_build_body(&mut body, swqos_settings.as_ref());
    if method == CreateMethod::RaydiumLaunchpad {
        let params = raydium_launchpad.context("missing raydium_launchpad params")?;
        body["raydium_launchpad"] = params;
        anyhow::ensure!(
            raydium_base_token_program.is_some(),
            "missing raydium base token program"
        );
    } else {
        anyhow::ensure!(
            raydium_launchpad.is_none() && raydium_base_token_program.is_none(),
            "unexpected raydium launchpad params for non-raydium create method"
        );
    }

    let url = format!("{base}/create/build");
    let response: CreateBuildResponse = match http_json(
        client
            .post(url.clone())
            .header("x-api-key", api_key)
            .json(&body),
    )
    .await
    {
        Ok(response) => response,
        Err(err) if swqos_settings.is_some() => {
            if let Some(note) = swqos_build_retry_note(&err) {
                notes.push(note.to_string());
                swqos_settings = None;
                apply_swqos_settings_to_build_body(&mut body, None);
                http_json(client.post(url).header("x-api-key", api_key).json(&body)).await?
            } else {
                return Err(err);
            }
        }
        Err(err) => return Err(err),
    };

    let unsigned_wire = B64
        .decode(response.transaction.trim())
        .context("decode unsigned tx base64")?;
    let unsigned_tx: VersionedTransaction =
        bincode::deserialize(&unsigned_wire).context("deserialize unsigned tx")?;

    let required_signers: Vec<Pubkey> = response
        .required_signers
        .iter()
        .map(|s| Pubkey::from_str(s.trim()))
        .collect::<Result<Vec<_>, _>>()
        .context("parse required_signers")?;
    anyhow::ensure!(
        required_signers.contains(&payer_pubkey),
        "response.required_signers missing payer pubkey"
    );
    anyhow::ensure!(
        required_signers.contains(&mint_pubkey),
        "response.required_signers missing mint pubkey"
    );

    let signed_tx = VersionedTransaction::try_new(
        unsigned_tx.message.clone(),
        &[payer.as_ref(), &mint_keypair],
    )
    .context("sign transaction")?;
    let signed_wire = bincode::serialize(&signed_tx).context("serialize signed tx")?;
    let signed_b64 = B64.encode(signed_wire);

    let mut cluster: Option<mamba::core::cluster::SolanaCluster> = None;
    let mut signed_simulation_ok: Option<bool> = None;
    if let Some(http_url) = http_url.map(str::trim).filter(|v| !v.is_empty()) {
        let sol = SolHook::new(http_url.to_string());
        cluster = detect_cluster_via_sol(&sol).await;
        signed_simulation_ok = simulate_signed_transaction_ok(&sol, &signed_tx).await;
    }

    let mut send_sig: Option<String> = None;
    let mut confirm_ok: Option<bool> = None;
    let mut verify_ok: Option<bool> = None;
    let mut send_error: Option<String> = None;
    let mut onchain_token_info: Option<TokenInfo> = None;

    let server_sim_ok = response.simulation.as_ref().map(|sim| sim.ok);

    if send {
        if verify && !confirm {
            send_error = Some("verify requires confirm".to_string());
        } else if server_sim_ok.is_some_and(|ok| !ok) {
            send_error = Some("refusing to send: server simulation failed".to_string());
        } else if signed_simulation_ok.is_some_and(|ok| !ok) {
            send_error = Some("refusing to send: signed simulation failed".to_string());
        } else {
            let rpc_url = http_url
                .map(str::trim)
                .filter(|v| !v.is_empty())
                .ok_or_else(|| anyhow::anyhow!("missing http url (required for live send)"));

            match rpc_url {
                Ok(rpc_url) => {
                    let sol = SolHook::new(rpc_url.to_string());

                    let send_result = if let Some(settings) = swqos_settings.as_ref() {
                        sol.submit_signed_via_swqos(&signed_tx, settings).await
                    } else {
                        send_signed_transaction_via_sol(&sol, &signed_tx).await
                    };

                    match send_result {
                        Ok(sig) => {
                            send_sig = Some(sig.to_string());

                            if send_error.is_none() && confirm {
                                match wait_for_confirmed_signature_via_sol(&sol, &sig, "create tx")
                                    .await
                                {
                                    Ok(()) => confirm_ok = Some(true),
                                    Err(err) => {
                                        confirm_ok = Some(false);
                                        send_error = Some(format!("{err:#}"));
                                    }
                                }
                            }

                            if send_error.is_none() && verify {
                                let verify_res: anyhow::Result<TokenInfo> = async {
                                    let mint_acc = sol
                                        .get_account(&mint_pubkey)
                                        .await
                                        .context("mint account not found after send")?;
                                    let expected_token_program =
                                        expected_mint_token_program_for_create(
                                            method,
                                            raydium_base_token_program,
                                            &response,
                                        )?;
                                    anyhow::ensure!(
                                        mint_acc.owner == expected_token_program,
                                        "mint owner mismatch: expected {} got {}",
                                        expected_token_program,
                                        mint_acc.owner
                                    );

                                    let info = sol
                                        .get_token_info(&mint_pubkey)
                                        .await
                                        .context("fetch on-chain token info")?;
                                    anyhow::ensure!(
                                        info.name == expected_name
                                            && info.symbol == expected_symbol
                                            && info.uri == expected_uri,
                                        "on-chain metadata mismatch: expected name={expected_name} symbol={expected_symbol} uri={expected_uri} | got name={} symbol={} uri={}",
	                                        info.name,
	                                        info.symbol,
	                                        info.uri
	                                    );

	                                    let mut missing: Vec<String> = Vec::new();
	                                    for (label, address) in response.derived_addresses.iter() {
                                        if method == CreateMethod::RaydiumLaunchpad
                                            && matches!(label.as_str(), "authority" | "event_authority")
                                        {
                                            // Raydium Launchpad uses authority/event_authority PDAs as address checks
                                            // and/or signers; they are not guaranteed to exist as funded accounts.
                                            continue;
                                        }
                                        if method == CreateMethod::PumpFun
                                            && matches!(label.as_str(), "bonding_curve_v2")
                                        {
                                            // Pump.fun requires `bonding_curve_v2` as a trailing remaining account for
                                            // buy/sell, but it's a PDA used for address checks and is not guaranteed
                                            // to exist as a funded on-chain account.
                                            continue;
                                        }
	                                        let pk = Pubkey::from_str(address.trim()).with_context(
                                            || {
                                                format!(
                                                    "invalid derived_addresses[{label}] pubkey: {address}"
                                                )
                                            },
                                        )?;
                                        if !sol.exists(&pk).await? {
                                            missing.push(label.clone());
                                        }
                                    }
                                    anyhow::ensure!(
                                        missing.is_empty(),
	                                        "on-chain verification failed (missing accounts): {}",
	                                        missing.join(", ")
	                                    );

	                                    Ok(info)
	                                }
	                                .await;

                                match verify_res {
                                    Ok(info) => {
                                        verify_ok = Some(true);
                                        onchain_token_info = Some(info);
                                    }
                                    Err(err) => {
                                        verify_ok = Some(false);
                                        send_error = Some(format!("{err:#}"));
                                    }
                                }
                            }
                        }
                        Err(err) => {
                            send_error = Some(format!("sendTransaction failed: {err:#}"));
                        }
                    }
                }
                Err(err) => {
                    send_error = Some(format!("{err:#}"));
                }
            }
        }
    }

    let rpc_url_redacted = http_url
        .map(str::trim)
        .filter(|v| !v.is_empty())
        .map(redact_url_for_artifact);

    let bundle = CreateArtifactBundle {
        timestamp_utc: timestamp.clone(),
        flow: "tui".to_string(),
        method: method.as_api_str().to_string(),
        payer: payer_pubkey.to_string(),
        mint: mint_pubkey.to_string(),
        expected_name,
        expected_symbol,
        expected_uri,
        api_base_url: Some(base.to_string()),
        rpc_url: rpc_url_redacted,
        request: Some(body),
        response: Some(response),
        signed_tx_b64: Some(signed_b64),
        signed_simulation: None,
        cluster: cluster.map(|v| format!("{v:?}")),
        send_requested: send,
        send_signature: send_sig.clone(),
        confirm_ok,
        verify_ok,
        onchain_token_info,
        metadata_upload,
        notes,
        error: send_error.clone(),
    };
    write_create_bundle(&bundle_path, &bundle)?;

    Ok(CreateFinished {
        out_dir: bundle_path,
        mint: mint_pubkey,
        method,
        cluster,
        server_sim_ok,
        signed_sim_ok: signed_simulation_ok,
        send_sig,
        confirm_ok,
        verify_ok,
        send_error,
    })
}

async fn build_create_pool_via_api_and_sign(
    market: Market,
    network: CreateNetwork,
    base_mint: Option<Pubkey>,
    quote_mint: Option<Pubkey>,
    base_amount: Option<String>,
    quote_amount: Option<String>,
    initial_price: Option<String>,
    pump_swap_index: Option<u16>,
    pump_swap_is_mayhem_mode: bool,
    raydium_cpmm_amm_config_index: Option<u16>,
    raydium_amm_v4_market: Option<Pubkey>,
    raydium_clmm_tick_spacing: Option<u16>,
    meteora_dlmm_bin_step: Option<u16>,
    meteora_dlmm_base_fee_bps: Option<u16>,
    meteora_damm_v1_trade_fee_bps: Option<u64>,
    meteora_damm_v2_config_index: Option<u64>,
    meteora_dbc_config_index: Option<u64>,
    meteora_dbc_name: Option<String>,
    meteora_dbc_symbol: Option<String>,
    meteora_dbc_uri: Option<String>,
    swqos_settings: Option<SWQoSettings>,
    base: &str,
    api_key: &str,
    payer: Arc<Keypair>,
    http_url: Option<&str>,
    send: bool,
    confirm: bool,
    verify: bool,
) -> anyhow::Result<CreatePoolFinished> {
    let (mut swqos_settings, initial_swqos_note) =
        swqos_settings_for_network(swqos_settings, network);
    let payer_pubkey = payer.pubkey();
    let mut dbc_mint_keypair: Option<Keypair> = None;
    let mut raydium_clmm_position_nft_mint: Option<Keypair> = None;
    let base_mint = match market {
        Market::MeteoraDbc => {
            let mint_keypair = Keypair::new();
            let mint_pubkey = mint_keypair.pubkey();
            dbc_mint_keypair = Some(mint_keypair);
            mint_pubkey
        }
        _ => base_mint.context("missing base_mint")?,
    };
    let rpc_url = http_url
        .map(str::trim)
        .filter(|v| !v.is_empty())
        .unwrap_or_else(|| network.default_http_url());
    let quote_mint_effective = quote_mint.unwrap_or(WSOL_MINT);

    let timestamp = chrono::Utc::now().format("%Y%m%dT%H%M%SZ").to_string();
    let out_dir = PathBuf::from("artifacts/create-pool");
    fs::create_dir_all(&out_dir)
        .with_context(|| format!("create-pool out dir {}", out_dir.display()))?;
    let bundle_path = create_pool_bundle_path(&out_dir, &timestamp, market.as_str(), &base_mint);
    let mut notes = Vec::new();
    if let Some(note) = initial_swqos_note {
        notes.push(note.to_string());
    }

    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(60))
        .build()
        .context("build http client")?;

    let mut body = json!({
        "market": market.as_str(),
        "payer": payer_pubkey.to_string(),
        "base_mint": base_mint.to_string(),
        "simulate": true,
        "rpc_url": rpc_url,
    });
    if quote_mint.is_some() {
        body["quote_mint"] = json!(quote_mint_effective.to_string());
    }
    if let Some(value) = base_amount
        .as_deref()
        .map(str::trim)
        .filter(|v| !v.is_empty())
    {
        body["base_amount"] = json!(value);
    }
    if let Some(value) = quote_amount
        .as_deref()
        .map(str::trim)
        .filter(|v| !v.is_empty())
    {
        body["quote_amount"] = json!(value);
    }
    if let Some(value) = initial_price
        .as_deref()
        .map(str::trim)
        .filter(|v| !v.is_empty())
    {
        body["initial_price"] = json!(value);
    }
    if let Some(value) = pump_swap_index {
        body["pump_swap_index"] = json!(value);
    }
    if pump_swap_is_mayhem_mode {
        body["pump_swap_is_mayhem_mode"] = json!(true);
    }
    if let Some(value) = raydium_cpmm_amm_config_index {
        body["raydium_cpmm_amm_config_index"] = json!(value);
    }
    if let Some(value) = raydium_amm_v4_market {
        body["raydium_amm_v4_market"] = json!(value.to_string());
    }
    if let Some(value) = raydium_clmm_tick_spacing {
        body["raydium_clmm_tick_spacing"] = json!(value);
    }
    let clmm_seed_requested = market == Market::RaydiumClmm
        && (base_amount
            .as_deref()
            .map(str::trim)
            .is_some_and(|v| !v.is_empty())
            || quote_amount
                .as_deref()
                .map(str::trim)
                .is_some_and(|v| !v.is_empty()));
    if clmm_seed_requested {
        let mint_keypair = Keypair::new();
        let mint_pubkey = mint_keypair.pubkey();
        body["raydium_clmm_position_nft_mint"] = json!(mint_pubkey.to_string());
        raydium_clmm_position_nft_mint = Some(mint_keypair);
    }
    if let Some(value) = meteora_dlmm_bin_step {
        body["meteora_dlmm_bin_step"] = json!(value);
    }
    if let Some(value) = meteora_dlmm_base_fee_bps {
        body["meteora_dlmm_base_fee_bps"] = json!(value);
    }
    if let Some(value) = meteora_damm_v1_trade_fee_bps {
        body["meteora_damm_v1_trade_fee_bps"] = json!(value);
    }
    if let Some(value) = meteora_damm_v2_config_index {
        body["meteora_damm_v2_config_index"] = json!(value);
    }
    if let Some(value) = meteora_dbc_config_index {
        body["meteora_dbc_config_index"] = json!(value);
    }
    if market == Market::MeteoraDbc {
        let name = meteora_dbc_name
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
            .context("missing meteora_dbc_name")?;
        let symbol = meteora_dbc_symbol
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
            .context("missing meteora_dbc_symbol")?;
        let uri = meteora_dbc_uri
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
            .context("missing meteora_dbc_uri")?;
        body["name"] = json!(name);
        body["symbol"] = json!(symbol);
        body["uri"] = json!(uri);
    }

    let mut damm_v2_position_nft_mint: Option<Keypair> = None;
    if market == Market::MeteoraDammV2 {
        let mint_keypair = Keypair::new();
        let mint_pubkey = mint_keypair.pubkey();
        body["meteora_damm_v2_position_nft_mint"] = json!(mint_pubkey.to_string());
        damm_v2_position_nft_mint = Some(mint_keypair);
    }
    apply_swqos_settings_to_build_body(&mut body, swqos_settings.as_ref());

    let url = format!("{base}/pool/build");
    let response: PoolBuildResponse = match http_json(
        client
            .post(url.clone())
            .header("x-api-key", api_key)
            .json(&body),
    )
    .await
    {
        Ok(response) => response,
        Err(err) if swqos_settings.is_some() => {
            if let Some(note) = swqos_build_retry_note(&err) {
                notes.push(note.to_string());
                swqos_settings = None;
                apply_swqos_settings_to_build_body(&mut body, None);
                http_json(client.post(url).header("x-api-key", api_key).json(&body)).await?
            } else {
                return Err(err);
            }
        }
        Err(err) => return Err(err),
    };

    let unsigned_wire = B64
        .decode(response.transaction.trim())
        .context("decode unsigned tx base64")?;
    let unsigned_tx: VersionedTransaction =
        bincode::deserialize(&unsigned_wire).context("deserialize unsigned tx")?;

    let required_signers: Vec<Pubkey> = response
        .required_signers
        .iter()
        .map(|s| Pubkey::from_str(s.trim()))
        .collect::<Result<Vec<_>, _>>()
        .context("parse required_signers")?;
    anyhow::ensure!(
        required_signers.contains(&payer_pubkey),
        "response.required_signers missing payer pubkey"
    );
    if market == Market::MeteoraDammV2 {
        let kp = damm_v2_position_nft_mint
            .as_ref()
            .context("missing meteora_damm_v2_position_nft_mint signer")?;
        anyhow::ensure!(
            required_signers.contains(&kp.pubkey()),
            "response.required_signers missing meteora_damm_v2_position_nft_mint pubkey"
        );
    }
    if market == Market::MeteoraDbc {
        let kp = dbc_mint_keypair
            .as_ref()
            .context("missing meteora_dbc base_mint signer")?;
        anyhow::ensure!(
            required_signers.contains(&kp.pubkey()),
            "response.required_signers missing meteora_dbc base_mint pubkey"
        );
    }
    if market == Market::RaydiumClmm && clmm_seed_requested {
        let kp = raydium_clmm_position_nft_mint
            .as_ref()
            .context("missing raydium_clmm position_nft_mint signer")?;
        anyhow::ensure!(
            required_signers.contains(&kp.pubkey()),
            "response.required_signers missing raydium_clmm_position_nft_mint pubkey"
        );
    }

    let mut unknown_signers: Vec<Pubkey> = Vec::new();
    for signer in required_signers.iter().copied() {
        if signer == payer_pubkey {
            continue;
        }
        let known = damm_v2_position_nft_mint
            .as_ref()
            .is_some_and(|kp| kp.pubkey() == signer)
            || dbc_mint_keypair
                .as_ref()
                .is_some_and(|kp| kp.pubkey() == signer);
        let known = known
            || raydium_clmm_position_nft_mint
                .as_ref()
                .is_some_and(|kp| kp.pubkey() == signer);
        if !known {
            unknown_signers.push(signer);
        }
    }
    anyhow::ensure!(
        unknown_signers.is_empty(),
        "pool builder returned unexpected extra required signers: {unknown_signers:?}"
    );

    let signed_tx = {
        let mut signer_refs: Vec<&dyn Signer> = vec![payer.as_ref()];
        if let Some(kp) = damm_v2_position_nft_mint.as_ref() {
            signer_refs.push(kp);
        }
        if let Some(kp) = dbc_mint_keypair.as_ref() {
            signer_refs.push(kp);
        }
        if let Some(kp) = raydium_clmm_position_nft_mint.as_ref() {
            signer_refs.push(kp);
        }
        VersionedTransaction::try_new(unsigned_tx.message.clone(), signer_refs.as_slice())
    }
    .context("sign transaction")?;
    let signed_wire = bincode::serialize(&signed_tx).context("serialize signed tx")?;
    let signed_b64 = B64.encode(signed_wire);

    let sol = SolHook::new(rpc_url.to_string());
    let cluster = detect_cluster_via_sol(&sol).await;
    let signed_simulation_ok = simulate_signed_transaction_ok(&sol, &signed_tx).await;

    let server_sim_ok = response.simulation.as_ref().map(|sim| sim.ok);

    let mut send_sig: Option<String> = None;
    let mut confirm_ok: Option<bool> = None;
    let mut verify_ok: Option<bool> = None;
    let mut send_error: Option<String> = None;

    let derived_pool = response
        .derived_addresses
        .get("pool")
        .or_else(|| response.derived_addresses.get("amm"))
        .or_else(|| response.derived_addresses.get("pool_state"))
        .or_else(|| response.derived_addresses.get("lb_pair"))
        .map(|v| v.trim().to_string())
        .filter(|v| !v.is_empty());
    let pool_pubkey = derived_pool
        .as_deref()
        .and_then(|raw| Pubkey::from_str(raw).ok());

    if send {
        if verify && !confirm {
            send_error = Some("verify requires confirm".to_string());
        } else if server_sim_ok.is_some_and(|ok| !ok) {
            send_error = Some("refusing to send: server simulation failed".to_string());
        } else if signed_simulation_ok.is_some_and(|ok| !ok) {
            send_error = Some("refusing to send: signed simulation failed".to_string());
        } else {
            let allow_mainnet_send = std::env::var("MAMBA_CLIENT_ALLOW_MAINNET_SEND")
                .ok()
                .is_some_and(|v| {
                    matches!(v.trim().to_ascii_lowercase().as_str(), "1" | "true" | "yes")
                });
            match network {
                CreateNetwork::Devnet => {
                    if cluster != Some(mamba::core::cluster::SolanaCluster::Devnet) {
                        send_error = Some(format!(
                            "refusing to send: rpc cluster mismatch (expected devnet got {:?})",
                            cluster
                        ));
                    }
                }
                CreateNetwork::Mainnet => {
                    if !allow_mainnet_send {
                        send_error = Some(
                            "send locked: mainnet (set MAMBA_CLIENT_ALLOW_MAINNET_SEND=true)"
                                .to_string(),
                        );
                    } else if cluster != Some(mamba::core::cluster::SolanaCluster::MainnetBeta) {
                        send_error = Some(format!(
                            "refusing to send: rpc cluster mismatch (expected mainnet got {:?})",
                            cluster
                        ));
                    }
                }
            }
        }

        if send_error.is_none() {
            let send_result = if let Some(settings) = swqos_settings.as_ref() {
                sol.submit_signed_via_swqos(&signed_tx, settings).await
            } else {
                send_signed_transaction_via_sol(&sol, &signed_tx).await
            };
            match send_result {
                Ok(sig) => {
                    send_sig = Some(sig.to_string());

                    if send_error.is_none() && confirm {
                        match wait_for_confirmed_signature_via_sol(&sol, &sig, "pool create tx")
                            .await
                        {
                            Ok(()) => confirm_ok = Some(true),
                            Err(err) => {
                                confirm_ok = Some(false);
                                send_error = Some(format!("{err:#}"));
                            }
                        }
                    }

                    if send_error.is_none() && verify {
                        let verify_res: anyhow::Result<()> = async {
                            let mut missing: Vec<String> = Vec::new();
                            for (label, address) in response.derived_addresses.iter() {
                                if label.to_ascii_lowercase().contains("authority") {
                                    continue;
                                }
                                let pk = Pubkey::from_str(address.trim()).with_context(|| {
                                    format!("invalid derived_addresses[{label}] pubkey: {address}")
                                })?;
                                if !sol.exists(&pk).await? {
                                    missing.push(label.clone());
                                }
                            }
                            anyhow::ensure!(
                                missing.is_empty(),
                                "on-chain verification failed (missing accounts): {}",
                                missing.join(", ")
                            );
                            Ok(())
                        }
                        .await;

                        match verify_res {
                            Ok(()) => {
                                verify_ok = Some(true);
                            }
                            Err(err) => {
                                verify_ok = Some(false);
                                send_error = Some(format!("{err:#}"));
                            }
                        }
                    }
                }
                Err(err) => {
                    send_error = Some(format!("sendTransaction failed: {err:#}"));
                }
            }
        }
    }

    let rpc_url_redacted = Some(redact_url_for_artifact(rpc_url));

    let bundle = CreatePoolArtifactBundle {
        timestamp_utc: timestamp.clone(),
        flow: "tui".to_string(),
        market: market.as_str().to_string(),
        payer: payer_pubkey.to_string(),
        base_mint: base_mint.to_string(),
        quote_mint: quote_mint_effective.to_string(),
        api_base_url: Some(base.to_string()),
        rpc_url: rpc_url_redacted,
        request: Some(body),
        response: Some(response),
        signed_tx_b64: Some(signed_b64),
        signed_sim_ok: signed_simulation_ok,
        cluster: cluster.map(|v| format!("{v:?}")),
        send_requested: send,
        send_signature: send_sig.clone(),
        confirm_ok,
        verify_ok,
        derived_pool: derived_pool.clone(),
        notes,
        error: send_error.clone(),
    };
    write_create_pool_bundle(&bundle_path, &bundle)?;

    Ok(CreatePoolFinished {
        out_dir: bundle_path,
        market,
        base_mint,
        quote_mint: quote_mint_effective,
        pool: pool_pubkey,
        cluster,
        server_sim_ok,
        signed_sim_ok: signed_simulation_ok,
        send_sig,
        confirm_ok,
        verify_ok,
        send_error,
    })
}

trait WalletBatchFinished {
    fn failure_detail(&self) -> Option<&str>;
}

impl WalletBatchFinished for CreateFinished {
    fn failure_detail(&self) -> Option<&str> {
        self.send_error
            .as_deref()
            .filter(|value| !value.trim().is_empty())
    }
}

impl WalletBatchFinished for CreatePoolFinished {
    fn failure_detail(&self) -> Option<&str> {
        self.send_error
            .as_deref()
            .filter(|value| !value.trim().is_empty())
    }
}

impl WalletBatchFinished for WalletCleanFinished {
    fn failure_detail(&self) -> Option<&str> {
        self.send_error
            .as_deref()
            .filter(|value| !value.trim().is_empty())
    }
}

fn wallet_outcome_error<T: WalletBatchFinished>(
    outcome: &WalletActionOutcome<T>,
) -> Option<String> {
    outcome.error.clone().or_else(|| {
        outcome
            .finished
            .as_ref()
            .and_then(|finished| finished.failure_detail().map(str::to_string))
    })
}

fn batch_outcome_lines<T: WalletBatchFinished>(outcomes: &[WalletActionOutcome<T>]) -> Vec<String> {
    outcomes
        .iter()
        .map(|outcome| {
            if let Some(error) = wallet_outcome_error(outcome) {
                format!(
                    "{} ({}) FAIL {}",
                    outcome.wallet_label,
                    short_pubkey(&outcome.wallet_pubkey),
                    truncate(&error, 100)
                )
            } else {
                format!(
                    "{} ({}) OK",
                    outcome.wallet_label,
                    short_pubkey(&outcome.wallet_pubkey)
                )
            }
        })
        .collect()
}

fn batch_outcome_counts<T: WalletBatchFinished>(
    outcomes: &[WalletActionOutcome<T>],
) -> (usize, usize) {
    let ok = outcomes
        .iter()
        .filter(|outcome| wallet_outcome_error(outcome).is_none())
        .count();
    (ok, outcomes.len())
}

fn batch_first_error<T: WalletBatchFinished>(
    outcomes: &[WalletActionOutcome<T>],
) -> Option<String> {
    outcomes.iter().find_map(wallet_outcome_error)
}

fn batch_representative_finished<T: WalletBatchFinished + Clone>(
    outcomes: &[WalletActionOutcome<T>],
) -> Option<T> {
    outcomes
        .iter()
        .filter(|outcome| wallet_outcome_error(outcome).is_none())
        .find_map(|outcome| outcome.finished.clone())
        .or_else(|| outcomes.iter().find_map(|outcome| outcome.finished.clone()))
}

fn spawn_create_build_batch(
    wallets: Vec<WalletActionTarget>,
    method: CreateMethod,
    name: String,
    symbol: String,
    uri: String,
    raydium_launchpad: Option<serde_json::Value>,
    raydium_base_token_program: Option<RaydiumBaseTokenProgram>,
    auto_buy: Option<CreateAutoBuyParams>,
    description: Option<String>,
    image_path: Option<PathBuf>,
    twitter: Option<String>,
    telegram: Option<String>,
    website: Option<String>,
    show_name: bool,
    ipfs_upload_url: Option<String>,
    decimals: Option<u8>,
    swqos_settings: Option<SWQoSettings>,
    base: String,
    api_key: String,
    http_url: Option<String>,
    send: bool,
    confirm: bool,
    verify: bool,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let mut outcomes = Vec::new();
        for wallet in wallets {
            let result = build_create_via_api_and_sign(
                method,
                name.clone(),
                symbol.clone(),
                uri.clone(),
                raydium_launchpad.clone(),
                raydium_base_token_program,
                auto_buy,
                description.clone(),
                image_path.clone(),
                twitter.clone(),
                telegram.clone(),
                website.clone(),
                show_name,
                ipfs_upload_url.clone(),
                decimals,
                swqos_settings.clone(),
                &base,
                &api_key,
                wallet.signer.clone(),
                http_url.as_deref(),
                send,
                confirm,
                verify,
            )
            .await;
            match result {
                Ok(finished) => outcomes.push(WalletActionOutcome {
                    wallet_pubkey: wallet.pubkey,
                    wallet_label: wallet.label,
                    finished: Some(finished),
                    error: None,
                }),
                Err(error) => outcomes.push(WalletActionOutcome {
                    wallet_pubkey: wallet.pubkey,
                    wallet_label: wallet.label,
                    finished: None,
                    error: Some(format!("{error:#}")),
                }),
            }
        }
        let _ = tx.send(AppMsg::CreateBatchFinished(outcomes)).await;
    });
}

