fn build_mamba_api_url(base: &str, path: &str) -> anyhow::Result<reqwest::Url> {
    let base = base.trim_end_matches('/');
    let path = path.trim_start_matches('/');
    let url = format!("{base}/{path}");
    reqwest::Url::parse(&url).with_context(|| format!("invalid url: {url}"))
}

const HTTP_TRADE_LOOKUP_TIMEOUT_BUFFER_SECS: u64 = 5;
const HTTP_TRADE_EXEC_TIMEOUT_BUFFER_SECS: u64 = 10;

fn http_trade_lookup_request_timeout_duration() -> Duration {
    Swaps::route_lookup_timeout_duration(Some(&HTTP_TRADE_MARKETS))
        .saturating_add(Swaps::price_lookup_timeout_duration())
        .saturating_add(Duration::from_secs(HTTP_TRADE_LOOKUP_TIMEOUT_BUFFER_SECS))
}

fn http_trade_exec_request_timeout_duration() -> Duration {
    Swaps::price_lookup_timeout_duration()
        .saturating_add(SolHook::send_confirm_timeout_duration())
        .saturating_add(Duration::from_secs(HTTP_TRADE_EXEC_TIMEOUT_BUFFER_SECS))
}

fn rewrite_http_timeout_error(
    error: anyhow::Error,
    label: &str,
    timeout: Duration,
) -> anyhow::Error {
    for cause in error.chain() {
        if let Some(reqwest_error) = cause.downcast_ref::<reqwest::Error>()
            && reqwest_error.is_timeout()
        {
            return anyhow::anyhow!(
                "{label} timed out after {}s while waiting for mamba_api",
                timeout.as_secs()
            );
        }
    }
    error
}

fn spawn_raydium_launchpad_global_configs_fetch(
    base: String,
    api_key: String,
    network: CreateNetwork,
    rpc_url: String,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let res = async {
            let client = reqwest::Client::builder()
                .timeout(Duration::from_secs(20))
                .build()
                .context("build http client")?;
            let mut url = build_mamba_api_url(&base, "create/raydium_launchpad/global-configs")?;
            url.query_pairs_mut().append_pair("rpc_url", &rpc_url);
            let out: Vec<RaydiumLaunchpadGlobalConfigResponse> =
                http_json(client.get(url).header("x-api-key", api_key)).await?;
            Ok::<_, anyhow::Error>(out)
        }
        .await;

        match res {
            Ok(configs) => {
                let _ = tx
                    .send(AppMsg::RaydiumLaunchpadGlobalConfigs { network, configs })
                    .await;
            }
            Err(error) => {
                let _ = tx
                    .send(AppMsg::RaydiumLaunchpadGlobalConfigsError {
                        network,
                        error: format!("{error:#}"),
                    })
                    .await;
            }
        }
    });
}

