fn latest_trade_route_for_market_mint(
    app: &AppState,
    market: Market,
    mint: Pubkey,
) -> Option<MintPoolRoute> {
    app.route_last.as_ref().and_then(|snapshot| {
        if snapshot.mint != mint {
            return None;
        }
        snapshot.route.filter(|route| route.market == market)
    })
}

async fn execute_live_trade_for_wallet(
    side: TradeSide,
    market: Market,
    explicit_route: Option<MintPoolRoute>,
    mint: Pubkey,
    buy_sol: f64,
    sell_pct: u64,
    slippage_pct: f64,
    retries: u32,
    priority_fee_override: Option<PriorityFeeOverride>,
    swqos_settings: Option<SWQoSettings>,
    rpc: Arc<RpcClient>,
    cluster: mamba::core::cluster::SolanaCluster,
    signer: Arc<Keypair>,
    wallet_pubkey: Pubkey,
    wallet_label: String,
) -> TradeExecUpdate {
    let sol_hook = SolHook::from_rpc_client_with_cluster(rpc, cluster);
    let sol = Arc::new(sol_hook.clone());
    let pump_fun = PumpFun::new(signer.clone(), sol.clone());
    let pump_swap = PumpSwap::new(signer, sol.clone());
    let swaps = Swaps::new(sol_hook, pump_swap, pump_fun);

    let mint_text = mint.to_string();
    let quote_text = WSOL_MINT.to_string();
    let market_priority = [market];
    let explicit_route = if let Some(route) = explicit_route {
        if route.creator == Pubkey::default() {
            match swaps
                .get_route_creator_for_market_pool(&mint, route.market, &route.pool)
                .await
            {
                Ok(resolved) if resolved.creator != Pubkey::default() => Some(MintPoolRoute {
                    creator: resolved.creator,
                    ..route
                }),
                _ => Some(route),
            }
        } else {
            Some(route)
        }
    } else {
        None
    };

    let mut success = false;
    let mut signature: Option<String> = None;
    let mut price_sol: Option<f64> = None;
    let mut error: Option<String> = None;

    match side {
        TradeSide::Buy => {
            let buy_sol = buy_sol.max(0.0);
            if buy_sol <= 0.0 {
                error = Some("buy_sol must be > 0".to_string());
            } else {
                let mut backoff = Duration::from_millis(250);
                for attempt in 0..=retries {
                    let result = if let Some(route) = explicit_route {
                        match swaps
                            .fetch_price_for_market_pool(route.market, &route.pool)
                            .await
                        {
                            Ok(price) => swaps
                                .buy_with_priority_fee_override(
                                    &mint_text,
                                    &route.pool.to_string(),
                                    &route.creator.to_string(),
                                    buy_sol,
                                    slippage_pct,
                                    price,
                                    Some(true),
                                    route.market,
                                    priority_fee_override,
                                    swqos_settings.is_some(),
                                    swqos_settings.clone(),
                                )
                                .await
                                .map(|execution| (execution, route, price)),
                            Err(error) => Err(error),
                        }
                    } else {
                        swaps
                            .buy_by_mint_with_priority_fee_override(
                                &mint_text,
                                Some(&quote_text),
                                0,
                                buy_sol,
                                slippage_pct,
                                Some(true),
                                Some(&market_priority),
                                priority_fee_override,
                                swqos_settings.is_some(),
                                swqos_settings.clone(),
                            )
                            .await
                    };
                    match result {
                        Ok((execution, _route, price)) => {
                            price_sol = Some(price);
                            success = execution.success;
                            signature = execution.signature.map(|sig| sig.to_string());
                            error = execution.error;
                            let retryable = error
                                .as_deref()
                                .map(trade_exec_error_is_retryable)
                                .unwrap_or(true);
                            if success || !retryable || attempt >= retries {
                                break;
                            }
                        }
                        Err(err) => {
                            error = Some(format!("{err:#}"));
                            break;
                        }
                    }

                    tokio::time::sleep(backoff).await;
                    backoff = (backoff * 2).min(Duration::from_secs(3));
                }

                if !success && error.is_none() {
                    error = Some(format!(
                        "buy tx failed after {} attempt(s)",
                        retries.saturating_add(1)
                    ));
                }
            }
        }
        TradeSide::Sell => {
            let sell_pct = sell_pct.clamp(1, 100);
            let result = if let Some(route) = explicit_route {
                match swaps
                    .fetch_price_for_market_pool(route.market, &route.pool)
                    .await
                {
                    Ok(price) => swaps
                        .sell_with_priority_fee_override(
                            &mint_text,
                            &route.pool.to_string(),
                            &route.creator.to_string(),
                            sell_pct,
                            slippage_pct,
                            price,
                            route.market,
                            retries,
                            priority_fee_override,
                            swqos_settings.is_some(),
                            swqos_settings.clone(),
                        )
                        .await
                        .map(|execution| (execution, route, price)),
                    Err(error) => Err(error),
                }
            } else {
                swaps
                    .sell_by_mint_with_priority_fee_override(
                        &mint_text,
                        Some(&quote_text),
                        0,
                        sell_pct,
                        slippage_pct,
                        Some(&market_priority),
                        retries,
                        priority_fee_override,
                        swqos_settings.is_some(),
                        swqos_settings.clone(),
                    )
                    .await
            };
            match result {
                Ok((execution, _route, price)) => {
                    price_sol = Some(price);
                    success = execution.success;
                    signature = execution.signature.map(|sig| sig.to_string());
                    error = execution.error;
                }
                Err(err) => error = Some(format!("{err:#}")),
            }
        }
    }

    finalize_trade_exec_diagnostics(market, &mut signature, &mut error);

    TradeExecUpdate {
        wallet_pubkey,
        wallet_label,
        market,
        mint,
        resolved_route: None,
        network: Some(match cluster {
            mamba::core::cluster::SolanaCluster::Devnet => CreateNetwork::Devnet,
            mamba::core::cluster::SolanaCluster::MainnetBeta => CreateNetwork::Mainnet,
            _ => CreateNetwork::Devnet,
        }),
        side,
        success,
        signature,
        price_sol,
        send_requested: true,
        requested_sell_pct: (side == TradeSide::Sell).then_some(sell_pct),
        error,
        warning: None,
    }
}

fn spawn_trade_exec_batch(
    wallets: Vec<WalletActionTarget>,
    side: TradeSide,
    market: Market,
    explicit_route: Option<MintPoolRoute>,
    mint: Pubkey,
    buy_sol: f64,
    sell_pct: u64,
    slippage_pct: f64,
    retries: u32,
    priority_fee_override: Option<PriorityFeeOverride>,
    swqos_settings: Option<SWQoSettings>,
    rpc: Arc<RpcClient>,
    cluster: mamba::core::cluster::SolanaCluster,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let mut updates = Vec::new();
        for wallet in wallets {
            updates.push(
                execute_live_trade_for_wallet(
                    side,
                    market,
                    explicit_route,
                    mint,
                    buy_sol,
                    sell_pct,
                    slippage_pct,
                    retries,
                    priority_fee_override,
                    swqos_settings.clone(),
                    rpc.clone(),
                    cluster,
                    wallet.signer,
                    wallet.pubkey,
                    wallet.label,
                )
                .await,
            );
        }
        let _ = tx.send(AppMsg::TradeExecBatch(updates)).await;
    });
}

fn spawn_trade_liquidity_fetch(
    market: Market,
    mint: Pubkey,
    pool: Pubkey,
    sol: Arc<SolHook>,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let keypair = Arc::new(Keypair::new());
        let mut liquidity_sol: Option<f64> = None;
        let mut error: Option<String> = None;

        let res: anyhow::Result<Option<f64>> = async {
            let raw = match market {
                Market::PumpFun => {
                    let pump_fun = PumpFun::new(keypair.clone(), sol.clone());
                    let state = pump_fun.fetch_state(&pool).await?;
                    Some((state.real_sol_reserves as f64) / 1e9)
                }
                Market::PumpSwap => {
                    let pump_swap = PumpSwap::new(keypair.clone(), sol.clone());
                    let state = pump_swap.fetch_state(&pool).await?;
                    let raw = pump_swap.fetch_wsol_liquidity_raw(&state).await?;
                    Some((raw as f64) / 1e9)
                }
                Market::RaydiumAmmV4 => {
                    let raydium = RaydiumAmmV4::new(keypair.clone(), sol.clone());
                    let state = raydium.fetch_state(&pool).await?;
                    let raw = raydium.fetch_wsol_liquidity_raw(&state).await?;
                    Some((raw as f64) / 1e9)
                }
                Market::RaydiumLaunchpad => {
                    let raydium = RaydiumLaunchpad::new(keypair.clone(), sol.clone());
                    let state = raydium.fetch_state(&pool).await?;
                    let raw = raydium.fetch_wsol_liquidity_raw(&state).await?;
                    Some((raw as f64) / 1e9)
                }
                Market::RaydiumClmm => {
                    let raydium = RaydiumClmm::new(keypair.clone(), sol.clone());
                    let state = raydium.fetch_state(&pool).await?;
                    let wsol_vault = if state.mint_a == WSOL_MINT {
                        state.vault_a
                    } else if state.mint_b == WSOL_MINT {
                        state.vault_b
                    } else {
                        anyhow::bail!("raydium clmm pool is not WSOL-quoted");
                    };

                    let account = sol
                        .get_account(&wsol_vault)
                        .await
                        .context("wsol vault account not found")?;
                    let (_, _, amount_raw) = parse_token_account_owner_and_amount(&account)
                        .context("failed to parse wsol vault token account")?;
                    Some((amount_raw as f64) / 1e9)
                }
                Market::RaydiumCpmm => {
                    let raydium = RaydiumCpmm::new(keypair.clone(), sol.clone());
                    let state = raydium.fetch_state(&pool).await?;
                    let raw = raydium.fetch_wsol_liquidity_raw(&state).await?;
                    Some((raw as f64) / 1e9)
                }
                Market::MeteoraDlmm => {
                    let meteora = MeteoraDlmm::new(keypair.clone(), sol.clone());
                    let state = meteora.fetch_state(&pool).await?;
                    let raw = meteora.fetch_wsol_liquidity_raw(&state).await?;
                    Some((raw as f64) / 1e9)
                }
                Market::MeteoraDammV1 => {
                    let meteora = MeteoraDammV1::new(keypair.clone(), sol.clone());
                    let state = meteora.fetch_state(&pool).await?;
                    let raw = meteora.fetch_wsol_liquidity_raw(&state).await?;
                    Some((raw as f64) / 1e9)
                }
                Market::MeteoraDammV2 => {
                    let meteora = MeteoraDammV2::new(keypair.clone(), sol.clone());
                    let state = meteora.fetch_state(&pool).await?;
                    let raw = meteora.fetch_wsol_liquidity_raw(&state).await?;
                    Some((raw as f64) / 1e9)
                }
                Market::MeteoraDbc => {
                    let meteora = MeteoraDbc::new(keypair.clone(), sol.clone());
                    let state = meteora.fetch_state(&pool).await?;
                    let raw = meteora.fetch_wsol_liquidity_raw(&state).await?;
                    Some((raw as f64) / 1e9)
                }
            };
            Ok(raw)
        }
        .await;

        match res {
            Ok(value) => liquidity_sol = value,
            Err(err) => error = Some(format!("{err:#}")),
        }

        let _ = tx
            .send(AppMsg::TradeLiquidity(TradeLiquiditySnapshot {
                market,
                mint,
                pool,
                fetched_unix_ms: now_unix_ms(),
                wsol_liquidity_sol: liquidity_sol,
                error,
            }))
            .await;
    });
}

fn spawn_mamba_api_bootstrap(
    tx: mpsc::Sender<AppMsg>,
    api_base_url_override: Option<String>,
    api_key_override: Option<String>,
) {
    tokio::spawn(async move {
        let base = match require_api_base_url(api_base_url_override) {
            Ok(base) => base,
            Err(err) => {
                let _ = tx
                    .send(AppMsg::BootstrapFinished {
                        api_child: None,
                        error: Some(format!("{err:#}")),
                    })
                    .await;
                return;
            }
        };

        let api_key = match require_api_key(api_key_override) {
            Ok(key) => key,
            Err(err) => {
                let _ = tx
                    .send(AppMsg::BootstrapFinished {
                        api_child: None,
                        error: Some(format!("{err:#}")),
                    })
                    .await;
                return;
            }
        };

        let keep_running = env_truthy("MAMBA_CLIENT_KEEP_API_RUNNING");
        let outcome = ensure_mamba_api_up(&base, &api_key, keep_running, |line| {
            let _ = tx.try_send(AppMsg::BootstrapLine(line));
        })
        .await;

        match outcome {
            Ok(ok) => {
                if ok.api_child.is_none() {
                    let _ = tx.try_send(AppMsg::BootstrapLine("mamba_api is up".to_string()));
                }
                if let Some(path) = ok.log_path {
                    let _ = tx.try_send(AppMsg::BootstrapLogPath(path));
                }
                let _ = tx
                    .send(AppMsg::BootstrapFinished {
                        api_child: ok.api_child,
                        error: None,
                    })
                    .await;
            }
            Err(err) => {
                if let Some(path) = err.log_path {
                    let _ = tx.try_send(AppMsg::BootstrapLogPath(path));
                }
                let _ = tx
                    .send(AppMsg::BootstrapFinished {
                        api_child: err.api_child,
                        error: Some(err.error),
                    })
                    .await;
            }
        }
    });
}

fn print_holders_snapshot(snapshot: &HoldersSnapshot) {
    println!("holders: mint={}", snapshot.mint);
    if let Some(supply) = snapshot.supply.as_ref() {
        let supply_ui = supply.real_number_string_trimmed();
        let covered = snapshot
            .covered_supply_pct
            .map(|v| format!("{v:.3}%"))
            .unwrap_or_else(|| "-".to_string());
        println!(
            "supply={} decimals={} covered_top={}",
            supply_ui, supply.decimals, covered
        );
    } else {
        println!("supply=unknown");
    }
    println!(
        "{:<5} {:<45} {:>18} {:>12} {:>9}",
        "rank", "owner", "amount", "%supply", "accounts"
    );
    for (idx, row) in snapshot.rows.iter().enumerate() {
        let pct = row
            .pct_supply
            .map(|v| format!("{v:.4}%"))
            .unwrap_or_else(|| "-".to_string());
        println!(
            "{:<5} {:<45} {:>18.6} {:>12} {:>9}",
            idx + 1,
            row.owner,
            row.amount,
            pct,
            row.token_accounts
        );
    }
}

fn program_id_for_market(market: Market) -> Pubkey {
    match market {
        Market::PumpSwap => PUMP_SWAP_ID,
        Market::PumpFun => PUMP_FUN_ID,
        Market::RaydiumAmmV4 => RAYDIUM_AMM_V4_ID,
        Market::RaydiumLaunchpad => RAYDIUM_LAUNCHPAD_ID,
        Market::RaydiumClmm => RAYDIUM_CLMM_ID,
        Market::RaydiumCpmm => RAYDIUM_CPMM_ID,
        Market::MeteoraDlmm => METEORA_DLMM_ID,
        Market::MeteoraDammV1 => METEORA_DAMM_V1_ID,
        Market::MeteoraDammV2 => METEORA_DAMM_V2_ID,
        Market::MeteoraDbc => METEORA_DBC_ID,
    }
}

fn parse_logs_to_events(
    market: Market,
    signature: &str,
    logs: &[String],
    observed_unix_ms: u64,
    observed_unix_secs: f64,
) -> Vec<ObservedEvent> {
    let mut out = Vec::new();

    match market {
        Market::PumpFun => {
            for event in PumpFun::parse_logs(logs.iter(), None) {
                match event {
                    PumpFunEvent::Create(Some(create)) => {
                        let delay = pump_fun_delay_secs(observed_unix_secs, create.timestamp);
                        let mint = Pubkey::from(create.mint.to_bytes());
                        let bonding_curve = Pubkey::from(create.bonding_curve.to_bytes());
                        let mut summary =
                            format!("CREATE {} ({}) mint={}", create.symbol, create.name, mint);
                        if let Some(delay) = delay {
                            summary.push_str(&format!(" delay={:.3}s", delay));
                        }
                        out.push(ObservedEvent {
                            kind: EventKind::Mint,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary,
                            pump_fun_delay_secs: delay,
                            mint: Some(mint),
                            pool: Some(bonding_curve),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        });
                    }
                    PumpFunEvent::Trade(Some(trade)) => {
                        let side = if trade.is_buy { "BUY" } else { "SELL" };
                        let trade_side = if trade.is_buy {
                            TradeSide::Buy
                        } else {
                            TradeSide::Sell
                        };
                        let mint = Pubkey::from(trade.mint.to_bytes());
                        let sol_amount = (trade.sol_amount as f64) / 1e9;
                        let token_amount = (trade.token_amount as f64) / 1e6;
                        out.push(ObservedEvent {
                            kind: EventKind::Swap,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "{} mint={} sol={:.6} tok={:.6}",
                                side, mint, sol_amount, token_amount
                            ),
                            pump_fun_delay_secs: None,
                            mint: Some(mint),
                            pool: None,
                            side: Some(trade_side),
                            sol_amount: Some(sol_amount),
                            token_amount: Some(token_amount),
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        });
                    }
                    _ => {}
                }
            }
        }
        Market::PumpSwap => {
            for event in PumpSwap::parse_logs(logs.iter(), None) {
                match event {
                    PumpSwapEvent::CreatePool(Some(create)) => {
                        let base_mint = Pubkey::from(create.base_mint.to_bytes());
                        let quote_mint = Pubkey::from(create.quote_mint.to_bytes());
                        let pool = Pubkey::from(create.pool.to_bytes());
                        let token_mint = if base_mint == WSOL_MINT && quote_mint != WSOL_MINT {
                            Some(quote_mint)
                        } else if quote_mint == WSOL_MINT && base_mint != WSOL_MINT {
                            Some(base_mint)
                        } else {
                            None
                        };
                        let meta = PumpSwapPoolMeta {
                            base_mint,
                            quote_mint,
                            base_decimals: create.base_mint_decimals,
                            quote_decimals: create.quote_mint_decimals,
                        };
                        out.push(ObservedEvent {
                            kind: EventKind::Mint,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "CREATE_POOL pool={} base={} quote={}",
                                pool, base_mint, quote_mint
                            ),
                            pump_fun_delay_secs: None,
                            mint: token_mint,
                            pool: Some(pool),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: Some(meta),
                        })
                    }
                    PumpSwapEvent::Buy(Some(buy)) => {
                        let pool = Pubkey::from(buy.pool.to_bytes());
                        out.push(ObservedEvent {
                            kind: EventKind::Swap,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "BUY pool={} (pending pool meta)",
                                short_pubkey(&pool)
                            ),
                            pump_fun_delay_secs: None,
                            mint: None,
                            pool: Some(pool),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: Some(PumpSwapTradeKind::Buy),
                            pump_swap_base_amount_raw: Some(buy.base_amount_out),
                            pump_swap_quote_amount_raw: Some(buy.quote_amount_in),
                            pump_swap_pool_meta: None,
                        })
                    }
                    PumpSwapEvent::Sell(Some(sell)) => {
                        let pool = Pubkey::from(sell.pool.to_bytes());
                        out.push(ObservedEvent {
                            kind: EventKind::Swap,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "SELL pool={} (pending pool meta)",
                                short_pubkey(&pool)
                            ),
                            pump_fun_delay_secs: None,
                            mint: None,
                            pool: Some(pool),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: Some(PumpSwapTradeKind::Sell),
                            pump_swap_base_amount_raw: Some(sell.base_amount_in),
                            pump_swap_quote_amount_raw: Some(sell.quote_amount_out),
                            pump_swap_pool_meta: None,
                        })
                    }
                    _ => {}
                }
            }
        }
        Market::RaydiumLaunchpad => {
            for event in RaydiumLaunchpad::parse_logs(logs.iter(), None) {
                match event {
                    RaydiumLaunchpadEvent::PoolCreate(Some(create)) => out.push(ObservedEvent {
                        kind: EventKind::Mint,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!(
                            "POOL_CREATE pool={} config={}",
                            create.pool_state, create.config
                        ),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: Some(create.pool_state),
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: None,
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }),
                    RaydiumLaunchpadEvent::Trade(Some(trade)) => {
                        let side = match trade.trade_direction {
                            0 => "BUY",
                            1 => "SELL",
                            _ => "TRADE",
                        };
                        let trade_side = match trade.trade_direction {
                            0 => Some(TradeSide::Buy),
                            1 => Some(TradeSide::Sell),
                            _ => None,
                        };
                        let sol_amount = match trade_side {
                            Some(TradeSide::Buy) => Some((trade.amount_in as f64) / 1e9),
                            Some(TradeSide::Sell) => Some((trade.amount_out as f64) / 1e9),
                            None => None,
                        };
                        out.push(ObservedEvent {
                            kind: EventKind::Swap,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "{} pool={} in={:.6} out={:.6} status={}",
                                side,
                                trade.pool_state,
                                (trade.amount_in as f64) / 1e9,
                                (trade.amount_out as f64) / 1e9,
                                trade.pool_status
                            ),
                            pump_fun_delay_secs: None,
                            mint: None,
                            pool: Some(trade.pool_state),
                            side: trade_side,
                            sol_amount,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        });
                    }
                    _ => {}
                }
            }
        }
        Market::RaydiumClmm => {
            for event in RaydiumClmm::parse_logs(logs.iter(), None) {
                match event {
                    RaydiumClmmEvent::PoolCreated(Some(pool)) => {
                        let token_mint = if pool.token_mint_0 == WSOL_MINT
                            && pool.token_mint_1 != WSOL_MINT
                        {
                            Some(pool.token_mint_1)
                        } else if pool.token_mint_1 == WSOL_MINT && pool.token_mint_0 != WSOL_MINT {
                            Some(pool.token_mint_0)
                        } else {
                            None
                        };
                        out.push(ObservedEvent {
                            kind: EventKind::Mint,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "POOL_CREATED pool={} m0={} m1={}",
                                pool.pool_state, pool.token_mint_0, pool.token_mint_1
                            ),
                            pump_fun_delay_secs: None,
                            mint: token_mint,
                            pool: Some(pool.pool_state),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        })
                    }
                    RaydiumClmmEvent::Swap(Some(swap)) => out.push(ObservedEvent {
                        kind: EventKind::Swap,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!(
                            "SWAP pool={} a0={} a1={} zf1={}",
                            swap.pool_state, swap.amount_0, swap.amount_1, swap.zero_for_one
                        ),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: Some(swap.pool_state),
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: Some(SwapDetail::RaydiumClmm {
                            amount_0: swap.amount_0,
                            amount_1: swap.amount_1,
                            zero_for_one: swap.zero_for_one,
                        }),
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }),
                    _ => {}
                }
            }
        }
        Market::RaydiumCpmm => {
            for event in RaydiumCpmm::parse_logs(logs.iter(), None) {
                if let RaydiumCpmmEvent::Swap(Some(swap)) = event {
                    let (token_mint, side, sol_amount) =
                        if swap.input_mint == WSOL_MINT && swap.output_mint != WSOL_MINT {
                            (
                                Some(swap.output_mint),
                                Some(TradeSide::Buy),
                                Some((swap.input_amount as f64) / 1e9),
                            )
                        } else if swap.output_mint == WSOL_MINT && swap.input_mint != WSOL_MINT {
                            (
                                Some(swap.input_mint),
                                Some(TradeSide::Sell),
                                Some((swap.output_amount as f64) / 1e9),
                            )
                        } else {
                            (None, None, None)
                        };
                    out.push(ObservedEvent {
                        kind: EventKind::Swap,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!(
                            "SWAP pool={} in={} ({}) out={} ({})",
                            swap.pool_id,
                            swap.input_amount,
                            swap.input_mint,
                            swap.output_amount,
                            swap.output_mint
                        ),
                        pump_fun_delay_secs: None,
                        mint: token_mint,
                        pool: Some(swap.pool_id),
                        side,
                        sol_amount,
                        token_amount: None,
                        swap_detail: None,
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    });
                }
            }
        }
        Market::RaydiumAmmV4 => {
            for event in RaydiumAmmV4::parse_logs(logs.iter(), None) {
                match event {
                    RaydiumAmmV4Event::SwapBaseIn(Some(swap)) => out.push(ObservedEvent {
                        kind: EventKind::Swap,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!(
                            "SWAP_IN in={} min_out={} dir={}",
                            swap.amount_in, swap.minimum_out, swap.direction
                        ),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: Some(SwapDetail::RaydiumAmmV4BaseIn {
                            amount_in: swap.amount_in,
                            out_amount: swap.out_amount,
                        }),
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }),
                    RaydiumAmmV4Event::SwapBaseOut(Some(swap)) => out.push(ObservedEvent {
                        kind: EventKind::Swap,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!(
                            "SWAP_OUT max_in={} out={} dir={}",
                            swap.max_in, swap.amount_out, swap.direction
                        ),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: Some(SwapDetail::RaydiumAmmV4BaseOut {
                            deduct_in: swap.deduct_in,
                            amount_out: swap.amount_out,
                        }),
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }),
                    _ => {}
                }
            }
        }
        Market::MeteoraDlmm => {
            for event in MeteoraDlmm::parse_logs(logs.iter(), None) {
                match event {
                    MeteoraDlmmEvent::LbPairCreate(Some(create)) => out.push(ObservedEvent {
                        kind: EventKind::Mint,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!("LB_PAIR_CREATE bytes={}", create.raw_data.len()),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: None,
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }),
                    MeteoraDlmmEvent::Swap(Some(swap)) => out.push(ObservedEvent {
                        kind: EventKind::Swap,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!("SWAP bytes={}", swap.raw_data.len()),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: None,
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }),
                    _ => {}
                }
            }
        }
        Market::MeteoraDammV1 => {
            for event in MeteoraDammV1::parse_logs(logs.iter(), None) {
                match event {
                    MeteoraDammV1Event::PoolCreated(Some(create)) => {
                        let token_mint = if create.token_a_mint == WSOL_MINT
                            && create.token_b_mint != WSOL_MINT
                        {
                            Some(create.token_b_mint)
                        } else if create.token_b_mint == WSOL_MINT
                            && create.token_a_mint != WSOL_MINT
                        {
                            Some(create.token_a_mint)
                        } else {
                            None
                        };
                        out.push(ObservedEvent {
                            kind: EventKind::Mint,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "POOL_CREATED pool={} a={} b={} lp={}",
                                create.pool,
                                create.token_a_mint,
                                create.token_b_mint,
                                create.lp_mint
                            ),
                            pump_fun_delay_secs: None,
                            mint: token_mint,
                            pool: Some(create.pool),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        })
                    }
                    MeteoraDammV1Event::Swap(Some(swap)) => out.push(ObservedEvent {
                        kind: EventKind::Swap,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!(
                            "SWAP in={} out={} fee={}",
                            swap.in_amount, swap.out_amount, swap.trade_fee
                        ),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: Some(SwapDetail::MeteoraDammV1 {
                            in_amount: swap.in_amount,
                            out_amount: swap.out_amount,
                        }),
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }),
                    _ => {}
                }
            }
        }
        Market::MeteoraDammV2 => {
            let mut parsed = false;
            for event in MeteoraDammV2::parse_logs(logs.iter(), None) {
                match event {
                    MeteoraDammV2Event::InitializePool(Some(init)) => {
                        parsed = true;
                        let token_mint = if init.token_a_mint == WSOL_MINT
                            && init.token_b_mint != WSOL_MINT
                        {
                            Some(init.token_b_mint)
                        } else if init.token_b_mint == WSOL_MINT && init.token_a_mint != WSOL_MINT {
                            Some(init.token_a_mint)
                        } else {
                            None
                        };
                        out.push(ObservedEvent {
                            kind: EventKind::Mint,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "INIT_POOL pool={} a={} b={} creator={}",
                                init.pool, init.token_a_mint, init.token_b_mint, init.creator
                            ),
                            pump_fun_delay_secs: None,
                            mint: token_mint,
                            pool: Some(init.pool),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        })
                    }
                    MeteoraDammV2Event::Swap2(Some(swap)) => {
                        parsed = true;
                        out.push(ObservedEvent {
                            kind: EventKind::Swap,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "SWAP2 pool={} a0={} a1={} out={}",
                                swap.pool, swap.amount_0, swap.amount_1, swap.output_amount
                            ),
                            pump_fun_delay_secs: None,
                            mint: None,
                            pool: Some(swap.pool),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: Some(SwapDetail::MeteoraDammV2 {
                                input_amount: swap.included_fee_input_amount,
                                output_amount: swap.output_amount,
                            }),
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        })
                    }
                    _ => {}
                }
            }

            if !parsed {
                let invoke_prefix = format!("Program {} invoke", METEORA_DAMM_V2_ID);
                if logs.iter().any(|log| log.starts_with(&invoke_prefix)) {
                    let instruction = logs
                        .iter()
                        .find_map(|log| log.split("Instruction:").nth(1))
                        .map(|tail| tail.trim().to_string())
                        .filter(|v| !v.is_empty())
                        .unwrap_or_else(|| "unknown".to_string());
                    let kind = if instruction.to_ascii_lowercase().contains("initialize") {
                        EventKind::Mint
                    } else {
                        EventKind::Swap
                    };
                    out.push(ObservedEvent {
                        kind,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!(
                            "INVOKE {} (emit_cpi) sig={}",
                            instruction,
                            truncate(signature, 18)
                        ),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: None,
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    });
                }
            }
        }
        Market::MeteoraDbc => {
            let mut parsed = false;
            for event in MeteoraDbc::parse_logs(logs.iter(), None) {
                match event {
                    MeteoraDbcEvent::InitializePool(Some(init)) => {
                        parsed = true;
                        out.push(ObservedEvent {
                            kind: EventKind::Mint,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "INIT_POOL pool={} base={} creator={} activation={}",
                                init.pool, init.base_mint, init.creator, init.activation_point
                            ),
                            pump_fun_delay_secs: None,
                            mint: Some(init.base_mint),
                            pool: Some(init.pool),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        })
                    }
                    MeteoraDbcEvent::Swap2(Some(swap)) => {
                        parsed = true;
                        out.push(ObservedEvent {
                            kind: EventKind::Swap,
                            market,
                            observed_unix_ms,
                            signature: signature.to_string(),
                            summary: format!(
                                "SWAP2 pool={} a0={} a1={} out={}",
                                swap.pool, swap.amount_0, swap.amount_1, swap.output_amount
                            ),
                            pump_fun_delay_secs: None,
                            mint: None,
                            pool: Some(swap.pool),
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: Some(SwapDetail::MeteoraDbc {
                                input_amount: swap.included_fee_input_amount,
                                output_amount: swap.output_amount,
                            }),
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        })
                    }
                    _ => {}
                }
            }

            if !parsed {
                let invoke_prefix = format!("Program {} invoke", METEORA_DBC_ID);
                if logs.iter().any(|log| log.starts_with(&invoke_prefix)) {
                    let instruction = logs
                        .iter()
                        .find_map(|log| log.split("Instruction:").nth(1))
                        .map(|tail| tail.trim().to_string())
                        .filter(|v| !v.is_empty())
                        .unwrap_or_else(|| "unknown".to_string());
                    let kind = if instruction.to_ascii_lowercase().contains("initialize") {
                        EventKind::Mint
                    } else {
                        EventKind::Swap
                    };
                    out.push(ObservedEvent {
                        kind,
                        market,
                        observed_unix_ms,
                        signature: signature.to_string(),
                        summary: format!(
                            "INVOKE {} (emit_cpi) sig={}",
                            instruction,
                            truncate(signature, 18)
                        ),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: None,
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    });
                }
            }
        }
    }

    out
}

async fn market_ws_task(
    market: Market,
    ws_url: String,
    out_tx: mpsc::Sender<AppMsg>,
) -> anyhow::Result<()> {
    let cfg = RpcTransactionLogsConfig {
        commitment: Some(CommitmentConfig::processed()),
    };

    let mut backoff = Duration::from_millis(250);
    loop {
        let _ = out_tx
            .send(AppMsg::Ws(ObservedEvent {
                kind: EventKind::Status,
                market,
                observed_unix_ms: now_unix_ms(),
                signature: String::new(),
                summary: format!("connecting to {}", redact_url_for_artifact(&ws_url)),
                pump_fun_delay_secs: None,
                mint: None,
                pool: None,
                side: None,
                sol_amount: None,
                token_amount: None,
                swap_detail: None,
                pump_swap_trade_kind: None,
                pump_swap_base_amount_raw: None,
                pump_swap_quote_amount_raw: None,
                pump_swap_pool_meta: None,
            }))
            .await;

        let client = match PubsubClient::new(&ws_url).await {
            Ok(client) => client,
            Err(error) => {
                let _ = out_tx
                    .send(AppMsg::Ws(ObservedEvent {
                        kind: EventKind::Warning,
                        market,
                        observed_unix_ms: now_unix_ms(),
                        signature: String::new(),
                        summary: format!("ws connect failed: {}", error),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: None,
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }))
                    .await;
                tokio::time::sleep(backoff).await;
                backoff = (backoff * 2).min(Duration::from_secs(5));
                continue;
            }
        };

        match market {
            Market::RaydiumLaunchpad => {
                let (mut stream_mainnet, _unsub_mainnet) = match client
                    .logs_subscribe(
                        RpcTransactionLogsFilter::Mentions(vec![RAYDIUM_LAUNCHPAD_ID.to_string()]),
                        cfg.clone(),
                    )
                    .await
                {
                    Ok(pair) => pair,
                    Err(error) => {
                        let _ = out_tx
                            .send(AppMsg::Ws(ObservedEvent {
                                kind: EventKind::Warning,
                                market,
                                observed_unix_ms: now_unix_ms(),
                                signature: String::new(),
                                summary: format!("logs_subscribe failed: {}", error),
                                pump_fun_delay_secs: None,
                                mint: None,
                                pool: None,
                                side: None,
                                sol_amount: None,
                                token_amount: None,
                                swap_detail: None,
                                pump_swap_trade_kind: None,
                                pump_swap_base_amount_raw: None,
                                pump_swap_quote_amount_raw: None,
                                pump_swap_pool_meta: None,
                            }))
                            .await;
                        tokio::time::sleep(backoff).await;
                        backoff = (backoff * 2).min(Duration::from_secs(5));
                        continue;
                    }
                };

                let (mut stream_devnet, _unsub_devnet) = match client
                    .logs_subscribe(
                        RpcTransactionLogsFilter::Mentions(vec![
                            RAYDIUM_LAUNCHPAD_DEVNET_ID.to_string(),
                        ]),
                        cfg.clone(),
                    )
                    .await
                {
                    Ok(pair) => pair,
                    Err(error) => {
                        let _ = out_tx
                            .send(AppMsg::Ws(ObservedEvent {
                                kind: EventKind::Warning,
                                market,
                                observed_unix_ms: now_unix_ms(),
                                signature: String::new(),
                                summary: format!("logs_subscribe failed: {}", error),
                                pump_fun_delay_secs: None,
                                mint: None,
                                pool: None,
                                side: None,
                                sol_amount: None,
                                token_amount: None,
                                swap_detail: None,
                                pump_swap_trade_kind: None,
                                pump_swap_base_amount_raw: None,
                                pump_swap_quote_amount_raw: None,
                                pump_swap_pool_meta: None,
                            }))
                            .await;
                        tokio::time::sleep(backoff).await;
                        backoff = (backoff * 2).min(Duration::from_secs(5));
                        continue;
                    }
                };

                backoff = Duration::from_millis(250);
                for program_id_label in [RAYDIUM_LAUNCHPAD_ID, RAYDIUM_LAUNCHPAD_DEVNET_ID] {
                    let _ = out_tx
                        .send(AppMsg::Ws(ObservedEvent {
                            kind: EventKind::Status,
                            market,
                            observed_unix_ms: now_unix_ms(),
                            signature: String::new(),
                            summary: format!("subscribed ({})", program_id_label),
                            pump_fun_delay_secs: None,
                            mint: None,
                            pool: None,
                            side: None,
                            sol_amount: None,
                            token_amount: None,
                            swap_detail: None,
                            pump_swap_trade_kind: None,
                            pump_swap_base_amount_raw: None,
                            pump_swap_quote_amount_raw: None,
                            pump_swap_pool_meta: None,
                        }))
                        .await;
                }

                loop {
                    let msg = tokio::select! {
                        msg = stream_mainnet.next() => msg,
                        msg = stream_devnet.next() => msg,
                    };
                    let Some(msg) = msg else {
                        break;
                    };

                    let observed_unix_ms = now_unix_ms();
                    let observed_unix_secs = now_unix_secs_f64();

                    let signature_text = msg.value.signature.to_string();
                    let logs = msg.value.logs;

                    for event in parse_logs_to_events(
                        market,
                        &signature_text,
                        &logs,
                        observed_unix_ms,
                        observed_unix_secs,
                    ) {
                        let _ = out_tx.send(AppMsg::Ws(event)).await;
                    }
                }
            }
            _ => {
                let program_id = program_id_for_market(market);
                let (mut stream, _unsub) = match client
                    .logs_subscribe(
                        RpcTransactionLogsFilter::Mentions(vec![program_id.to_string()]),
                        cfg.clone(),
                    )
                    .await
                {
                    Ok(pair) => pair,
                    Err(error) => {
                        let _ = out_tx
                            .send(AppMsg::Ws(ObservedEvent {
                                kind: EventKind::Warning,
                                market,
                                observed_unix_ms: now_unix_ms(),
                                signature: String::new(),
                                summary: format!("logs_subscribe failed: {}", error),
                                pump_fun_delay_secs: None,
                                mint: None,
                                pool: None,
                                side: None,
                                sol_amount: None,
                                token_amount: None,
                                swap_detail: None,
                                pump_swap_trade_kind: None,
                                pump_swap_base_amount_raw: None,
                                pump_swap_quote_amount_raw: None,
                                pump_swap_pool_meta: None,
                            }))
                            .await;
                        tokio::time::sleep(backoff).await;
                        backoff = (backoff * 2).min(Duration::from_secs(5));
                        continue;
                    }
                };

                backoff = Duration::from_millis(250);
                let _ = out_tx
                    .send(AppMsg::Ws(ObservedEvent {
                        kind: EventKind::Status,
                        market,
                        observed_unix_ms: now_unix_ms(),
                        signature: String::new(),
                        summary: format!("subscribed ({})", program_id),
                        pump_fun_delay_secs: None,
                        mint: None,
                        pool: None,
                        side: None,
                        sol_amount: None,
                        token_amount: None,
                        swap_detail: None,
                        pump_swap_trade_kind: None,
                        pump_swap_base_amount_raw: None,
                        pump_swap_quote_amount_raw: None,
                        pump_swap_pool_meta: None,
                    }))
                    .await;

                while let Some(msg) = stream.next().await {
                    let observed_unix_ms = now_unix_ms();
                    let observed_unix_secs = now_unix_secs_f64();

                    let signature_text = msg.value.signature.to_string();
                    let logs = msg.value.logs;

                    for event in parse_logs_to_events(
                        market,
                        &signature_text,
                        &logs,
                        observed_unix_ms,
                        observed_unix_secs,
                    ) {
                        let _ = out_tx.send(AppMsg::Ws(event)).await;
                    }
                }
            }
        }

        let _ = out_tx
            .send(AppMsg::Ws(ObservedEvent {
                kind: EventKind::Warning,
                market,
                observed_unix_ms: now_unix_ms(),
                signature: String::new(),
                summary: "subscription ended; reconnecting".to_string(),
                pump_fun_delay_secs: None,
                mint: None,
                pool: None,
                side: None,
                sol_amount: None,
                token_amount: None,
                swap_detail: None,
                pump_swap_trade_kind: None,
                pump_swap_base_amount_raw: None,
                pump_swap_quote_amount_raw: None,
                pump_swap_pool_meta: None,
            }))
            .await;

        tokio::time::sleep(backoff).await;
        backoff = (backoff * 2).min(Duration::from_secs(5));
    }
}

