#[derive(Debug, Default, Clone)]
struct LoadingUiState {
    lines: VecDeque<String>,
    done: bool,
    error: Option<String>,
    api_log_path: Option<PathBuf>,
}

impl LoadingUiState {
    fn push_line(&mut self, line: impl Into<String>) {
        const MAX_LINES: usize = 10;
        self.lines.push_back(line.into());
        while self.lines.len() > MAX_LINES {
            self.lines.pop_front();
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum TradeControlsField {
    Buy,
    Sell,
    BuySol,
    SellPct,
    Live,
    SlippagePct,
    Retries,
    PriorityFeeLevel,
    PriorityFeeSol,
    Mev,
    MevTip,
}

impl TradeControlsField {
    fn next(self, custom_priority_fee: bool) -> Self {
        match self {
            Self::Buy => Self::Sell,
            Self::Sell => Self::BuySol,
            Self::BuySol => Self::SellPct,
            Self::SellPct => Self::Live,
            Self::Live => Self::SlippagePct,
            Self::SlippagePct => Self::Retries,
            Self::Retries => Self::PriorityFeeLevel,
            Self::PriorityFeeLevel => {
                if custom_priority_fee {
                    Self::PriorityFeeSol
                } else {
                    Self::Mev
                }
            }
            Self::PriorityFeeSol => Self::Mev,
            Self::Mev => Self::MevTip,
            Self::MevTip => Self::Buy,
        }
    }

    fn prev(self, custom_priority_fee: bool) -> Self {
        match self {
            Self::Buy => Self::MevTip,
            Self::Sell => Self::Buy,
            Self::BuySol => Self::Sell,
            Self::SellPct => Self::BuySol,
            Self::Live => Self::SellPct,
            Self::SlippagePct => Self::Live,
            Self::Retries => Self::SlippagePct,
            Self::PriorityFeeLevel => Self::Retries,
            Self::PriorityFeeSol => Self::PriorityFeeLevel,
            Self::Mev => {
                if custom_priority_fee {
                    Self::PriorityFeeSol
                } else {
                    Self::PriorityFeeLevel
                }
            }
            Self::MevTip => Self::Mev,
        }
    }

    fn from_submit_side(side: TradeSide) -> Self {
        match side {
            TradeSide::Buy => Self::Buy,
            TradeSide::Sell => Self::Sell,
        }
    }

    fn submit_side(self) -> Option<TradeSide> {
        match self {
            Self::Buy | Self::BuySol => Some(TradeSide::Buy),
            Self::Sell | Self::SellPct => Some(TradeSide::Sell),
            Self::Live
            | Self::SlippagePct
            | Self::Retries
            | Self::PriorityFeeLevel
            | Self::PriorityFeeSol
            | Self::Mev
            | Self::MevTip => None,
        }
    }
}

