#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CreateExecutionMode {
    Dry,
    Live,
}

impl CreateExecutionMode {
    fn cycle(self, delta: i32) -> Self {
        match (self, delta.signum()) {
            (Self::Dry, 1) => Self::Live,
            (Self::Live, 1) => Self::Dry,
            (Self::Dry, -1) => Self::Live,
            (Self::Live, -1) => Self::Dry,
            _ => self,
        }
    }

    fn label(self) -> &'static str {
        match self {
            Self::Dry => "build",
            Self::Live => "send",
        }
    }
}

