impl CreateUiState {
    fn recompute_raydium_platform_filter(&mut self) {
        self.raydium_platform_filtered.clear();

        let Some(global_config) = self
            .selected_raydium_global_config()
            .map(|cfg| cfg.pubkey.trim())
            .filter(|v| !v.is_empty())
        else {
            self.raydium_platform_filtered
                .extend(0..self.raydium_platform_configs.len());
            if self.raydium_platform_idx >= self.raydium_platform_filtered.len() {
                self.raydium_platform_idx = 0;
            }
            return;
        };

        let global_config = global_config.to_string();
        for (idx, cfg) in self.raydium_platform_configs.iter().enumerate() {
            if cfg
                .curve_params_global_configs
                .iter()
                .any(|value| value.trim() == global_config)
            {
                self.raydium_platform_filtered.push(idx);
            }
        }

        if self.raydium_platform_idx >= self.raydium_platform_filtered.len() {
            self.raydium_platform_idx = 0;
        }
    }

    fn raydium_platform_filtered_len(&self) -> usize {
        self.raydium_platform_filtered.len()
    }

    fn raydium_platform_count_for_global(&self, global_config: &str) -> usize {
        let needle = global_config.trim();
        if needle.is_empty() {
            return 0;
        }
        self.raydium_platform_configs
            .iter()
            .filter(|cfg| {
                cfg.curve_params_global_configs
                    .iter()
                    .any(|value| value.trim() == needle)
            })
            .count()
    }

    fn select_best_raydium_platform_for_selected_global(&mut self) {
        if self.raydium_platform_filtered.is_empty() {
            self.raydium_platform_idx = 0;
            return;
        }

        let mut best_pos = 0usize;
        let mut best_len = 0u32;
        for (pos, &idx) in self.raydium_platform_filtered.iter().enumerate() {
            let Some(cfg) = self.raydium_platform_configs.get(idx) else {
                continue;
            };
            if cfg.curve_params_len > best_len {
                best_len = cfg.curve_params_len;
                best_pos = pos;
            }
        }
        self.raydium_platform_idx = best_pos;
    }

    fn autoselect_raydium_launchpad_defaults(&mut self) {
        if self.raydium_global_configs.is_empty() || self.raydium_platform_configs.is_empty() {
            return;
        }

        let mut best_global_idx = 0usize;
        let mut best_platform_count = 0usize;
        for (idx, cfg) in self.raydium_global_configs.iter().enumerate() {
            let count = self.raydium_platform_count_for_global(&cfg.pubkey);
            if count > best_platform_count {
                best_platform_count = count;
                best_global_idx = idx;
            }
        }

        if best_platform_count > 0 {
            self.raydium_global_idx = best_global_idx;
        }

        self.recompute_raydium_platform_filter();
        self.select_best_raydium_platform_for_selected_global();
    }

    fn selected_raydium_global_config(&self) -> Option<&RaydiumLaunchpadGlobalConfigResponse> {
        self.raydium_global_configs.get(self.raydium_global_idx)
    }

    fn selected_raydium_platform_config(&self) -> Option<&RaydiumLaunchpadPlatformConfigResponse> {
        self.raydium_platform_filtered
            .get(self.raydium_platform_idx)
            .and_then(|idx| self.raydium_platform_configs.get(*idx))
    }

    fn selected_raydium_curve_param(&self) -> Option<&RaydiumLaunchpadPlatformCurveParamResponse> {
        self.raydium_curve_params.get(self.raydium_curve_idx)
    }

    fn reset_raydium_discovery_state(&mut self) {
        self.raydium_global_configs.clear();
        self.raydium_platform_configs.clear();
        self.raydium_platform_filtered.clear();
        self.raydium_curve_params.clear();
        self.raydium_global_idx = 0;
        self.raydium_platform_idx = 0;
        self.raydium_curve_idx = 0;
        self.raydium_configs_inflight = false;
        self.raydium_curve_inflight = false;
        self.raydium_error = None;
    }

    fn begin_raydium_configs_fetch(
        &mut self,
        base: &str,
        api_key: &str,
        rpc_url: &str,
        tx: mpsc::Sender<AppMsg>,
    ) {
        self.reset_raydium_discovery_state();
        self.raydium_configs_inflight = true;
        let rpc_url = {
            let rpc_url = rpc_url.trim();
            if rpc_url.is_empty() {
                self.network.default_http_url().to_string()
            } else {
                rpc_url.to_string()
            }
        };
        spawn_raydium_launchpad_global_configs_fetch(
            base.to_string(),
            api_key.to_string(),
            self.network,
            rpc_url.clone(),
            tx.clone(),
        );
        spawn_raydium_launchpad_platform_configs_fetch(
            base.to_string(),
            api_key.to_string(),
            self.network,
            rpc_url,
            tx,
        );
    }

    fn begin_raydium_curve_fetch(
        &mut self,
        base: &str,
        api_key: &str,
        rpc_url: &str,
        tx: mpsc::Sender<AppMsg>,
    ) {
        let Some((global_config, platform_config)) = self
            .selected_raydium_global_config()
            .map(|global| global.pubkey.clone())
            .zip(
                self.selected_raydium_platform_config()
                    .map(|platform| platform.pubkey.clone()),
            )
        else {
            return;
        };

        self.raydium_curve_inflight = true;
        self.raydium_curve_params.clear();
        self.raydium_curve_idx = 0;
        self.raydium_error = None;

        let rpc_url = {
            let rpc_url = rpc_url.trim();
            if rpc_url.is_empty() {
                self.network.default_http_url().to_string()
            } else {
                rpc_url.to_string()
            }
        };
        spawn_raydium_launchpad_curve_params_fetch(
            base.to_string(),
            api_key.to_string(),
            self.network,
            rpc_url,
            platform_config,
            global_config,
            tx,
        );
    }

    fn is_field_enabled(&self, field: CreateEditField) -> bool {
        match field {
            CreateEditField::Decimals => self.method != CreateMethod::PumpFun,
            CreateEditField::Uri => self.image_path.trim().is_empty(),
            CreateEditField::RaydiumGlobalConfig
            | CreateEditField::RaydiumPlatformConfig
            | CreateEditField::RaydiumCurveParam
            | CreateEditField::RaydiumBaseTokenProgram => {
                self.method == CreateMethod::RaydiumLaunchpad
            }
            CreateEditField::RaydiumTransferFeeEnabled => {
                self.method == CreateMethod::RaydiumLaunchpad
                    && matches!(
                        self.raydium_base_token_program,
                        RaydiumBaseTokenProgram::SplToken2022
                    )
            }
            CreateEditField::RaydiumTransferFeeBps | CreateEditField::RaydiumTransferFeeMax => {
                self.method == CreateMethod::RaydiumLaunchpad
                    && matches!(
                        self.raydium_base_token_program,
                        RaydiumBaseTokenProgram::SplToken2022
                    )
                    && self.raydium_transfer_fee_enabled
            }
            CreateEditField::AutoBuy => {
                matches!(
                    self.method,
                    CreateMethod::PumpFun | CreateMethod::RaydiumLaunchpad
                )
            }
            CreateEditField::AutoBuySol | CreateEditField::AutoBuySlippagePct => {
                matches!(
                    self.method,
                    CreateMethod::PumpFun | CreateMethod::RaydiumLaunchpad
                ) && self.auto_buy_enabled
            }
            CreateEditField::Description
            | CreateEditField::Twitter
            | CreateEditField::Website
            | CreateEditField::Telegram => self.details_open,
            _ => true,
        }
    }

    fn next_enabled_field(&self) -> CreateEditField {
        let mut field = self.field;
        for _ in 0..32 {
            field = field.next();
            if self.is_field_enabled(field) {
                return field;
            }
        }
        self.field
    }

    fn prev_enabled_field(&self) -> CreateEditField {
        let mut field = self.field;
        for _ in 0..32 {
            field = field.prev();
            if self.is_field_enabled(field) {
                return field;
            }
        }
        self.field
    }

    fn clamp_field(&mut self) {
        if !self.is_field_enabled(self.field) {
            self.field = self.next_enabled_field();
        }
    }

    fn active_mut(&mut self) -> Option<&mut String> {
        match self.field {
            CreateEditField::Network => None,
            CreateEditField::Method => None,
            CreateEditField::AutoBuy => None,
            CreateEditField::Execution => None,
            CreateEditField::Mev => None,
            CreateEditField::Details => None,
            CreateEditField::RaydiumGlobalConfig => None,
            CreateEditField::RaydiumPlatformConfig => None,
            CreateEditField::RaydiumCurveParam => None,
            CreateEditField::RaydiumBaseTokenProgram => None,
            CreateEditField::RaydiumTransferFeeEnabled => None,
            CreateEditField::Name => Some(&mut self.name),
            CreateEditField::Symbol => Some(&mut self.symbol),
            CreateEditField::Description => Some(&mut self.description),
            CreateEditField::ImagePath => Some(&mut self.image_path),
            CreateEditField::MevTip => Some(&mut self.mev_tip_sol),
            CreateEditField::AutoBuySol => Some(&mut self.auto_buy_sol),
            CreateEditField::AutoBuySlippagePct => Some(&mut self.auto_buy_slippage_pct),
            CreateEditField::Twitter => Some(&mut self.twitter),
            CreateEditField::Website => Some(&mut self.website),
            CreateEditField::Telegram => Some(&mut self.telegram),
            CreateEditField::Uri => self.image_path.trim().is_empty().then_some(&mut self.uri),
            CreateEditField::Decimals => {
                (self.method != CreateMethod::PumpFun).then_some(&mut self.decimals)
            }
            CreateEditField::RaydiumTransferFeeBps => Some(&mut self.raydium_transfer_fee_bps),
            CreateEditField::RaydiumTransferFeeMax => Some(&mut self.raydium_transfer_fee_max),
        }
    }

    fn cycle_method(&mut self, delta: i32) {
        const METHODS: [CreateMethod; 4] = [
            CreateMethod::PumpFun,
            CreateMethod::SplToken,
            CreateMethod::SplToken2022,
            CreateMethod::RaydiumLaunchpad,
        ];
        let idx = METHODS.iter().position(|m| *m == self.method).unwrap_or(0);
        let len = METHODS.len() as i32;
        let next = (idx as i32 + delta).rem_euclid(len) as usize;
        self.method = METHODS[next];
        if !matches!(
            self.method,
            CreateMethod::PumpFun | CreateMethod::RaydiumLaunchpad
        ) {
            self.auto_buy_enabled = false;
        }
        if matches!(
            self.method,
            CreateMethod::SplToken | CreateMethod::SplToken2022 | CreateMethod::RaydiumLaunchpad
        ) && self.decimals.trim().is_empty()
        {
            self.decimals = "6".to_string();
        }
        self.clamp_field();
    }
}

