impl CreatePoolUiState {
    fn cycle_market(&mut self, delta: i32) {
        let idx = CREATE_POOL_MARKETS
            .iter()
            .position(|m| *m == self.market)
            .unwrap_or(0);
        let len = CREATE_POOL_MARKETS.len() as i32;
        let next = (idx as i32 + delta).rem_euclid(len) as usize;
        self.market = CREATE_POOL_MARKETS[next];
        self.clamp_field();
    }

    fn clamp_field(&mut self) {
        if !self.is_field_enabled(self.field) {
            self.field = self.next_enabled_field();
        }
    }

    fn is_field_enabled(&self, field: CreatePoolEditField) -> bool {
        match field {
            CreatePoolEditField::Network
            | CreatePoolEditField::Market
            | CreatePoolEditField::Execution
            | CreatePoolEditField::Mev
            | CreatePoolEditField::MevTip
            | CreatePoolEditField::QuoteMint => true,
            CreatePoolEditField::BaseMint => self.market != Market::MeteoraDbc,
            CreatePoolEditField::BaseAmount | CreatePoolEditField::QuoteAmount => matches!(
                self.market,
                Market::PumpSwap
                    | Market::RaydiumAmmV4
                    | Market::RaydiumCpmm
                    | Market::RaydiumClmm
                    | Market::MeteoraDlmm
                    | Market::MeteoraDammV1
                    | Market::MeteoraDammV2
            ),
            CreatePoolEditField::InitialPrice => matches!(
                self.market,
                Market::RaydiumClmm | Market::MeteoraDlmm | Market::MeteoraDammV2
            ),
            CreatePoolEditField::PumpSwapIndex | CreatePoolEditField::PumpSwapMayhemMode => {
                self.market == Market::PumpSwap
            }
            CreatePoolEditField::RaydiumCpmmAmmConfigIndex => self.market == Market::RaydiumCpmm,
            CreatePoolEditField::RaydiumAmmV4Market => self.market == Market::RaydiumAmmV4,
            CreatePoolEditField::RaydiumClmmTickSpacing => self.market == Market::RaydiumClmm,
            CreatePoolEditField::MeteoraDlmmBinStep
            | CreatePoolEditField::MeteoraDlmmBaseFeeBps => self.market == Market::MeteoraDlmm,
            CreatePoolEditField::MeteoraDammV1TradeFeeBps => self.market == Market::MeteoraDammV1,
            CreatePoolEditField::MeteoraDammV2ConfigIndex => self.market == Market::MeteoraDammV2,
            CreatePoolEditField::MeteoraDbcConfigIndex
            | CreatePoolEditField::MeteoraDbcName
            | CreatePoolEditField::MeteoraDbcSymbol
            | CreatePoolEditField::MeteoraDbcUri => self.market == Market::MeteoraDbc,
        }
    }

    fn next_enabled_field(&self) -> CreatePoolEditField {
        let mut field = self.field;
        for _ in 0..64 {
            field = field.next();
            if self.is_field_enabled(field) {
                return field;
            }
        }
        self.field
    }

    fn prev_enabled_field(&self) -> CreatePoolEditField {
        let mut field = self.field;
        for _ in 0..64 {
            field = field.prev();
            if self.is_field_enabled(field) {
                return field;
            }
        }
        self.field
    }

    fn active_mut(&mut self) -> Option<&mut String> {
        match self.field {
            CreatePoolEditField::BaseMint => Some(&mut self.base_mint),
            CreatePoolEditField::MevTip => Some(&mut self.mev_tip_sol),
            CreatePoolEditField::QuoteMint => Some(&mut self.quote_mint),
            CreatePoolEditField::BaseAmount => Some(&mut self.base_amount),
            CreatePoolEditField::QuoteAmount => Some(&mut self.quote_amount),
            CreatePoolEditField::InitialPrice => Some(&mut self.initial_price),
            CreatePoolEditField::PumpSwapIndex => Some(&mut self.pump_swap_index),
            CreatePoolEditField::RaydiumCpmmAmmConfigIndex => {
                Some(&mut self.raydium_cpmm_amm_config_index)
            }
            CreatePoolEditField::RaydiumAmmV4Market => Some(&mut self.raydium_amm_v4_market),
            CreatePoolEditField::RaydiumClmmTickSpacing => {
                Some(&mut self.raydium_clmm_tick_spacing)
            }
            CreatePoolEditField::MeteoraDlmmBinStep => Some(&mut self.meteora_dlmm_bin_step),
            CreatePoolEditField::MeteoraDlmmBaseFeeBps => Some(&mut self.meteora_dlmm_base_fee_bps),
            CreatePoolEditField::MeteoraDammV1TradeFeeBps => {
                Some(&mut self.meteora_damm_v1_trade_fee_bps)
            }
            CreatePoolEditField::MeteoraDammV2ConfigIndex => {
                Some(&mut self.meteora_damm_v2_config_index)
            }
            CreatePoolEditField::MeteoraDbcConfigIndex => Some(&mut self.meteora_dbc_config_index),
            CreatePoolEditField::MeteoraDbcName => Some(&mut self.meteora_dbc_name),
            CreatePoolEditField::MeteoraDbcSymbol => Some(&mut self.meteora_dbc_symbol),
            CreatePoolEditField::MeteoraDbcUri => Some(&mut self.meteora_dbc_uri),
            _ => None,
        }
    }

    fn derived_pool_label(&self) -> &'static str {
        match self.market {
            Market::PumpSwap => "pool",
            Market::RaydiumAmmV4 => "amm",
            Market::RaydiumClmm | Market::RaydiumCpmm => "pool_state",
            Market::MeteoraDlmm => "lb_pair",
            Market::MeteoraDammV1 => "pool",
            _ => "pool",
        }
    }

    fn market_supported(&self) -> bool {
        matches!(
            self.market,
            Market::PumpSwap
                | Market::RaydiumAmmV4
                | Market::RaydiumCpmm
                | Market::RaydiumClmm
                | Market::MeteoraDlmm
                | Market::MeteoraDammV1
                | Market::MeteoraDammV2
                | Market::MeteoraDbc
        )
    }
}

