#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum WalletTransferAsset {
    Sol,
    Token,
}

impl WalletTransferAsset {
    fn cycle(self, delta: i32) -> Self {
        match (self, delta.signum()) {
            (Self::Sol, 1) => Self::Token,
            (Self::Token, 1) => Self::Sol,
            (Self::Sol, -1) => Self::Token,
            (Self::Token, -1) => Self::Sol,
            _ => self,
        }
    }

    fn label(self) -> &'static str {
        match self {
            Self::Sol => "sol",
            Self::Token => "token",
        }
    }
}

