#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum QuickTradeLookupField {
    MintInput,
    Side,
    Network,
    Lookup,
}

impl QuickTradeLookupField {
    fn next(self) -> Self {
        match self {
            Self::MintInput => Self::Side,
            Self::Side => Self::Network,
            Self::Network => Self::Lookup,
            Self::Lookup => Self::MintInput,
        }
    }

    fn prev(self) -> Self {
        match self {
            Self::MintInput => Self::Lookup,
            Self::Side => Self::MintInput,
            Self::Network => Self::Side,
            Self::Lookup => Self::Network,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum QuickTradeField {
    Side,
    Network,
    BuySol,
    SellPct,
    SlippagePct,
    Retries,
    PriorityFeeLevel,
    PriorityFeeSol,
    Mev,
    MevTip,
    Action,
}

impl QuickTradeField {
    fn next(self, custom_priority_fee: bool) -> Self {
        match self {
            Self::Side => Self::Network,
            Self::Network => Self::BuySol,
            Self::BuySol => Self::SellPct,
            Self::SellPct => Self::SlippagePct,
            Self::SlippagePct => Self::Retries,
            Self::Retries => Self::PriorityFeeLevel,
            Self::PriorityFeeLevel => {
                if custom_priority_fee {
                    Self::PriorityFeeSol
                } else {
                    Self::Mev
                }
            }
            Self::PriorityFeeSol => Self::Mev,
            Self::Mev => Self::MevTip,
            Self::MevTip => Self::Action,
            Self::Action => Self::Side,
        }
    }

    fn prev(self, custom_priority_fee: bool) -> Self {
        match self {
            Self::Side => Self::Action,
            Self::Network => Self::Side,
            Self::BuySol => Self::Network,
            Self::SellPct => Self::BuySol,
            Self::SlippagePct => Self::SellPct,
            Self::Retries => Self::SlippagePct,
            Self::PriorityFeeLevel => Self::Retries,
            Self::PriorityFeeSol => Self::PriorityFeeLevel,
            Self::Mev => {
                if custom_priority_fee {
                    Self::PriorityFeeSol
                } else {
                    Self::PriorityFeeLevel
                }
            }
            Self::MevTip => Self::Mev,
            Self::Action => Self::MevTip,
        }
    }
}

