struct QuickTradeUiState {
    side: TradeSide,
    network: CreateNetwork,
    lookup_field: QuickTradeLookupField,
    field: QuickTradeField,
    mint_input: String,
    route: Option<HttpTradeRoute>,
    metadata: Option<HttpTradeTokenMetadata>,
    lookup_inflight: bool,
    inflight: bool,
    low_lq_confirm_pending: bool,
    execution: CreateExecutionMode,
    edit: Option<QuickTradeEditState>,
    status: Option<String>,
    error: Option<String>,
    last_wallet_results: Vec<String>,
    last_wallet_updates: Vec<TradeExecUpdate>,
}

impl QuickTradeUiState {
    fn new(side: TradeSide, mint_input: String) -> Self {
        Self {
            side,
            network: CreateNetwork::Devnet,
            lookup_field: QuickTradeLookupField::MintInput,
            field: QuickTradeField::Side,
            mint_input,
            route: None,
            metadata: None,
            lookup_inflight: false,
            inflight: false,
            low_lq_confirm_pending: false,
            execution: CreateExecutionMode::Dry,
            edit: None,
            status: None,
            error: None,
            last_wallet_results: Vec::new(),
            last_wallet_updates: Vec::new(),
        }
    }

    fn clear_lookup_feedback(&mut self) {
        if self.route.is_none() {
            self.status = None;
            self.error = None;
        }
    }

    fn push_mint_input(&mut self, text: &str) {
        for c in text.chars() {
            if c.is_control() || c.is_whitespace() || !c.is_ascii_alphanumeric() {
                continue;
            }
            if self.mint_input.chars().count() >= MAX_PUBKEY_INPUT_CHARS {
                break;
            }
            self.mint_input.push(c);
        }
        self.lookup_field = QuickTradeLookupField::MintInput;
        self.clear_lookup_feedback();
    }

    fn pop_mint_input(&mut self) {
        if self.mint_input.pop().is_some() {
            self.clear_lookup_feedback();
        }
    }

    fn reset_lookup(&mut self) {
        self.route = None;
        self.metadata = None;
        self.lookup_inflight = false;
        self.inflight = false;
        self.low_lq_confirm_pending = false;
        self.lookup_field = QuickTradeLookupField::MintInput;
        self.field = QuickTradeField::Side;
        self.edit = None;
        self.status = None;
        self.error = None;
        self.last_wallet_results.clear();
        self.last_wallet_updates.clear();
    }
}

