struct TuiGuard {
    log_redirected: bool,
}

impl TuiGuard {
    fn enter() -> anyhow::Result<Self> {
        enable_raw_mode().context("enable raw mode")?;
        let mut stdout = io::stdout();
        execute!(stdout, EnterAlternateScreen, EnableBracketedPaste)
            .context("enter alternate screen")?;

        let timestamp = chrono::Utc::now().format("%Y%m%dT%H%M%SZ").to_string();
        let out_dir = PathBuf::from("artifacts/logs");
        fs::create_dir_all(&out_dir).context("create artifacts/logs")?;
        let path = out_dir.join(format!("{timestamp}_mamba.log"));
        let log_redirected = match mamba::utils::writing::set_log_file(&path) {
            Ok(()) => true,
            Err(_) => {
                // If we can't redirect logs to a file, hard-mute to protect the TUI.
                mamba::utils::writing::mute_logs();
                false
            }
        };

        Ok(Self { log_redirected })
    }
}

impl Drop for TuiGuard {
    fn drop(&mut self) {
        if self.log_redirected {
            mamba::utils::writing::restore_stderr_logging();
        } else {
            // If we previously muted to protect the TUI, restore normal stderr logging.
            mamba::utils::writing::restore_stderr_logging();
        }
        let _ = disable_raw_mode();
        let mut stdout = io::stdout();
        let _ = execute!(
            stdout,
            DisableMouseCapture,
            DisableBracketedPaste,
            LeaveAlternateScreen
        );
    }
}

