fn truncate(s: &str, max_chars: usize) -> String {
    if s.chars().count() <= max_chars {
        return s.to_string();
    }
    if max_chars < 3 {
        return s.chars().take(max_chars).collect::<String>();
    }
    let mut out = s
        .chars()
        .take(max_chars.saturating_sub(3))
        .collect::<String>();
    out.push_str("...");
    out
}

fn truncate_middle(s: &str, max_chars: usize) -> String {
    let len = s.chars().count();
    if len <= max_chars {
        return s.to_string();
    }
    if max_chars < 5 {
        return truncate(s, max_chars);
    }
    let head_chars = ((max_chars - 3) / 2).max(1);
    let tail_chars = (max_chars - 3).saturating_sub(head_chars).max(1);
    let head = s.chars().take(head_chars).collect::<String>();
    let tail = s
        .chars()
        .rev()
        .take(tail_chars)
        .collect::<Vec<_>>()
        .into_iter()
        .rev()
        .collect::<String>();
    format!("{head}...{tail}")
}

fn format_age_since_ms(fetched_unix_ms: u64) -> String {
    if fetched_unix_ms == 0 {
        return "-".to_string();
    }
    let age_s = (now_unix_ms().saturating_sub(fetched_unix_ms) as f64) / 1000.0;
    format!("{age_s:.1}s")
}

