fn format_trade_wallet_result_line(update: &TradeExecUpdate) -> String {
    let level = if update.success { "OK" } else { "FAIL" };
    let sig = update
        .signature
        .as_deref()
        .map(|value| truncate(value, 18))
        .unwrap_or_else(|| "-".to_string());
    let mut line = format!(
        "{} ({}) {} {} via {} sig={sig}",
        update.wallet_label,
        short_pubkey(&update.wallet_pubkey),
        match update.side {
            TradeSide::Buy => "BUY",
            TradeSide::Sell => "SELL",
        },
        level,
        update.market.as_str(),
    );
    if let Some(error) = update
        .error
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        line.push_str(" err=");
        line.push_str(&truncate(error, 80));
    }
    if let Some(warning) = update
        .warning
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        line.push_str(" warn=");
        line.push_str(&truncate(warning, 80));
    }
    line
}

fn apply_trade_exec_update(app: &mut AppState, update: TradeExecUpdate) {
    app.trade_last_exec = Some(update.clone());
    let key = (update.market, update.mint);

    if let Some(price) = update.price_sol
        && price.is_finite()
        && price > 0.0
    {
        app.touch_mint(update.market, update.mint);
        app.selected_mint_by_market
            .entry(update.market)
            .or_insert(update.mint);
        app.mint_activity
            .entry((update.market, update.mint))
            .or_default()
            .observe_price(now_unix_ms(), price);
        app.record_price_history(update.market, update.mint, now_unix_ms(), price);
    }

    if update.success
        && update.side == TradeSide::Buy
        && let Some(price) = update.price_sol
        && price.is_finite()
        && price > 0.0
    {
        app.trade_last_buy_price.insert(key, price);
        app.trade_frozen_pnl_price.remove(&key);
    }

    if update.success && update.send_requested {
        match update.side {
            TradeSide::Buy => {
                app.trade_token_balance_fetched_unix_ms.insert(key, 0);
                app.trade_token_balance_inflight.remove(&key);
            }
            TradeSide::Sell if update.requested_sell_pct == Some(100) => {
                if let Some(price) = update
                    .price_sol
                    .filter(|value| value.is_finite() && *value > 0.0)
                {
                    app.trade_frozen_pnl_price.insert(key, price);
                }
                app.trade_token_balances.insert(key, 0.0);
                app.trade_token_balance_fetched_unix_ms
                    .insert(key, now_unix_ms());
                app.trade_token_balance_inflight.remove(&key);
            }
            TradeSide::Sell => {
                app.trade_token_balance_fetched_unix_ms.insert(key, 0);
                app.trade_token_balance_inflight.remove(&key);
            }
        }
    }

    let (kind, level) = if update.success {
        (EventKind::Status, "OK")
    } else {
        (EventKind::Warning, "FAIL")
    };
    let sig = update
        .signature
        .as_deref()
        .map(|value| truncate(value, 18))
        .unwrap_or_else(|| "-".to_string());
    let price = update
        .price_sol
        .filter(|value| value.is_finite() && *value > 0.0)
        .map(|value| format!("{value:.8}"))
        .unwrap_or_else(|| "-".to_string());
    let side = match update.side {
        TradeSide::Buy => "BUY",
        TradeSide::Sell => "SELL",
    };
    let mut summary = format!(
        "TRADE {side} {level} wallet={} mint={} price={} sig={}",
        update.wallet_label,
        short_pubkey(&update.mint),
        price,
        sig
    );
    if let Some(sig) = update
        .signature
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        let cluster = match update.network.or(app.connected_network) {
            Some(CreateNetwork::Devnet) => Some(mamba::core::cluster::SolanaCluster::Devnet),
            Some(CreateNetwork::Mainnet) => Some(mamba::core::cluster::SolanaCluster::MainnetBeta),
            None => None,
        };
        summary.push_str(" solscan=");
        summary.push_str(&solscan_tx_url(sig, cluster));
    }
    if let Some(err) = update
        .error
        .as_deref()
        .filter(|value| !value.trim().is_empty())
    {
        summary.push_str(" err=");
        summary.push_str(&truncate(err, 120));
    }

    AppState::push_bounded(
        &mut app.status,
        ObservedEvent {
            kind,
            market: update.market,
            observed_unix_ms: now_unix_ms(),
            signature: update.signature.unwrap_or_default(),
            summary,
            pump_fun_delay_secs: None,
            mint: Some(update.mint),
            pool: None,
            side: Some(update.side),
            sol_amount: None,
            token_amount: None,
            swap_detail: None,
            pump_swap_trade_kind: None,
            pump_swap_base_amount_raw: None,
            pump_swap_quote_amount_raw: None,
            pump_swap_pool_meta: None,
        },
        AppState::MAX_STATUS,
    );
}

fn trade_token_balance(app: &AppState, key: (Market, Pubkey)) -> Option<f64> {
    app.trade_token_balances
        .get(&key)
        .copied()
        .filter(|value| value.is_finite() && *value >= 0.0)
}

fn trade_pnl_reference_price(
    app: &AppState,
    key: (Market, Pubkey),
    current_price: Option<f64>,
) -> Option<f64> {
    if trade_token_balance(app, key).is_some_and(|value| value <= 0.0) {
        app.trade_frozen_pnl_price
            .get(&key)
            .copied()
            .filter(|value| value.is_finite() && *value > 0.0)
            .or(current_price)
    } else {
        current_price
    }
}

#[derive(Debug, Clone, Copy, Default)]
struct LivePositionStats {
    current_price: Option<f64>,
    buy_price: Option<f64>,
    token_balance: Option<f64>,
    profit_pct: Option<f64>,
    pnl_frozen: bool,
    token_balance_loading: bool,
}

#[derive(Debug, Clone, Copy)]
struct KnownTradeError {
    venue: &'static str,
    name: &'static str,
    message: &'static str,
    hint: &'static str,
}

fn live_position_stats(
    app: &AppState,
    key: (Market, Pubkey),
    current_price: Option<f64>,
) -> LivePositionStats {
    let current_price = current_price.filter(|value| value.is_finite() && *value > 0.0);
    let buy_price = app
        .trade_last_buy_price
        .get(&key)
        .copied()
        .filter(|value| value.is_finite() && *value > 0.0);
    let token_balance = trade_token_balance(app, key);
    let pnl_frozen = token_balance.is_some_and(|value| value <= 0.0)
        && app
            .trade_frozen_pnl_price
            .get(&key)
            .is_some_and(|value| value.is_finite() && *value > 0.0);
    let pnl_price = trade_pnl_reference_price(app, key, current_price);
    let profit_pct = match (pnl_price, buy_price) {
        (Some(current), Some(entry)) if current.is_finite() && entry.is_finite() && entry > 0.0 => {
            Some(((current - entry) / entry) * 100.0)
        }
        _ => None,
    };

    LivePositionStats {
        current_price,
        buy_price,
        token_balance,
        profit_pct,
        pnl_frozen,
        token_balance_loading: app.trade_token_balance_inflight.contains(&key),
    }
}

fn format_live_profit_pct(stats: LivePositionStats) -> String {
    let label = stats
        .profit_pct
        .filter(|value| value.is_finite())
        .map(|value| format!("{value:+.2}%"))
        .unwrap_or_else(|| "-".to_string());
    if stats.pnl_frozen && label != "-" {
        format!("{label} (closed)")
    } else {
        label
    }
}

fn active_trade_balance_lookup_key(ui: &UiState, app: &AppState) -> Option<(Market, Pubkey)> {
    if app.selected_wallet_pubkeys.is_empty() {
        return None;
    }

    match ui.screen {
        Screen::QuickTrade => ui
            .quick_trade
            .route
            .as_ref()
            .map(|route| (route.market, route.mint)),
        Screen::Monitor if app.tab_idx == TAB_TRADE => {
            app.selected_market().zip(app.selected_mint())
        }
        _ => None,
    }
}

