async fn fetch_http_trade_metadata(
    client: &reqwest::Client,
    base: &str,
    mint: &str,
    api_key: &str,
    rpc_url: Option<&str>,
) -> Option<HttpTradeTokenMetadata> {
    let path = format!("mints/{mint}/metadata");
    let mut url = build_mamba_api_url(base, &path).ok()?;
    if let Some(rpc_url) = rpc_url.map(str::trim).filter(|value| !value.is_empty()) {
        url.query_pairs_mut().append_pair("rpc_url", rpc_url);
    }
    http_json::<ApiMintMetadataResponse>(client.get(url).header("x-api-key", api_key))
        .await
        .ok()
        .map(|meta| HttpTradeTokenMetadata {
            name: meta.name,
            symbol: meta.symbol,
        })
}

fn begin_quick_trade_lookup(
    ui: &mut UiState,
    app: &AppState,
    http_url: Option<&str>,
    tx: mpsc::Sender<AppMsg>,
) {
    ui.quick_trade.error = None;
    ui.quick_trade.status = None;

    let mint_text = ui.quick_trade.mint_input.trim().to_string();
    if mint_text.is_empty() {
        ui.quick_trade.error = Some("mint is required".to_string());
        return;
    }
    if Pubkey::from_str(&mint_text).is_err() {
        ui.quick_trade.error = Some("mint must be a valid pubkey".to_string());
        return;
    }

    let base = match require_api_base_url(app.api_base_url_override.clone()) {
        Ok(value) => value,
        Err(err) => {
            ui.quick_trade.error = Some(format!("{err:#}"));
            return;
        }
    };
    let api_key = match require_api_key(app.api_key_override.clone()) {
        Ok(value) => value,
        Err(err) => {
            ui.quick_trade.error = Some(format!("{err:#}"));
            return;
        }
    };

    ui.quick_trade.lookup_inflight = true;
    ui.quick_trade.route = None;
    ui.quick_trade.metadata = None;
    ui.quick_trade.last_wallet_results.clear();
    ui.quick_trade.last_wallet_updates.clear();
    ui.quick_trade.status = Some(format!(
        "checking mint route over HTTPS on {}...",
        ui.quick_trade.network.label()
    ));
    let mint_for_request = mint_text.clone();
    let rpc_url_override = quick_trade_rpc_url_override(ui, app, http_url);
    ui.quick_trade.low_lq_confirm_pending = false;
    tokio::spawn(async move {
        let request_timeout = http_trade_lookup_request_timeout_duration();
        let result: anyhow::Result<QuickTradeLookupReady> = async {
            let client = reqwest::Client::builder()
                .timeout(request_timeout)
                .build()
                .context("build http client")?;
            let supported_csv = http_trade_market_csv(&HTTP_TRADE_MARKETS);
            let quote_mint = WSOL_MINT.to_string();
            let route_path = format!("mints/{mint_for_request}/route");
            let mut route_url = build_mamba_api_url(&base, &route_path)?;
            {
                let mut pairs = route_url.query_pairs_mut();
                pairs.append_pair("market_priority", supported_csv.as_str());
                pairs.append_pair("quote_mint", quote_mint.as_str());
                if let Some(rpc_url) = rpc_url_override.as_deref() {
                    pairs.append_pair("rpc_url", rpc_url);
                }
            }

            let metadata_future = async {
                tokio::time::timeout(
                    Duration::from_secs(2),
                    fetch_http_trade_metadata(
                        &client,
                        &base,
                        &mint_for_request,
                        &api_key,
                        rpc_url_override.as_deref(),
                    ),
                )
                .await
                .ok()
                .flatten()
            };

            let route_future = http_json::<ApiMintRouteResponse>(
                client.get(route_url).header("x-api-key", api_key.clone()),
            );

            let (route_result, metadata) = tokio::join!(route_future, metadata_future);
            match route_result {
                Ok(route) => Ok(QuickTradeLookupReady {
                    route: parse_http_trade_route(route)?,
                    metadata,
                }),
                Err(primary_error) => {
                    if rpc_url_override.is_some() {
                        return Err(primary_error);
                    }

                    let supported_rows = http_json::<Vec<ApiCachedMintView>>(
                        client
                            .get(format!("{base}/mints"))
                            .header("x-api-key", api_key.clone())
                            .query(&[
                                ("markets", supported_csv.as_str()),
                                ("q", mint_for_request.as_str()),
                                ("limit", "20"),
                            ]),
                    )
                    .await
                    .unwrap_or_default();
                    if let Some(row) = supported_rows
                        .into_iter()
                        .find(|row| row.mint.trim() == mint_for_request)
                    {
                        return Ok(QuickTradeLookupReady {
                            route: parse_http_trade_cached_mint(row)?,
                            metadata,
                        });
                    }

                    let any_rows = http_json::<Vec<ApiCachedMintView>>(
                        client
                            .get(format!("{base}/mints"))
                            .header("x-api-key", api_key.clone())
                            .query(&[("q", mint_for_request.as_str()), ("limit", "20")]),
                    )
                    .await
                    .unwrap_or_default();
                    if let Some(row) = any_rows
                        .into_iter()
                        .find(|row| row.mint.trim() == mint_for_request)
                    {
                        return Ok(QuickTradeLookupReady {
                            route: parse_http_trade_cached_mint(row)?,
                            metadata,
                        });
                    }
                    Err(primary_error)
                }
            }
        }
        .await
        .map_err(|error| {
            rewrite_http_timeout_error(error, "quick-trade route lookup", request_timeout)
        });

        match result {
            Ok(ready) => {
                let _ = tx.send(AppMsg::QuickTradeLookupReady(ready)).await;
            }
            Err(error) => {
                let _ = tx
                    .send(AppMsg::QuickTradeLookupFailed {
                        error: format!("{error:#}"),
                    })
                    .await;
            }
        }
    });
}

async fn execute_http_trade_for_wallet(
    route: HttpTradeRoute,
    side: TradeSide,
    execute: bool,
    buy_sol: f64,
    sell_pct: u64,
    slippage_pct: f64,
    retries: u32,
    priority_fee_level: Option<String>,
    priority_fee_sol: Option<f64>,
    swqos_settings: Option<SWQoSettings>,
    network: CreateNetwork,
    wallet: WalletActionTarget,
    base: &str,
    api_key: &str,
    rpc_url_override: Option<&str>,
) -> TradeExecUpdate {
    let request_timeout = http_trade_exec_request_timeout_duration();
    let response = async {
        let client = reqwest::Client::builder()
            .timeout(request_timeout)
            .build()
            .context("build http client")?;
        let market_priority = http_trade_market_csv(&HTTP_TRADE_MARKETS);
        let mut body = json!({
            "side": match side {
                TradeSide::Buy => "buy",
                TradeSide::Sell => "sell",
            },
            "mint": route.mint.to_string(),
            "market": route.market.as_str(),
            "pool": route.pool.to_string(),
            "quote_mint": WSOL_MINT.to_string(),
            "market_priority": market_priority,
            "buy_sol": (side == TradeSide::Buy).then_some(buy_sol),
            "sell_pct": (side == TradeSide::Sell).then_some(sell_pct),
            "slippage_pct": slippage_pct,
            "retries": retries,
            "execute": execute,
            "wallet": wallet.pubkey.to_string(),
            "use_swqos": swqos_settings.is_some(),
            "swqos_settings": swqos_settings.as_ref().map(|settings| json!({
                "provider": settings.provider,
                "jito_key": settings.jito_key,
                "nextblock_key": settings.nextblock_key,
                "zero_slot_key": settings.zero_slot_key,
                "temporal_key": settings.temporal_key,
                "blox_key": settings.blox_key,
                "tip_lamports": settings.tip_lamports,
            })),
        });
        if route.creator != Pubkey::default() {
            body["creator"] = json!(route.creator.to_string());
        }
        if let Some(rpc_url) = rpc_url_override
            .map(str::trim)
            .filter(|value| !value.is_empty())
        {
            body["rpc_url"] = json!(rpc_url);
        }
        if let Some(priority_fee_level) = priority_fee_level.as_deref() {
            body["priority_fee_level"] = json!(priority_fee_level);
        }
        if let Some(priority_fee_sol) = priority_fee_sol {
            body["priority_fee_sol"] = json!(priority_fee_sol);
        }
        http_json::<ApiSwapResponse>(
            client
                .post(format!("{base}/swap"))
                .header("x-api-key", api_key)
                .json(&body),
        )
        .await
    }
    .await
    .map_err(|error| {
        rewrite_http_timeout_error(error, "quick-trade swap request", request_timeout)
    });

    match response {
        Ok(result) => {
            let (resolved_route, market, warning) = match parse_http_trade_swap_route(&result) {
                Ok(resolved_route) => {
                    let market = resolved_route.market;
                    (Some(resolved_route), market, result.warning.clone())
                }
                Err(error) => {
                    let warning = match result.warning.clone() {
                        Some(existing) => Some(format!(
                            "{existing}; swap response route parse failed, using preview route: {error:#}"
                        )),
                        None => Some(format!(
                            "swap response route parse failed, using preview route: {error:#}"
                        )),
                    };
                    (None, route.market, warning)
                }
            };
            let mut signature = result
                .signature
                .as_deref()
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(str::to_string);
            let mut error = (!result.success).then(|| {
                result.error.unwrap_or_else(|| {
                    if result.executed {
                        "api swap reported unsuccessful execution".to_string()
                    } else if result.dry_run {
                        "api dry-run reported unsuccessful build".to_string()
                    } else {
                        "api swap failed".to_string()
                    }
                })
            });
            finalize_trade_exec_diagnostics(market, &mut signature, &mut error);
            TradeExecUpdate {
                wallet_pubkey: wallet.pubkey,
                wallet_label: wallet.label,
                market,
                mint: route.mint,
                resolved_route,
                network: Some(network),
                side,
                success: result.success,
                signature,
                price_sol: Some(result.price).filter(|value| value.is_finite() && *value > 0.0),
                send_requested: execute,
                requested_sell_pct: (side == TradeSide::Sell).then_some(sell_pct),
                error,
                warning,
            }
        }
        Err(error) => {
            let mut signature = None;
            let mut error = Some(format!("{error:#}"));
            finalize_trade_exec_diagnostics(route.market, &mut signature, &mut error);
            TradeExecUpdate {
                wallet_pubkey: wallet.pubkey,
                wallet_label: wallet.label,
                market: route.market,
                mint: route.mint,
                resolved_route: None,
                network: Some(network),
                side,
                success: false,
                signature,
                price_sol: Some(route.price_sol).filter(|value| value.is_finite() && *value > 0.0),
                send_requested: execute,
                requested_sell_pct: (side == TradeSide::Sell).then_some(sell_pct),
                error,
                warning: None,
            }
        }
    }
}

fn spawn_http_trade_exec_batch(
    wallets: Vec<WalletActionTarget>,
    route: HttpTradeRoute,
    side: TradeSide,
    execute: bool,
    buy_sol: f64,
    sell_pct: u64,
    slippage_pct: f64,
    retries: u32,
    priority_fee_level: Option<String>,
    priority_fee_sol: Option<f64>,
    swqos_settings: Option<SWQoSettings>,
    network: CreateNetwork,
    base: String,
    api_key: String,
    rpc_url_override: Option<String>,
    tx: mpsc::Sender<AppMsg>,
) {
    tokio::spawn(async move {
        let mut updates = Vec::new();
        for wallet in wallets {
            updates.push(
                execute_http_trade_for_wallet(
                    route.clone(),
                    side,
                    execute,
                    buy_sol,
                    sell_pct,
                    slippage_pct,
                    retries,
                    priority_fee_level.clone(),
                    priority_fee_sol,
                    swqos_settings.clone(),
                    network,
                    wallet,
                    &base,
                    &api_key,
                    rpc_url_override.as_deref(),
                )
                .await,
            );
        }
        let _ = tx.send(AppMsg::TradeExecBatch(updates)).await;
    });
}

fn begin_quick_trade_submit(
    ui: &mut UiState,
    app: &mut AppState,
    wallet_ctx: &WalletContext,
    config: &MambaClientConfig,
    http_url: Option<&str>,
    tx: mpsc::Sender<AppMsg>,
) {
    let Some(route) = ui.quick_trade.route.clone() else {
        ui.quick_trade.error = Some("check the mint route first".to_string());
        return;
    };

    let base = match require_api_base_url(app.api_base_url_override.clone()) {
        Ok(value) => value,
        Err(err) => {
            ui.quick_trade.error = Some(format!("{err:#}"));
            return;
        }
    };
    let api_key = match require_api_key(app.api_key_override.clone()) {
        Ok(value) => value,
        Err(err) => {
            ui.quick_trade.error = Some(format!("{err:#}"));
            return;
        }
    };

    let side = ui.quick_trade.side;
    let execution = ui.quick_trade.execution;
    let execute = execution == CreateExecutionMode::Live;
    let buy_sol = app.trade_buy_sol.max(0.0);
    let sell_pct = app.trade_sell_pct.clamp(1, 100);
    let slippage_pct = app.trade_slippage_pct.clamp(1.0, 99.0);
    let retries = app.trade_retries;
    let (priority_fee_level, priority_fee_sol) = match app
        .trade_priority_fee_level
        .request_fields(app.trade_priority_fee_custom_sol)
    {
        Ok(value) => value,
        Err(err) => {
            ui.quick_trade.error = Some(format!("{err:#}"));
            return;
        }
    };
    let swqos_settings = match swqos_settings_from_config(&config.mev) {
        Ok(value) => swqos_settings_for_network(value, ui.quick_trade.network).0,
        Err(err) => {
            ui.quick_trade.error = Some(format!("{err:#}"));
            return;
        }
    };

    if side == TradeSide::Buy && buy_sol <= 0.0 {
        ui.quick_trade.error = Some("buy size must be > 0".to_string());
        return;
    }

    if execute && route.low_lq && !auto_accept_low_lq_pools_from_env() {
        if !ui.quick_trade.low_lq_confirm_pending {
            ui.quick_trade.error = None;
            ui.quick_trade.low_lq_confirm_pending = true;
            ui.quick_trade.status = Some(format!(
                "low-LQ route selected: {} pool {} has {:.6} SOL WSOL quote (< 10 SOL). Press SEND again to confirm or run lookup again.",
                route.market.as_str(),
                short_pubkey(&route.pool),
                route.wsol_liquidity_sol,
            ));
            return;
        }
    } else {
        ui.quick_trade.low_lq_confirm_pending = false;
    }

    if app.trade_inflight.is_some() {
        note_trade_inflight_blocked_attempt(app);
        ui.quick_trade.error = Some("trade already in-flight".to_string());
        return;
    }

    let wallets = wallet_ctx.active_wallets();
    if wallets.is_empty() {
        ui.quick_trade.error = Some(
            wallet_ctx
                .availability_error()
                .unwrap_or_else(|| "no active wallets".to_string()),
        );
        return;
    }

    ui.quick_trade.error = None;
    ui.quick_trade.inflight = true;
    ui.quick_trade.low_lq_confirm_pending = false;
    ui.quick_trade.last_wallet_results.clear();
    ui.quick_trade.last_wallet_updates.clear();
    ui.quick_trade.status = Some(if execute {
        format!(
            "sending {} over HTTPS for {} active wallet(s) on {} ({})...",
            match side {
                TradeSide::Buy => "BUY",
                TradeSide::Sell => "SELL",
            },
            wallets.len(),
            short_pubkey(&route.mint),
            ui.quick_trade.network.label().to_ascii_uppercase(),
        )
    } else {
        format!(
            "building {} over HTTPS for {} active wallet(s) on {} ({})...",
            match side {
                TradeSide::Buy => "BUY",
                TradeSide::Sell => "SELL",
            },
            wallets.len(),
            short_pubkey(&route.mint),
            ui.quick_trade.network.label().to_ascii_uppercase(),
        )
    });
    begin_trade_inflight(app, side, route.market, route.mint);

    let rpc_url_override = quick_trade_rpc_url_override(ui, app, http_url);
    spawn_http_trade_exec_batch(
        wallets,
        route,
        side,
        execute,
        buy_sol,
        sell_pct,
        slippage_pct,
        retries,
        priority_fee_level,
        priority_fee_sol,
        swqos_settings,
        ui.quick_trade.network,
        base,
        api_key,
        rpc_url_override,
        tx,
    );
}

#[derive(Debug, Clone)]
struct TxObs {
    observed_unix_ms: u64,
    signature: String,
    side: Option<TradeSide>,
    sol_amount: Option<f64>,
    token_amount: Option<f64>,
    summary: String,
}

#[derive(Debug, Clone, Default)]
struct MintActivity {
    first_seen_unix_ms: u64,
    last_seen_unix_ms: u64,
    tx_count: u64,
    txs: VecDeque<TxObs>,
    buys: u64,
    sells: u64,
    swaps: u64,
    sol_volume: f64,
    token_volume: f64,
    last_price_sol: Option<f64>,
    highest_price_sol: Option<f64>,
}

impl MintActivity {
    const MAX_TXS: usize = 64;

    fn enrich_swap_signature(
        &mut self,
        signature: &str,
        side: Option<TradeSide>,
        sol_amount: Option<f64>,
        token_amount: Option<f64>,
    ) -> bool {
        if signature.trim().is_empty() {
            return false;
        }

        let Some(tx) = self.txs.iter_mut().find(|tx| tx.signature == signature) else {
            return false;
        };

        let mut updated = false;

        if tx.side.is_none()
            && let Some(side) = side
        {
            match side {
                TradeSide::Buy => self.buys = self.buys.saturating_add(1),
                TradeSide::Sell => self.sells = self.sells.saturating_add(1),
            }
            tx.side = Some(side);
            updated = true;
        }

        if tx.sol_amount.is_none()
            && let Some(sol_amount) = sol_amount
            && sol_amount.is_finite()
        {
            self.sol_volume += sol_amount.max(0.0);
            tx.sol_amount = Some(sol_amount);
            updated = true;
        }

        if tx.token_amount.is_none()
            && let Some(token_amount) = token_amount
            && token_amount.is_finite()
        {
            self.token_volume += token_amount.max(0.0);
            tx.token_amount = Some(token_amount);
            updated = true;
        }

        if updated
            && let (Some(sol_amount), Some(token_amount)) = (tx.sol_amount, tx.token_amount)
            && sol_amount.is_finite()
            && token_amount.is_finite()
            && token_amount > 0.0
        {
            let price = sol_amount / token_amount;
            if price.is_finite() && price > 0.0 {
                self.last_price_sol = Some(price);
                let prev = self.highest_price_sol.unwrap_or(price);
                self.highest_price_sol = Some(prev.max(price));
            }
        }

        updated
    }

    fn observe(&mut self, event: &ObservedEvent) {
        if self.first_seen_unix_ms == 0 {
            self.first_seen_unix_ms = event.observed_unix_ms;
        }
        self.last_seen_unix_ms = self.last_seen_unix_ms.max(event.observed_unix_ms);

        match event.kind {
            EventKind::Mint => {}
            EventKind::Swap => {
                self.swaps = self.swaps.saturating_add(1);
                match event.side {
                    Some(TradeSide::Buy) => self.buys = self.buys.saturating_add(1),
                    Some(TradeSide::Sell) => self.sells = self.sells.saturating_add(1),
                    None => {}
                }

                if let Some(sol_amount) = event.sol_amount {
                    self.sol_volume += sol_amount.max(0.0);
                }
                if let Some(token_amount) = event.token_amount {
                    self.token_volume += token_amount.max(0.0);
                }

                if let (Some(sol_amount), Some(token_amount)) =
                    (event.sol_amount, event.token_amount)
                    && sol_amount.is_finite()
                    && token_amount.is_finite()
                    && token_amount > 0.0
                {
                    let price = sol_amount / token_amount;
                    if price.is_finite() && price > 0.0 {
                        self.last_price_sol = Some(price);
                        let prev = self.highest_price_sol.unwrap_or(price);
                        self.highest_price_sol = Some(prev.max(price));
                    }
                }
            }
            EventKind::Status | EventKind::Warning => {}
        }

        if !event.signature.trim().is_empty() {
            let already_seen = self.txs.iter().any(|tx| tx.signature == event.signature);
            if !already_seen {
                self.tx_count = self.tx_count.saturating_add(1);
                self.txs.push_front(TxObs {
                    observed_unix_ms: event.observed_unix_ms,
                    signature: event.signature.clone(),
                    side: event.side,
                    sol_amount: event.sol_amount,
                    token_amount: event.token_amount,
                    summary: event.summary.clone(),
                });
                while self.txs.len() > Self::MAX_TXS {
                    self.txs.pop_back();
                }
            }
        }
    }

    fn observe_price(&mut self, observed_unix_ms: u64, price_sol: f64) {
        if self.first_seen_unix_ms == 0 {
            self.first_seen_unix_ms = observed_unix_ms;
        }
        self.last_seen_unix_ms = self.last_seen_unix_ms.max(observed_unix_ms);

        if price_sol.is_finite() && price_sol > 0.0 {
            self.last_price_sol = Some(price_sol);
            let prev = self.highest_price_sol.unwrap_or(price_sol);
            self.highest_price_sol = Some(prev.max(price_sol));
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum MintSortMode {
    CreationTime,
    HighestTxs,
    Price,
}

#[derive(Debug, Clone, Copy)]
struct MintSortConfig {
    mode: MintSortMode,
    descending: bool,
}

impl Default for MintSortConfig {
    fn default() -> Self {
        Self {
            mode: MintSortMode::CreationTime,
            descending: true,
        }
    }
}

fn raw_amount_to_ui(amount_raw: u64, decimals: u8) -> f64 {
    let scale = 10_f64.powi(i32::from(decimals));
    (amount_raw as f64) / scale
}

fn pump_swap_token_and_sol_meta(meta: &PumpSwapPoolMeta) -> Option<(bool, Pubkey, u8, u8)> {
    if meta.quote_mint == WSOL_MINT && meta.base_mint != WSOL_MINT {
        return Some((
            true,
            meta.base_mint,
            meta.base_decimals,
            meta.quote_decimals,
        ));
    }
    if meta.base_mint == WSOL_MINT && meta.quote_mint != WSOL_MINT {
        return Some((
            false,
            meta.quote_mint,
            meta.quote_decimals,
            meta.base_decimals,
        ));
    }
    None
}

fn normalize_pump_swap_swap_event(event: &mut ObservedEvent, meta: &PumpSwapPoolMeta) {
    if event.market != Market::PumpSwap || event.kind != EventKind::Swap {
        return;
    }
    let Some(pool) = event.pool else {
        return;
    };
    let Some(trade_kind) = event.pump_swap_trade_kind else {
        return;
    };
    let Some(base_raw) = event.pump_swap_base_amount_raw else {
        return;
    };
    let Some(quote_raw) = event.pump_swap_quote_amount_raw else {
        return;
    };

    let Some((token_is_base, token_mint, token_decimals, sol_decimals)) =
        pump_swap_token_and_sol_meta(meta)
    else {
        return;
    };

    if event.mint.is_none() {
        event.mint = Some(token_mint);
    }

    let (token_raw, sol_raw) = if token_is_base {
        (base_raw, quote_raw)
    } else {
        (quote_raw, base_raw)
    };

    let token_amount = raw_amount_to_ui(token_raw, token_decimals);
    let sol_amount = raw_amount_to_ui(sol_raw, sol_decimals);
    if !token_amount.is_finite() || !sol_amount.is_finite() {
        return;
    }

    event.token_amount = Some(token_amount);
    event.sol_amount = Some(sol_amount);

    let side = if token_is_base {
        match trade_kind {
            PumpSwapTradeKind::Buy => TradeSide::Buy,
            PumpSwapTradeKind::Sell => TradeSide::Sell,
        }
    } else {
        match trade_kind {
            PumpSwapTradeKind::Buy => TradeSide::Sell,
            PumpSwapTradeKind::Sell => TradeSide::Buy,
        }
    };
    event.side = Some(side);

    let (side_text, tok_label, sol_label) = match side {
        TradeSide::Buy => ("BUY", "tok_out", "sol_in"),
        TradeSide::Sell => ("SELL", "tok_in", "sol_out"),
    };
    event.summary = format!(
        "{} pool={} {}={:.6} {}={:.6}",
        side_text,
        short_pubkey(&pool),
        tok_label,
        token_amount,
        sol_label,
        sol_amount
    );
}

