fn draw_mev_setup(f: &mut ratatui::Frame<'_>, ui: &UiState, app: &AppState) {
    let area = f.area();
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(5),
            Constraint::Min(0),
            Constraint::Length(1),
        ])
        .split(area);

    let header = Paragraph::new(vec![
        Line::from(Span::styled(
            "MEV / SWQoS Setup",
            Style::default().fg(UI_ACCENT).add_modifier(Modifier::BOLD),
        )),
        Line::from(wallet_status_line(app, chunks[0].width as usize)),
        Line::from(Span::styled(
            if ui.mev_setup.startup_required {
                "Choose one active provider, store any keys you need, or skip once."
            } else {
                "Choose one active provider and store the keys you want available."
            },
            Style::default().fg(UI_DIM),
        )),
    ])
    .block(ui_card_plain())
    .wrap(Wrap { trim: true });
    f.render_widget(header, chunks[0]);

    let body_width = chunks[1].width.saturating_sub(2) as usize;
    let prefix = |field: MevSetupField| {
        if ui.mev_setup.field == field {
            Span::styled(
                "▸ ",
                Style::default()
                    .fg(UI_HIGHLIGHT)
                    .add_modifier(Modifier::BOLD),
            )
        } else {
            Span::styled("  ", Style::default().fg(UI_DIM))
        }
    };
    let label_style = |field: MevSetupField| {
        if ui.mev_setup.field == field {
            Style::default()
                .fg(UI_HIGHLIGHT)
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default()
        }
    };
    let input_line = |field: MevSetupField, label: &str, value: &str, hint: &str| -> Line {
        let mut spans = vec![
            prefix(field),
            Span::styled(format!("{label}: "), label_style(field)),
        ];
        let trimmed = value.trim();
        if trimmed.is_empty() {
            spans.push(Span::styled(hint.to_string(), Style::default().fg(UI_DIM)));
        } else {
            spans.push(Span::raw(truncate(
                trimmed,
                body_width.saturating_sub(label.len() + 4),
            )));
        }
        if ui.mev_setup.field == field {
            spans.push(Span::styled("|", Style::default().fg(UI_HIGHLIGHT)));
        }
        Line::from(spans)
    };

    let mut provider_spans = vec![
        prefix(MevSetupField::Provider),
        Span::styled("provider (←/→): ", label_style(MevSetupField::Provider)),
    ];
    for (idx, provider) in SwqosProvider::ALL.iter().enumerate() {
        if idx > 0 {
            provider_spans.push(Span::raw("  "));
        }
        let selected = *provider == ui.mev_setup.provider;
        provider_spans.push(Span::styled(
            if selected {
                format!("[{}]", provider.label())
            } else {
                provider.label().to_string()
            },
            if selected {
                Style::default()
                    .fg(UI_HIGHLIGHT)
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(UI_DIM)
            },
        ));
    }

    let cancel_label = if ui.mev_setup.startup_required {
        "SKIP"
    } else {
        "CANCEL"
    };
    let mut lines = vec![
        Line::from(provider_spans),
        Line::from(""),
        input_line(
            MevSetupField::JitoKey,
            "jito_key",
            &ui.mev_setup.jito_key,
            "<optional>",
        ),
        input_line(
            MevSetupField::NextBlockKey,
            "nextblock_key",
            &ui.mev_setup.nextblock_key,
            "<required for nextblock>",
        ),
        input_line(
            MevSetupField::ZeroSlotKey,
            "zero_slot_key",
            &ui.mev_setup.zero_slot_key,
            "<required for zero_slot>",
        ),
        input_line(
            MevSetupField::TemporalKey,
            "temporal_key",
            &ui.mev_setup.temporal_key,
            "<required for temporal>",
        ),
        input_line(
            MevSetupField::BloxKey,
            "blox_key",
            &ui.mev_setup.blox_key,
            "<required for bloxroute>",
        ),
        Line::from(""),
        Line::from(vec![
            prefix(MevSetupField::Save),
            Span::styled(
                format!("[SAVE] [{cancel_label}]"),
                if matches!(
                    ui.mev_setup.field,
                    MevSetupField::Save | MevSetupField::Cancel
                ) {
                    Style::default()
                        .fg(UI_HIGHLIGHT)
                        .add_modifier(Modifier::BOLD)
                } else {
                    Style::default()
                },
            ),
        ]),
        Line::from(Span::styled(
            truncate(
                &format!(
                    "active provider after save: {}",
                    ui.mev_setup.provider.label()
                ),
                body_width,
            ),
            Style::default().fg(UI_DIM),
        )),
        Line::from(Span::styled(
            "Tab/Shift+Tab navigate, Enter saves, Esc returns, F4 reopens later.",
            Style::default().fg(UI_DIM),
        )),
    ];
    if let Some(status) = ui.mev_setup.status.as_deref() {
        lines.push(Line::from(Span::styled(
            truncate(status, body_width),
            Style::default().fg(UI_DIM),
        )));
    }
    if let Some(error) = ui.mev_setup.error.as_deref() {
        lines.push(Line::from(Span::styled(
            truncate(error, body_width),
            Style::default().fg(UI_ERROR),
        )));
    }

    let body = Paragraph::new(lines)
        .block(ui_card("Setup"))
        .wrap(Wrap { trim: false });
    f.render_widget(body, chunks[1]);

    let footer = Paragraph::new("F1 help")
        .style(Style::default().fg(UI_DIM))
        .alignment(Alignment::Center);
    f.render_widget(footer, chunks[2]);
}

