async fn send_and_confirm(
    rpc: &RpcClient,
    tx: &VersionedTransaction,
    label: &str,
) -> anyhow::Result<Signature> {
    let sig = rpc
        .send_transaction_with_config(
            tx,
            solana_client::rpc_config::RpcSendTransactionConfig {
                skip_preflight: false,
                preflight_commitment: Some(CommitmentLevel::Processed),
                encoding: None,
                max_retries: Some(3),
                min_context_slot: None,
            },
        )
        .await
        .with_context(|| format!("sendTransaction failed ({label})"))?;
    for _ in 0..60u32 {
        if rpc
            .confirm_transaction_with_commitment(&sig, CommitmentConfig::confirmed())
            .await
            .ok()
            .is_some_and(|v| v.value)
        {
            return Ok(sig);
        }
        tokio::time::sleep(Duration::from_millis(500)).await;
    }
    bail!("tx did not confirm in time ({label}): {sig}");
}

async fn create_spl_mint_and_mint_to_payer(
    rpc: &RpcClient,
    payer: &Keypair,
    decimals: u8,
    mint_amount_raw: u64,
) -> anyhow::Result<(Pubkey, Signature)> {
    let mint_kp = Keypair::new();
    let mint = mint_kp.pubkey();

    let mint_space = spl_token::state::Mint::LEN;
    let mint_rent = rpc
        .get_minimum_balance_for_rent_exemption(mint_space)
        .await
        .context("rpc getMinimumBalanceForRentExemption(mint) failed")?;

    let payer_pk = payer.pubkey();
    let payer_ata =
        derive_associated_token_address(&payer_pk, &mint, &mamba::core::sol::TOKEN_PROGRAM_ID);

    let mut instructions = Vec::new();
    instructions.push(system_instruction_if::create_account(
        &payer_pk,
        &mint,
        mint_rent,
        mint_space as u64,
        &mamba::core::sol::TOKEN_PROGRAM_ID,
    ));
    instructions.push(
        spl_token::instruction::initialize_mint(
            &mamba::core::sol::TOKEN_PROGRAM_ID,
            &mint,
            &payer_pk,
            Some(&payer_pk),
            decimals,
        )
        .context("build initialize_mint ix")?,
    );
    instructions.push(create_associated_token_account_idempotent(
        &payer_pk,
        &payer_pk,
        &mint,
        &mamba::core::sol::TOKEN_PROGRAM_ID,
    ));
    if mint_amount_raw > 0 {
        instructions.push(
            spl_token::instruction::mint_to(
                &mamba::core::sol::TOKEN_PROGRAM_ID,
                &mint,
                &payer_ata,
                &payer_pk,
                &[],
                mint_amount_raw,
            )
            .context("build mint_to ix")?,
        );
    }

    let blockhash = rpc
        .get_latest_blockhash_with_commitment(CommitmentConfig::processed())
        .await
        .context("rpc getLatestBlockhash failed")?
        .0;
    let unsigned = compile_unsigned_v0_transaction(&payer_pk, &instructions, blockhash)?;
    let signed = VersionedTransaction::try_new(unsigned.message.clone(), &[payer, &mint_kp])
        .context("sign mint create tx")?;

    let sig = send_and_confirm(rpc, &signed, "create_spl_mint").await?;
    Ok((mint, sig))
}

fn find_openbook_vault_signer(
    openbook_program_id: &Pubkey,
    market: &Pubkey,
) -> anyhow::Result<(Pubkey, u64)> {
    for nonce in 0u64..10_000u64 {
        let seed = nonce.to_le_bytes();
        if let Ok(vault_signer) =
            Pubkey::create_program_address(&[market.as_ref(), seed.as_ref()], openbook_program_id)
        {
            return Ok((vault_signer, nonce));
        }
    }
    bail!("failed to find openbook vault signer nonce");
}

fn openbook_initialize_market_ix(
    openbook_program_id: Pubkey,
    market: Pubkey,
    req_q: Pubkey,
    event_q: Pubkey,
    bids: Pubkey,
    asks: Pubkey,
    coin_vault: Pubkey,
    pc_vault: Pubkey,
    coin_mint: Pubkey,
    pc_mint: Pubkey,
    coin_lot_size: u64,
    pc_lot_size: u64,
    vault_signer_nonce: u64,
    pc_dust_threshold: u64,
) -> Instruction {
    // openbook-dex: bincode((0u8, MarketInstruction::InitializeMarket(InitializeMarketInstruction{...})))
    // Layout observed in `MarketInstruction::unpack`: [version:u8][discrim:u32][fields..]
    let mut data = Vec::with_capacity(39);
    data.push(0u8); // version
    data.extend_from_slice(&0u32.to_le_bytes()); // InitializeMarket discrim
    data.extend_from_slice(&coin_lot_size.to_le_bytes());
    data.extend_from_slice(&pc_lot_size.to_le_bytes());
    data.extend_from_slice(&0u16.to_le_bytes()); // fee_rate_bps
    data.extend_from_slice(&vault_signer_nonce.to_le_bytes());
    data.extend_from_slice(&pc_dust_threshold.to_le_bytes());

    Instruction {
        program_id: openbook_program_id,
        accounts: vec![
            AccountMeta::new(market, false),
            AccountMeta::new(req_q, false),
            AccountMeta::new(event_q, false),
            AccountMeta::new(bids, false),
            AccountMeta::new(asks, false),
            AccountMeta::new(coin_vault, false),
            AccountMeta::new(pc_vault, false),
            AccountMeta::new_readonly(coin_mint, false),
            AccountMeta::new_readonly(pc_mint, false),
            AccountMeta::new_readonly(mamba::core::create::RENT_SYSVAR_ID, false),
        ],
        data,
    }
}

async fn create_openbook_market(
    rpc: &RpcClient,
    payer: &Keypair,
    openbook_program_id: Pubkey,
    coin_mint: Pubkey,
    pc_mint: Pubkey,
) -> anyhow::Result<(Pubkey, Signature)> {
    // Minimal sizes that satisfy openbook-dex `process_initialize_market` checks:
    // - request queue must fit >=1 Request
    // - event queue must fit >=128 Events
    // - bids/asks slab must have nodes.len() > 200
    const MARKET_LEN: usize = 388;
    const REQ_Q_LEN: usize = 124; // 12 (padding) + 32 (hdr) + 80 (1 Request)
    const EVENT_Q_LEN: usize = 11_308; // 12 (padding) + 32 (hdr) + 128*88 (Events)
    const BIDS_LEN: usize = 14_524; // 12 (padding) + 8 (ob hdr) + (32 + 201*72) (slab)
    const ASKS_LEN: usize = 14_524;

    let payer_pk = payer.pubkey();

    let market_kp = Keypair::new();
    let req_q_kp = Keypair::new();
    let event_q_kp = Keypair::new();
    let bids_kp = Keypair::new();
    let asks_kp = Keypair::new();

    let market = market_kp.pubkey();
    let (vault_signer, vault_signer_nonce) =
        find_openbook_vault_signer(&openbook_program_id, &market)?;

    let coin_vault = derive_associated_token_address(
        &vault_signer,
        &coin_mint,
        &mamba::core::sol::TOKEN_PROGRAM_ID,
    );
    let pc_vault = derive_associated_token_address(
        &vault_signer,
        &pc_mint,
        &mamba::core::sol::TOKEN_PROGRAM_ID,
    );

    let market_rent = rpc
        .get_minimum_balance_for_rent_exemption(MARKET_LEN)
        .await
        .context("rent exemption fetch failed (market)")?;
    let req_q_rent = rpc
        .get_minimum_balance_for_rent_exemption(REQ_Q_LEN)
        .await
        .context("rent exemption fetch failed (req_q)")?;
    let event_q_rent = rpc
        .get_minimum_balance_for_rent_exemption(EVENT_Q_LEN)
        .await
        .context("rent exemption fetch failed (event_q)")?;
    let bids_rent = rpc
        .get_minimum_balance_for_rent_exemption(BIDS_LEN)
        .await
        .context("rent exemption fetch failed (bids)")?;
    let asks_rent = rpc
        .get_minimum_balance_for_rent_exemption(ASKS_LEN)
        .await
        .context("rent exemption fetch failed (asks)")?;

    // Split into multiple txns to stay under the v0 txn size limit.
    let create_accounts = vec![
        system_instruction_if::create_account(
            &payer_pk,
            &market,
            market_rent,
            MARKET_LEN as u64,
            &openbook_program_id,
        ),
        system_instruction_if::create_account(
            &payer_pk,
            &req_q_kp.pubkey(),
            req_q_rent,
            REQ_Q_LEN as u64,
            &openbook_program_id,
        ),
        system_instruction_if::create_account(
            &payer_pk,
            &event_q_kp.pubkey(),
            event_q_rent,
            EVENT_Q_LEN as u64,
            &openbook_program_id,
        ),
        system_instruction_if::create_account(
            &payer_pk,
            &bids_kp.pubkey(),
            bids_rent,
            BIDS_LEN as u64,
            &openbook_program_id,
        ),
        system_instruction_if::create_account(
            &payer_pk,
            &asks_kp.pubkey(),
            asks_rent,
            ASKS_LEN as u64,
            &openbook_program_id,
        ),
    ];
    let blockhash = rpc
        .get_latest_blockhash_with_commitment(CommitmentConfig::processed())
        .await
        .context("rpc getLatestBlockhash failed")?
        .0;
    let unsigned = compile_unsigned_v0_transaction(&payer_pk, &create_accounts, blockhash)?;
    let signed = VersionedTransaction::try_new(
        unsigned.message.clone(),
        &[
            payer,
            &market_kp,
            &req_q_kp,
            &event_q_kp,
            &bids_kp,
            &asks_kp,
        ],
    )
    .context("sign openbook create accounts tx")?;
    let _sig_accounts = send_and_confirm(rpc, &signed, "openbook_create_accounts").await?;

    let create_vault_atas = vec![
        create_associated_token_account_idempotent(
            &payer_pk,
            &vault_signer,
            &coin_mint,
            &mamba::core::sol::TOKEN_PROGRAM_ID,
        ),
        create_associated_token_account_idempotent(
            &payer_pk,
            &vault_signer,
            &pc_mint,
            &mamba::core::sol::TOKEN_PROGRAM_ID,
        ),
    ];
    let blockhash = rpc
        .get_latest_blockhash_with_commitment(CommitmentConfig::processed())
        .await
        .context("rpc getLatestBlockhash failed")?
        .0;
    let unsigned = compile_unsigned_v0_transaction(&payer_pk, &create_vault_atas, blockhash)?;
    let signed = VersionedTransaction::try_new(unsigned.message.clone(), &[payer])
        .context("sign openbook create vault atas tx")?;
    let _sig_vaults = send_and_confirm(rpc, &signed, "openbook_create_vault_atas").await?;

    let init_market = vec![openbook_initialize_market_ix(
        openbook_program_id,
        market,
        req_q_kp.pubkey(),
        event_q_kp.pubkey(),
        bids_kp.pubkey(),
        asks_kp.pubkey(),
        coin_vault,
        pc_vault,
        coin_mint,
        pc_mint,
        1_000_000, // coin_lot_size (1e6 base atoms)
        1_000_000, // pc_lot_size (1e6 quote atoms)
        vault_signer_nonce,
        100, // pc_dust_threshold
    )];
    let blockhash = rpc
        .get_latest_blockhash_with_commitment(CommitmentConfig::processed())
        .await
        .context("rpc getLatestBlockhash failed")?
        .0;
    let unsigned = compile_unsigned_v0_transaction(&payer_pk, &init_market, blockhash)?;
    let signed = VersionedTransaction::try_new(unsigned.message.clone(), &[payer])
        .context("sign openbook init market tx")?;
    let sig = send_and_confirm(rpc, &signed, "openbook_initialize_market").await?;

    // Sanity check: mint offsets used by pool builder must match.
    let acc = rpc
        .get_account_with_commitment(&market, CommitmentConfig::processed())
        .await
        .context("rpc getAccount(openbook market) failed")?
        .value
        .context("openbook market account missing after init")?;
    anyhow::ensure!(
        acc.owner == openbook_program_id,
        "openbook market owner mismatch: {}",
        acc.owner
    );
    anyhow::ensure!(
        acc.data.len() >= mamba::dex::raydium_amm_v4::OPENBOOK_V3_MARKET_MIN_LEN,
        "openbook market account too short: {}",
        acc.data.len()
    );
    let read_pk = |offset: usize| -> anyhow::Result<Pubkey> {
        let bytes = acc
            .data
            .get(offset..offset + 32)
            .with_context(|| format!("missing pubkey at offset {offset}"))?;
        Ok(Pubkey::new_from_array(bytes.try_into()?))
    };
    let got_coin = read_pk(mamba::dex::raydium_amm_v4::OPENBOOK_V3_MARKET_BASE_MINT_OFFSET)?;
    let got_pc = read_pk(mamba::dex::raydium_amm_v4::OPENBOOK_V3_MARKET_QUOTE_MINT_OFFSET)?;
    anyhow::ensure!(
        got_coin == coin_mint && got_pc == pc_mint,
        "openbook market mint mismatch (coin={} pc={})",
        got_coin,
        got_pc
    );

    Ok((market, sig))
}

async fn run_pool_suite(
    http_url: Option<String>,
    setup_send: bool,
    send: bool,
    api_base_url_override: Option<String>,
    api_key_override: Option<String>,
) -> anyhow::Result<()> {
    let base = require_api_base_url(api_base_url_override)?;
    let api_key = require_api_key(api_key_override)?;

    let keep_running = env_truthy("MAMBA_CLIENT_KEEP_API_RUNNING");
    let _mamba_api_guard = ensure_mamba_api_up(&base, &api_key, keep_running, |line| {
        eprintln!("{line}");
    })
    .await
    .map_err(|err| anyhow::anyhow!("{}", err.error))?
    .api_child;

    let rpc_url = http_url
        .as_deref()
        .map(str::trim)
        .filter(|v| !v.is_empty())
        .context("--pool-suite requires --http-url (or MAMBA_API_HTTP_URLS env)")?
        .to_string();
    let rpc_url_redacted = redact_url_for_artifact(&rpc_url);
    let rpc = RpcClient::new(rpc_url.clone());

    let genesis_hash = rpc
        .get_genesis_hash()
        .await
        .context("rpc getGenesisHash failed")?;
    let cluster = mamba::core::cluster::SolanaCluster::from_genesis_hash(&genesis_hash.to_string());
    anyhow::ensure!(
        cluster == mamba::core::cluster::SolanaCluster::Devnet,
        "refusing to run pool-suite: rpc cluster mismatch (expected devnet got {:?})",
        cluster
    );
    let setup_send = setup_send || send;
    eprintln!(
        "pool-suite mode={} setup_send={setup_send}",
        if send { "send" } else { "simulate" }
    );

    // Pool-suite is a deterministic devnet smoke test. Default behavior is build+simulate (no
    // sends) to minimize devnet SOL usage. Live sends are only performed when `--pool-suite-send`
    // is set.
    let payer = load_signer_keypair_from_env()?
        .context("pool-suite requires a signer (set MAMBA_PRIVATE_KEY)")?;
    eprintln!("pool-suite payer={}", payer.pubkey());

    let balance = rpc
        .get_balance(&payer.pubkey())
        .await
        .context("rpc getBalance failed")?;
    eprintln!("pool-suite payer balance={} lamports", balance);
    let min_lamports = if send {
        8_000_000_000 // full send-mode (pool+create txs)
    } else if setup_send {
        2_000_000_000 // setup-send mode (mint+openbook rent)
    } else {
        500_000_000 // simulate-only (no sends)
    };
    anyhow::ensure!(
        balance >= min_lamports,
        "pool-suite requires >= {:.2} SOL (balance={} lamports)",
        (min_lamports as f64) / 1e9,
        balance
    );

    // Load cached suite base mint + OpenBook market. If missing, only create it when
    // `--pool-suite-setup-send` is set (to avoid surprise devnet SOL spend).
    #[derive(Debug, Deserialize, Serialize)]
    struct PoolSuiteCache {
        cluster: String,
        payer: String,
        base_mint: String,
        base_mint_create_signature: Option<String>,
        openbook_market: String,
        openbook_market_create_signature: Option<String>,
    }

    let cache_path = PathBuf::from("artifacts/tmp/pool_suite_cache.json");
    let cached: Option<PoolSuiteCache> = fs::read(&cache_path)
        .ok()
        .and_then(|bytes| serde_json::from_slice::<PoolSuiteCache>(&bytes).ok())
        .filter(|c| c.cluster.trim() == "devnet" && c.payer.trim() == payer.pubkey().to_string());

    let (suite_base_mint, base_mint_sig, openbook_market, openbook_sig) = if let Some(cached) =
        cached
    {
        let base_mint = Pubkey::from_str(cached.base_mint.trim())
            .context("pool-suite cache base_mint invalid")?;
        let openbook_market = Pubkey::from_str(cached.openbook_market.trim())
            .context("pool-suite cache openbook_market invalid")?;
        (
            base_mint,
            cached.base_mint_create_signature,
            openbook_market,
            cached.openbook_market_create_signature,
        )
    } else {
        anyhow::ensure!(
            setup_send,
            "pool-suite setup cache missing: run once with --pool-suite --pool-suite-setup-send to create/cache a base mint + OpenBook market (cache: {})",
            cache_path.display()
        );
        let (suite_base_mint, base_mint_sig) =
            create_spl_mint_and_mint_to_payer(&rpc, payer.as_ref(), 6, 10_000_000_000).await?;
        eprintln!(
            "pool-suite base_mint={} (sig={})",
            suite_base_mint, base_mint_sig
        );

        let openbook_program_id = mamba::core::cluster::raydium_amm_v4_openbook_program_id(
            mamba::core::cluster::SolanaCluster::Devnet,
        );
        let (openbook_market, openbook_sig) = create_openbook_market(
            &rpc,
            payer.as_ref(),
            openbook_program_id,
            suite_base_mint,
            WSOL_MINT,
        )
        .await?;
        eprintln!(
            "pool-suite openbook_market={} (sig={})",
            openbook_market, openbook_sig
        );

        fs::create_dir_all("artifacts/tmp").ok();
        let cache = PoolSuiteCache {
            cluster: "devnet".to_string(),
            payer: payer.pubkey().to_string(),
            base_mint: suite_base_mint.to_string(),
            base_mint_create_signature: Some(base_mint_sig.to_string()),
            openbook_market: openbook_market.to_string(),
            openbook_market_create_signature: Some(openbook_sig.to_string()),
        };
        let _ = fs::write(
            &cache_path,
            serde_json::to_vec_pretty(&cache).unwrap_or_default(),
        );

        (
            suite_base_mint,
            Some(base_mint_sig.to_string()),
            openbook_market,
            Some(openbook_sig.to_string()),
        )
    };

    if rpc
        .get_account_with_commitment(&suite_base_mint, CommitmentConfig::processed())
        .await
        .ok()
        .and_then(|v| v.value)
        .is_none()
    {
        bail!(
            "pool-suite cache base_mint does not exist on-chain: {suite_base_mint} (delete {} and re-run with --pool-suite-setup-send)",
            cache_path.display()
        );
    }
    if rpc
        .get_account_with_commitment(&openbook_market, CommitmentConfig::processed())
        .await
        .ok()
        .and_then(|v| v.value)
        .is_none()
    {
        bail!(
            "pool-suite cache openbook_market does not exist on-chain: {openbook_market} (delete {} and re-run with --pool-suite-setup-send)",
            cache_path.display()
        );
    }

    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(60))
        .build()
        .context("build http client")?;

    let timestamp = chrono::Utc::now().format("%Y%m%dT%H%M%SZ").to_string();
    let mut results: Vec<PoolSuiteMarketResult> = Vec::new();

    let base_ref = base.as_str();
    let api_key_ref = api_key.as_str();
    let rpc_url_ref = rpc_url.as_str();

    let run_pool_market = |market: Market,
                           base_amount: Option<&str>,
                           quote_amount: Option<&str>,
                           initial_price: Option<&str>,
                           raydium_amm_v4_market: Option<Pubkey>| {
        let base_amount = base_amount.map(|v| v.to_string());
        let quote_amount = quote_amount.map(|v| v.to_string());
        let initial_price = initial_price.map(|v| v.to_string());
        let payer = payer.clone();
        async move {
            let res = build_create_pool_via_api_and_sign(
                market,
                CreateNetwork::Devnet,
                Some(suite_base_mint),
                Some(WSOL_MINT),
                base_amount,
                quote_amount,
                initial_price,
                None,
                false,
                None,
                raydium_amm_v4_market,
                None,
                None,
                None,
                None,
                None,
                None,
                Some("Suite DBC".to_string()),
                Some("SUITEDBC".to_string()),
                Some("https://example.com".to_string()),
                None,
                base_ref,
                api_key_ref,
                payer,
                Some(rpc_url_ref),
                send,
                send,
                send,
            )
            .await;

            match res {
                Ok(finished) => PoolSuiteMarketResult {
                    market: market.as_str().to_string(),
                    ok: if send {
                        finished.send_error.is_none()
                            && finished.confirm_ok.unwrap_or(false)
                            && finished.verify_ok.unwrap_or(false)
                    } else {
                        finished.server_sim_ok.unwrap_or(false)
                            && finished.signed_sim_ok.unwrap_or(false)
                    },
                    signature: finished.send_sig.clone(),
                    pool: finished.pool.map(|v| v.to_string()),
                    mint: Some(finished.base_mint.to_string()),
                    bundle: Some(finished.out_dir.display().to_string()),
                    error: finished.send_error.clone(),
                },
                Err(err) => PoolSuiteMarketResult {
                    market: market.as_str().to_string(),
                    ok: false,
                    signature: None,
                    pool: None,
                    mint: Some(suite_base_mint.to_string()),
                    bundle: None,
                    error: Some(format!("{err:#}")),
                },
            }
        }
    };

    // Pool builders (8/10).
    //
    // Note: Meteora DLMM currently enforces a "token launch owner proof" check. Run it before
    // builders that seed liquidity and reduce the payer's base token balance.
    results.push(run_pool_market(Market::RaydiumClmm, None, None, Some("1"), None).await);
    results.push(run_pool_market(Market::MeteoraDlmm, None, None, Some("1"), None).await);

    results.push(run_pool_market(Market::PumpSwap, Some("1000"), Some("0.05"), None, None).await);
    results
        .push(run_pool_market(Market::RaydiumCpmm, Some("1000"), Some("0.05"), None, None).await);
    results.push(
        run_pool_market(
            Market::MeteoraDammV1,
            Some("1000"),
            Some("0.05"),
            None,
            None,
        )
        .await,
    );
    results.push(
        run_pool_market(
            Market::MeteoraDammV2,
            Some("1000"),
            Some("0.05"),
            Some("1"),
            None,
        )
        .await,
    );
    results.push(run_pool_market(Market::MeteoraDbc, None, None, None, None).await);
    results.push(
        run_pool_market(
            Market::RaydiumAmmV4,
            Some("1000"),
            Some("0.05"),
            None,
            Some(openbook_market),
        )
        .await,
    );

    // Pump.fun + Raydium Launchpad (2/10): pool creation is coupled to token launch.
    let create_token = |method: CreateMethod, raydium_launchpad: Option<serde_json::Value>| {
        let payer = payer.clone();
        async move {
            let res = build_create_via_api_and_sign(
                method,
                format!("PoolSuite {}", method.as_api_str()),
                "SUITE".to_string(),
                "https://example.com".to_string(),
                raydium_launchpad,
                if method == CreateMethod::RaydiumLaunchpad {
                    Some(RaydiumBaseTokenProgram::SplToken)
                } else {
                    None
                },
                None,
                None,
                None,
                None,
                None,
                None,
                true,
                None,
                if method == CreateMethod::RaydiumLaunchpad {
                    Some(6)
                } else {
                    None
                },
                None,
                base_ref,
                api_key_ref,
                payer,
                Some(rpc_url_ref),
                send,
                send,
                send,
            )
            .await;

            match res {
                Ok(finished) => PoolSuiteMarketResult {
                    market: method.as_api_str().to_string(),
                    ok: if send {
                        finished.send_error.is_none()
                            && finished.confirm_ok.unwrap_or(false)
                            && finished.verify_ok.unwrap_or(false)
                    } else {
                        finished.server_sim_ok.unwrap_or(false)
                            && finished.signed_sim_ok.unwrap_or(false)
                    },
                    signature: finished.send_sig.clone(),
                    pool: None,
                    mint: Some(finished.mint.to_string()),
                    bundle: Some(finished.out_dir.display().to_string()),
                    error: finished.send_error.clone(),
                },
                Err(err) => PoolSuiteMarketResult {
                    market: method.as_api_str().to_string(),
                    ok: false,
                    signature: None,
                    pool: None,
                    mint: None,
                    bundle: None,
                    error: Some(format!("{err:#}")),
                },
            }
        }
    };

    results.push(create_token(CreateMethod::PumpFun, None).await);

    let raydium_launchpad_params: anyhow::Result<serde_json::Value> = async {
        let mut globals_url =
            build_mamba_api_url(&base, "create/raydium_launchpad/global-configs")?;
        globals_url
            .query_pairs_mut()
            .append_pair("rpc_url", &rpc_url);
        let globals: Vec<RaydiumLaunchpadGlobalConfigResponse> =
            http_json(client.get(globals_url).header("x-api-key", &api_key)).await?;
        anyhow::ensure!(
            !globals.is_empty(),
            "raydium launchpad: no global configs found"
        );

        let mut platforms_url =
            build_mamba_api_url(&base, "create/raydium_launchpad/platform-configs")?;
        platforms_url
            .query_pairs_mut()
            .append_pair("rpc_url", &rpc_url);
        let platforms: Vec<RaydiumLaunchpadPlatformConfigResponse> =
            http_json(client.get(platforms_url).header("x-api-key", &api_key)).await?;
        anyhow::ensure!(
            !platforms.is_empty(),
            "raydium launchpad: no platform configs found"
        );

        for platform in platforms.iter() {
            for global in globals.iter() {
                if !platform
                    .curve_params_global_configs
                    .iter()
                    .any(|v| v.trim() == global.pubkey.trim())
                {
                    continue;
                }

                let mut params_url = build_mamba_api_url(
                    &base,
                    &format!(
                        "create/raydium_launchpad/platform-configs/{}/curve-params",
                        platform.pubkey
                    ),
                )?;
                params_url
                    .query_pairs_mut()
                    .append_pair("rpc_url", &rpc_url)
                    .append_pair("global_config", global.pubkey.trim());
                let params: Vec<RaydiumLaunchpadPlatformCurveParamResponse> =
                    http_json(client.get(params_url).header("x-api-key", &api_key)).await?;
                if params.is_empty() {
                    continue;
                }
                let Some(picked) = params.iter().find(|p| {
                    let amm_ok = matches!(p.amm_fee_on.trim(), "quote_token" | "both_token");
                    let supply_ok = p.supply > 0;
                    let quote_ok = p.total_quote_fund_raising > 0;
                    let base_ok = global.curve_type != 0 || p.total_base_sell > 0;
                    amm_ok && supply_ok && quote_ok && base_ok
                }) else {
                    continue;
                };
                let curve_kind = match global.curve_type {
                    0 => "constant",
                    1 => "fixed",
                    2 => "linear",
                    other => bail!("raydium launchpad: unsupported curve_type {other}"),
                };
                let curve = match curve_kind {
                    "constant" => json!({
                        "kind": "constant",
                        "supply": picked.supply,
                        "total_base_sell": picked.total_base_sell,
                        "total_quote_fund_raising": picked.total_quote_fund_raising,
                        "migrate_type": picked.migrate_type,
                    }),
                    "fixed" => json!({
                        "kind": "fixed",
                        "supply": picked.supply,
                        "total_quote_fund_raising": picked.total_quote_fund_raising,
                        "migrate_type": picked.migrate_type,
                    }),
                    "linear" => json!({
                        "kind": "linear",
                        "supply": picked.supply,
                        "total_quote_fund_raising": picked.total_quote_fund_raising,
                        "migrate_type": picked.migrate_type,
                    }),
                    _ => unreachable!(),
                };
                let amm_fee_on = picked.amm_fee_on.trim();
                return Ok::<_, anyhow::Error>(json!({
                    "global_config": global.pubkey.trim(),
                    "platform_config": platform.pubkey.trim(),
                    "base_token_program": "spl_token",
                    "curve": curve,
                    "vesting": {
                        "total_locked_amount": picked.vesting_total_locked_amount,
                        "cliff_period": picked.vesting_cliff_period,
                        "unlock_period": picked.vesting_unlock_period,
                    },
                    "amm_fee_on": amm_fee_on,
                    "transfer_fee_extension": null,
                }));
            }
        }

        bail!("raydium launchpad: failed to find compatible (global_config, platform_config) with curve params");
    }
    .await;

    match raydium_launchpad_params {
        Ok(params) => {
            results.push(create_token(CreateMethod::RaydiumLaunchpad, Some(params)).await)
        }
        Err(err) => results.push(PoolSuiteMarketResult {
            market: CreateMethod::RaydiumLaunchpad.as_api_str().to_string(),
            ok: false,
            signature: None,
            pool: None,
            mint: None,
            bundle: None,
            error: Some(format!("{err:#}")),
        }),
    }

    let artifact = PoolSuiteArtifact {
        timestamp_utc: timestamp.clone(),
        rpc_url: rpc_url_redacted,
        payer: payer.pubkey().to_string(),
        suite_base_mint: suite_base_mint.to_string(),
        openbook_market: Some(openbook_market.to_string()),
        base_mint_create_signature: base_mint_sig.clone(),
        openbook_market_create_signature: openbook_sig.clone(),
        results,
    };

    let out_dir = PathBuf::from("artifacts/validation");
    fs::create_dir_all(&out_dir).context("create artifacts/validation dir")?;
    let out_path = out_dir.join(format!("{timestamp}_pool_suite.json"));
    fs::write(&out_path, serde_json::to_vec_pretty(&artifact)?)
        .with_context(|| format!("write {}", out_path.display()))?;
    eprintln!("wrote pool-suite artifact: {}", out_path.display());

    eprintln!("pool-suite summary:");
    let mut failed: Vec<String> = Vec::new();
    for item in artifact.results.iter() {
        if item.ok {
            eprintln!(
                "  {:<18} ok sig={} bundle={}",
                item.market,
                item.signature.as_deref().unwrap_or("-"),
                item.bundle.as_deref().unwrap_or("-")
            );
        } else {
            failed.push(item.market.clone());
            eprintln!(
                "  {:<18} FAIL error={}",
                item.market,
                item.error.as_deref().unwrap_or("-")
            );
        }
    }
    if !failed.is_empty() {
        bail!("pool-suite failures: {}", failed.join(", "));
    }
    Ok(())
}

fn run_wallet_export(command: WalletExportCommand) -> anyhow::Result<()> {
    let store_path = wallet_store_path().context(format!(
        "wallet store path unavailable (set {MAMBA_WALLET_STORE_PATH_ENV})"
    ))?;
    let store = ManagedWalletStore::load(&store_path)?
        .with_context(|| format!("wallet store not found: {}", store_path.display()))?;

    let wallets = store.export_wallets(&command.selectors)?;
    anyhow::ensure!(
        !wallets.is_empty(),
        "no managed wallets found in {}",
        store_path.display()
    );
    write_wallet_export(&command.out, &wallets, command.format)?;

    let format = match command.format {
        ManagedWalletExportFormat::Json => "json",
        ManagedWalletExportFormat::Text => "txt",
    };
    println!(
        "wrote {} wallet secret{} to {} ({format})",
        wallets.len(),
        if wallets.len() == 1 { "" } else { "s" },
        command.out.display()
    );
    println!("source store: {}", store_path.display());
    Ok(())
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    show_startup_splash().await;

    let args = parse_args()?;

    let forced_mint = match args
        .mint
        .as_deref()
        .map(str::trim)
        .filter(|v| !v.is_empty())
    {
        Some(raw) => {
            Some(Pubkey::from_str(raw).with_context(|| format!("invalid --mint pubkey: {raw}"))?)
        }
        None => None,
    };

    if args.snapshot {
        let written = render_tui_snapshots(
            args.ws_url.as_deref(),
            args.http_url.as_deref(),
            args.markets,
            args.holders_limit,
            forced_mint,
        )?;
        println!("wrote snapshots:");
        for path in written {
            println!("  {path}");
        }
        return Ok(());
    }

    if let Some(command) = args.wallet_export {
        run_wallet_export(command)?;
        return Ok(());
    }

    if let Some(command) = args.create {
        run_create_command(
            command,
            args.http_url.clone(),
            args.api_base_url.clone(),
            args.api_key.clone(),
        )
        .await?;
        return Ok(());
    }

    if args.holders {
        let mint = forced_mint.context("--holders requires --mint <MINT>")?;
        let http_url = args
            .http_url
            .clone()
            .context("--holders requires --http-url (or MAMBA_API_HTTP_URLS env)")?;
        let sol = SolHook::new(http_url);
        let snapshot = fetch_holders_snapshot(&sol, &mint, args.holders_limit).await?;
        print_holders_snapshot(&snapshot);
        return Ok(());
    }

    if args.pool_suite {
        return run_pool_suite(
            args.http_url.clone(),
            args.pool_suite_setup_send,
            args.pool_suite_send,
            args.api_base_url.clone(),
            args.api_key.clone(),
        )
        .await;
    }

    let ws_url = args
        .ws_url
        .context("missing WS websocket url (set MAMBA_API_WS_URLS or pass --ws-url)")?;
    if args.suite {
        return run_suite(
            ws_url,
            args.http_url.clone(),
            args.markets,
            Duration::from_secs(args.suite_secs),
        )
        .await;
    }

    log!(
        cc::LIGHT_WHITE,
        "starting mamba (markets={}, suite=false)",
        args.markets.len()
    );
    run_tui(
        ws_url,
        args.http_url,
        args.markets,
        args.holders_limit,
        forced_mint,
        args.api_base_url,
        args.api_key,
    )
    .await
}

#[cfg(test)]
