    #[test]
    fn test_finalize_trade_exec_diagnostics_decodes_pump_fun_6003() {
        let sig = Signature::default().to_string();
        let mut parsed_sig = None;
        let mut error = Some(format!(
            "Transaction failed {sig} | status err: InstructionError(1, Custom(6003)) | log: Program {PUMP_FUN_ID} failed: custom program error: 0x1773"
        ));

        finalize_trade_exec_diagnostics(Market::PumpFun, &mut parsed_sig, &mut error);

        assert_eq!(parsed_sig.as_deref(), Some(sig.as_str()));
        let normalized = error.expect("normalized error");
        assert!(normalized.contains("Pump.fun TooLittleSolReceived (6003)"));
        assert!(normalized.contains("retry or loosen sell slippage"));
    }

